/**
 * Virtual joystick pure computation functions and VirtualJoystick class.
 * Exported for property-based testing.
 * @packageDocumentation
 */

/// <reference lib="dom" />

/**
 * Normalize joystick displacement to unit-circle-bounded output.
 * Guards against zero maxRadius by returning (0, 0).
 */
export function normalizeJoystick(
  dx: number,
  dy: number,
  maxRadius: number,
): { axisX: number; axisY: number } {
  if (maxRadius <= 0) return { axisX: 0, axisY: 0 };
  const rawX = dx / maxRadius;
  const rawY = dy / maxRadius;
  const magnitude = Math.sqrt(rawX * rawX + rawY * rawY);
  if (magnitude > 1) {
    return { axisX: rawX / magnitude, axisY: rawY / magnitude };
  }
  return { axisX: rawX, axisY: rawY };
}

/**
 * Virtual joystick class that manages touch event listeners on the
 * `#joystick-overlay` element. Renders a circular base and movable thumb
 * indicator using HTML/CSS. Exposes normalized axisX/axisY properties
 * for consumption by the JoystickSystem.
 */
export class VirtualJoystick {
  /** Normalized horizontal axis value (-1 to 1). */
  axisX = 0;
  /** Normalized vertical axis value (-1 to 1). */
  axisY = 0;

  private readonly _overlay: HTMLElement;
  private readonly _base: HTMLElement;
  private readonly _thumb: HTMLElement;
  private readonly _maxRadius: number;
  private _centerX = 0;
  private _centerY = 0;
  private _activeId: number | null = null;

  // Bound handlers for cleanup
  private readonly _onTouchStart: (e: TouchEvent) => void;
  private readonly _onTouchMove: (e: TouchEvent) => void;
  private readonly _onTouchEnd: (e: TouchEvent) => void;

  constructor() {
    const overlay = document.getElementById('joystick-overlay');
    if (!overlay) {
      throw new Error('VirtualJoystick: #joystick-overlay element not found');
    }
    this._overlay = overlay;

    // Create base circle element
    this._base = document.createElement('div');
    this._base.style.cssText = `
      position: absolute;
      inset: 0;
      border-radius: 50%;
      background: rgba(255, 255, 255, 0.15);
      border: 2px solid rgba(255, 255, 255, 0.35);
      box-sizing: border-box;
    `;

    // Create thumb indicator element
    this._thumb = document.createElement('div');
    const thumbSize = 40;
    this._thumb.style.cssText = `
      position: absolute;
      width: ${thumbSize}px;
      height: ${thumbSize}px;
      border-radius: 50%;
      background: rgba(255, 255, 255, 0.6);
      border: 2px solid rgba(255, 255, 255, 0.8);
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      pointer-events: none;
      box-sizing: border-box;
    `;

    this._overlay.appendChild(this._base);
    this._overlay.appendChild(this._thumb);

    // Compute max radius from overlay size (half the smaller dimension)
    const rect = this._overlay.getBoundingClientRect();
    this._maxRadius = Math.min(rect.width, rect.height) / 2;
    this._centerX = rect.left + rect.width / 2;
    this._centerY = rect.top + rect.height / 2;

    // Bind event handlers
    this._onTouchStart = this._handleTouchStart.bind(this);
    this._onTouchMove = this._handleTouchMove.bind(this);
    this._onTouchEnd = this._handleTouchEnd.bind(this);

    this._overlay.addEventListener('touchstart', this._onTouchStart, { passive: false });
    this._overlay.addEventListener('touchmove', this._onTouchMove, { passive: false });
    this._overlay.addEventListener('touchend', this._onTouchEnd, { passive: false });
    this._overlay.addEventListener('touchcancel', this._onTouchEnd, { passive: false });
  }

  /** Remove all event listeners and DOM elements. */
  destroy(): void {
    this._overlay.removeEventListener('touchstart', this._onTouchStart);
    this._overlay.removeEventListener('touchmove', this._onTouchMove);
    this._overlay.removeEventListener('touchend', this._onTouchEnd);
    this._overlay.removeEventListener('touchcancel', this._onTouchEnd);

    if (this._base.parentNode) {
      this._base.parentNode.removeChild(this._base);
    }
    if (this._thumb.parentNode) {
      this._thumb.parentNode.removeChild(this._thumb);
    }

    this.axisX = 0;
    this.axisY = 0;
  }

  // ── Touch event handlers ──────────────────────────────────────────────

  private _handleTouchStart(e: TouchEvent): void {
    e.preventDefault();

    if (this._activeId !== null) return;

    const touch = e.changedTouches[0];
    if (!touch) return;

    this._activeId = touch.identifier;

    // Recalculate center in case of layout changes
    const rect = this._overlay.getBoundingClientRect();
    this._centerX = rect.left + rect.width / 2;
    this._centerY = rect.top + rect.height / 2;

    this._updateFromTouch(touch.clientX, touch.clientY);
  }

  private _handleTouchMove(e: TouchEvent): void {
    e.preventDefault();

    if (this._activeId === null) return;

    const touch = this._findActiveTouch(e.changedTouches);
    if (!touch) return;

    this._updateFromTouch(touch.clientX, touch.clientY);
  }

  private _handleTouchEnd(e: TouchEvent): void {
    e.preventDefault();

    if (this._activeId === null) return;

    const touch = this._findActiveTouch(e.changedTouches);
    if (!touch) return;

    // Reset to center
    this._activeId = null;
    this.axisX = 0;
    this.axisY = 0;
    this._thumb.style.transform = 'translate(-50%, -50%)';
    this._thumb.style.top = '50%';
    this._thumb.style.left = '50%';
  }

  // ── Helpers ───────────────────────────────────────────────────────────

  private _findActiveTouch(touches: TouchList): Touch | null {
    for (let i = 0; i < touches.length; i++) {
      if (touches[i]!.identifier === this._activeId) {
        return touches[i]!;
      }
    }
    return null;
  }

  private _updateFromTouch(clientX: number, clientY: number): void {
    const dx = clientX - this._centerX;
    const dy = clientY - this._centerY;

    // Normalize using the pure function
    const normalized = normalizeJoystick(dx, dy, this._maxRadius);
    this.axisX = normalized.axisX;
    this.axisY = normalized.axisY;

    // Clamp visual thumb position to the base circle
    const visualDx = normalized.axisX * this._maxRadius;
    const visualDy = normalized.axisY * this._maxRadius;

    // Position thumb relative to center (50% + pixel offset)
    this._thumb.style.left = `calc(50% + ${visualDx}px)`;
    this._thumb.style.top = `calc(50% + ${visualDy}px)`;
    this._thumb.style.transform = 'translate(-50%, -50%)';
  }
}
