/**
 * Difficulty configuration and scaling functions for the Bee Game.
 * Defines pollen requirements and enemy spawn intervals that scale with day progression.
 * @packageDocumentation
 */

// ─── Interfaces ───────────────────────────────────────────────────────────────

/** Configuration for a single difficulty phase. */
export interface DifficultyPhase {
  /** Inclusive day range [start, end] for this phase. */
  dayRange: [number, number];
  /** Enemy types available during this phase. */
  enemyTypes: string[];
  /** Base spawn interval in seconds at the start of this phase. */
  baseSpawnInterval: number;
  /** Per-day decrease in spawn interval within this phase. */
  spawnIntervalDecay: number;
  /** Minimum spawn interval (floor) for this phase. */
  minSpawnInterval: number;
  /** Optional speed multiplier applied to enemy movement in this phase. */
  speedMultiplier?: number;
  /** Optional number of enemies spawned per spawn event. */
  enemiesPerSpawn?: number;
}

/** Top-level difficulty configuration. */
export interface DifficultyConfig {
  /** Base pollen requirement for Day 1. */
  t0: number;
  /** Growth rate per day. */
  r: number;
  /** Maximum day for scaling (caps at this day's value). */
  maxDay: number;
  /** Phase definitions for enemy spawn rules. */
  phases: DifficultyPhase[];
}

// ─── Configuration ────────────────────────────────────────────────────────────

export const DIFFICULTY_CONFIG: DifficultyConfig = {
  t0: 5,
  r: 1.2,
  maxDay: 30,
  phases: [
    {
      dayRange: [1, 5],
      enemyTypes: ['Bird_01', 'Bird_02'],
      baseSpawnInterval: 2.5,
      spawnIntervalDecay: 0.1,
      minSpawnInterval: 2.1,
    },
    {
      dayRange: [6, 15],
      enemyTypes: ['Bird_01', 'Bird_02', 'Bird_03', 'Bird_04', 'Bird_05', 'Flytrap'],
      baseSpawnInterval: 2.0,
      spawnIntervalDecay: 0.05,
      minSpawnInterval: 1.55,
    },
    {
      dayRange: [16, Infinity],
      enemyTypes: ['Bird_01', 'Bird_02', 'Bird_03', 'Bird_04', 'Bird_05', 'Flytrap'],
      baseSpawnInterval: 1.5,
      spawnIntervalDecay: 0,
      minSpawnInterval: 1.5,
      speedMultiplier: 1.25,
      enemiesPerSpawn: 2,
    },
  ],
};

// ─── Calculation Functions ────────────────────────────────────────────────────

/**
 * Calculate the minimum pollen requirement for a given day.
 * Formula: floor(t0 * r^(min(day, maxDay) - 1))
 *
 * Days beyond maxDay are capped at the maxDay value.
 *
 * @param day - The day number (1-based)
 * @param config - Optional difficulty config override (defaults to DIFFICULTY_CONFIG)
 * @returns The minimum pollen required for the given day
 */
export function calculateMinPollen(
  day: number,
  config: DifficultyConfig = DIFFICULTY_CONFIG,
): number {
  const effectiveDay = Math.min(day, config.maxDay);
  return Math.floor(config.t0 * Math.pow(config.r, effectiveDay - 1));
}

/**
 * Get the spawn interval for a given day based on phase rules.
 *
 * - Phase 1 (days 1-5): max(2.1, 2.5 - (day-1) * 0.1)
 * - Phase 2 (days 6-15): max(1.55, 2.0 - (day-6) * 0.05)
 * - Phase 3 (days 16+): 1.5
 *
 * @param day - The day number (1-based)
 * @param config - Optional difficulty config override (defaults to DIFFICULTY_CONFIG)
 * @returns The spawn interval in seconds for the given day
 */
export function getSpawnInterval(
  day: number,
  config: DifficultyConfig = DIFFICULTY_CONFIG,
): number {
  const phase = config.phases.find(
    (p) => day >= p.dayRange[0] && day <= p.dayRange[1],
  );

  if (!phase) {
    // Fallback to last phase if day is beyond all defined ranges
    const lastPhase = config.phases[config.phases.length - 1];
    return lastPhase.minSpawnInterval;
  }

  const dayOffset = day - phase.dayRange[0];
  const interval = phase.baseSpawnInterval - dayOffset * phase.spawnIntervalDecay;
  return Math.max(phase.minSpawnInterval, interval);
}
