/**
 * Pure map generation system for the Bee Game.
 * Exports data-only functions that compute positions/placements,
 * separating layout logic from PixiJS rendering for testability.
 * @packageDocumentation
 */

import { FLYTRAP_CONFIG } from '../enemy-config.js';
import { WORLD_CONFIG } from '../config.js';

// ─── Interfaces ───────────────────────────────────────────────────────────────

/** Configuration input for map generation. */
export interface MapConfig {
  /** Total map width in pixels. Must be >= 3000. */
  mapWidth: number;
  /** Size of each ground tile in pixels. */
  tileSize: number;
  /** Number of ground rows (1 surface + fill rows beneath). */
  groundRows: number;
  /** Minimum number of collectible flowers. */
  minFlowers: number;
  /** Minimum spacing between any two collectible flowers in pixels. */
  flowerSpacing: number;
  /** Minimum distance from the Hive where flowers can be placed. */
  hiveExclusion: number;
  /** Minimum spacing between consecutive trees in pixels. */
  treeMinSpacing: number;
  /** Maximum spacing between consecutive trees in pixels. */
  treeMaxSpacing: number;
  /** Number of flytraps to place. */
  flytrapCount: number;
  /** Minimum spacing between flytrap instances in pixels. */
  flytrapSpacing: number;
}

/** Output of map generation — all positions for rendering. */
export interface MapLayout {
  /** Total map width in pixels. */
  mapWidth: number;
  /** Hive X position in pixels. */
  hiveX: number;
  /** Y coordinate of the ground surface (top of topmost tile row). */
  groundY: number;
  /** X positions of big_tree_green_01 sprites. */
  trees: number[];
  /** X positions of collectible flowers. */
  flowers: number[];
  /** X positions of decorative flowers (small_flower_blue, small_flower_pink). */
  decorativeFlowers: number[];
  /** X positions of flytrap entities. */
  flytraps: number[];
}

// ─── Default Config ───────────────────────────────────────────────────────────

/** Default map configuration derived from game constants. */
export const DEFAULT_MAP_CONFIG: MapConfig = {
  mapWidth: WORLD_CONFIG.width,
  tileSize: WORLD_CONFIG.tileSize,
  groundRows: WORLD_CONFIG.groundRows,
  minFlowers: 8,
  flowerSpacing: 80,
  hiveExclusion: 120,
  treeMinSpacing: 600,
  treeMaxSpacing: 900,
  flytrapCount: FLYTRAP_CONFIG.count,
  flytrapSpacing: FLYTRAP_CONFIG.spacing,
};

// ─── Pure Generation Functions ────────────────────────────────────────────────

/**
 * Compute the hive X position near the center of the map (40-60% of width),
 * so the player can explore equally to the left and right.
 */
export function generateHiveX(mapWidth: number, _tileSize: number, rng: () => number): number {
  // Place hive in the middle 20% band: 40%–60% of map width
  const minHiveX = mapWidth * 0.4;
  const maxHiveX = mapWidth * 0.6;
  return minHiveX + rng() * (maxHiveX - minHiveX);
}

/**
 * Compute the Y coordinate of the ground surface.
 * The ground occupies `groundRows` tile rows at the bottom of the design height.
 */
export function computeGroundY(designHeight: number, tileSize: number, groundRows: number): number {
  return designHeight - tileSize * groundRows;
}

/**
 * Generate tree X positions across the map with spacing between treeMinSpacing and treeMaxSpacing.
 * Trees start from a small offset and continue to the end of the map.
 */
export function generateTreePositions(
  mapWidth: number,
  treeMinSpacing: number,
  treeMaxSpacing: number,
  rng: () => number,
): number[] {
  const trees: number[] = [];
  // Start first tree at a random position within the first spacing interval
  let x = treeMinSpacing * 0.5 + rng() * (treeMaxSpacing - treeMinSpacing) * 0.5;

  while (x < mapWidth) {
    trees.push(x);
    // Next tree at a random distance between min and max spacing
    const spacing = treeMinSpacing + rng() * (treeMaxSpacing - treeMinSpacing);
    x += spacing;
  }

  return trees;
}

/**
 * Generate collectible flower X positions.
 * Ensures:
 * - At least `minFlowers` flowers placed
 * - Minimum `flowerSpacing` px between any two flowers
 * - No flower within `hiveExclusion` px of hiveX
 * - Flowers are spread across the map width
 */
export function generateFlowerPositions(
  mapWidth: number,
  hiveX: number,
  minFlowers: number,
  flowerSpacing: number,
  hiveExclusion: number,
  rng: () => number,
): number[] {
  const flowers: number[] = [];
  const margin = 40; // Keep flowers away from map edges
  const maxAttempts = 200;

  // Try to place flowers using randomized positions with spacing constraints
  let attempts = 0;

  while (flowers.length < minFlowers && attempts < maxAttempts) {
    const candidate = margin + rng() * (mapWidth - 2 * margin);
    attempts++;

    // Check hive exclusion
    if (Math.abs(candidate - hiveX) < hiveExclusion) continue;

    // Check spacing against all existing flowers
    const tooClose = flowers.some((f) => Math.abs(candidate - f) < flowerSpacing);
    if (tooClose) continue;

    flowers.push(candidate);
    attempts = 0; // Reset attempts on success
  }

  // If random placement didn't yield enough flowers, use a deterministic fallback
  if (flowers.length < minFlowers) {
    // Calculate available range excluding hive exclusion zone
    const availablePositions: number[] = [];
    for (let x = margin; x < mapWidth - margin; x += flowerSpacing) {
      if (Math.abs(x - hiveX) >= hiveExclusion) {
        // Check against already placed flowers
        const tooClose = flowers.some((f) => Math.abs(x - f) < flowerSpacing);
        if (!tooClose) {
          availablePositions.push(x);
        }
      }
    }

    // Add positions until we have enough
    for (const pos of availablePositions) {
      if (flowers.length >= minFlowers) break;
      flowers.push(pos);
    }
  }

  // Sort for consistent ordering
  flowers.sort((a, b) => a - b);

  return flowers;
}

/**
 * Generate decorative flower X positions.
 * These have no gameplay interaction — placed for visual variety.
 * Typically more numerous than collectible flowers.
 */
export function generateDecorativeFlowerPositions(
  mapWidth: number,
  rng: () => number,
): number[] {
  const decorative: number[] = [];
  const margin = 30;
  const minSpacing = 60;
  // Place roughly one every 150-250px
  let x = margin + rng() * 100;

  while (x < mapWidth - margin) {
    decorative.push(x);
    x += minSpacing + rng() * 150;
  }

  return decorative;
}

/**
 * Generate flytrap X positions with minimum spacing constraint.
 * Flytraps are placed at ground level at fixed positions.
 * They must be at least `flytrapSpacing` pixels apart and away from the hive.
 */
export function generateFlytrapPositions(
  mapWidth: number,
  hiveX: number,
  flytrapCount: number,
  flytrapSpacing: number,
  hiveExclusion: number,
  rng: () => number,
): number[] {
  const flytraps: number[] = [];
  const margin = 100; // Keep away from map edges
  const maxAttempts = 200;

  let attempts = 0;

  while (flytraps.length < flytrapCount && attempts < maxAttempts) {
    const candidate = margin + rng() * (mapWidth - 2 * margin);
    attempts++;

    // Check hive exclusion
    if (Math.abs(candidate - hiveX) < hiveExclusion) continue;

    // Check spacing against all existing flytraps
    const tooClose = flytraps.some((f) => Math.abs(candidate - f) < flytrapSpacing);
    if (tooClose) continue;

    flytraps.push(candidate);
    attempts = 0; // Reset on success
  }

  // Deterministic fallback if random placement fails
  if (flytraps.length < flytrapCount) {
    // Place remaining flytraps evenly across the available space
    const availableStart = Math.max(margin, hiveX + hiveExclusion);
    const availableEnd = mapWidth - margin;
    const step = (availableEnd - availableStart) / (flytrapCount - flytraps.length + 1);

    for (let i = 1; flytraps.length < flytrapCount; i++) {
      const pos = availableStart + step * i;
      const tooClose = flytraps.some((f) => Math.abs(pos - f) < flytrapSpacing);
      if (!tooClose && Math.abs(pos - hiveX) >= hiveExclusion) {
        flytraps.push(pos);
      }
    }
  }

  flytraps.sort((a, b) => a - b);

  return flytraps;
}

// ─── Main Generation Function ─────────────────────────────────────────────────

/**
 * Generate a complete map layout from configuration.
 * This is a pure function — given the same config and RNG seed, it produces
 * the same layout. The optional `rng` parameter defaults to Math.random.
 *
 * @param config - Map generation parameters
 * @param designHeight - The design height of the game viewport (default 600)
 * @param rng - Random number generator returning values in [0, 1). Defaults to Math.random.
 * @returns A MapLayout with all computed positions
 */
export function generateMapLayout(
  config: MapConfig = DEFAULT_MAP_CONFIG,
  designHeight: number = 600,
  rng: () => number = Math.random,
): MapLayout {
  const {
    mapWidth,
    tileSize,
    groundRows,
    minFlowers,
    flowerSpacing,
    hiveExclusion,
    treeMinSpacing,
    treeMaxSpacing,
    flytrapCount,
    flytrapSpacing,
  } = config;

  // Compute ground surface Y
  const groundY = computeGroundY(designHeight, tileSize, groundRows);

  // Place the hive
  const hiveX = generateHiveX(mapWidth, tileSize, rng);

  // Generate tree positions
  const trees = generateTreePositions(mapWidth, treeMinSpacing, treeMaxSpacing, rng);

  // Generate collectible flower positions
  const flowers = generateFlowerPositions(
    mapWidth,
    hiveX,
    minFlowers,
    flowerSpacing,
    hiveExclusion,
    rng,
  );

  // Generate decorative flower positions
  const decorativeFlowers = generateDecorativeFlowerPositions(mapWidth, rng);

  // Generate flytrap positions
  const flytraps = generateFlytrapPositions(
    mapWidth,
    hiveX,
    flytrapCount,
    flytrapSpacing,
    hiveExclusion,
    rng,
  );

  return {
    mapWidth,
    hiveX,
    groundY,
    trees,
    flowers,
    decorativeFlowers,
    flytraps,
  };
}
