/**
 * Pure chasing-enemy logic for the Bee Game (Bird_05).
 *
 * These functions implement the lead-pursuit and steering math for the pursuer
 * enemy. They are deliberately free of ECS/PixiJS dependencies so they can be
 * unit- and property-tested in isolation.
 *
 * Core gameplay coupling: a heavier bee (more pollen) is chased faster.
 * See {@link computeChaseSpeed}.
 *
 * @packageDocumentation
 */

import type { Bird05Config } from '../enemy-config.js';

/** A 2D vector. */
export interface Vec2 {
  x: number;
  y: number;
}

/**
 * Normalize a pollen load to a [0, 1] fraction of capacity.
 *
 * @param pollenLoad - Current pollen carried.
 * @param maxCapacity - Bee carrying capacity (> 0).
 */
export function loadFraction(pollenLoad: number, maxCapacity: number): number {
  if (maxCapacity <= 0) return 0;
  return Math.max(0, Math.min(pollenLoad / maxCapacity, 1));
}

/**
 * Compute the chase speed for the chaser.
 *
 * Faster when the bee is heavier (acceleration/aggression bias).
 *
 * @param load - Pollen load fraction in [0, 1].
 * @param config - Bird_05 tuning.
 * @returns Chase speed in px/s.
 */
export function computeChaseSpeed(load: number, config: Bird05Config): number {
  const l = Math.max(0, Math.min(load, 1));
  return config.baseChaseSpeed + l * config.chaseSpeedPerLoad;
}

/**
 * Predict where the bee will be after `leadTime`, given its velocity.
 *
 * Used for lead pursuit — the chaser aims slightly ahead of the bee rather than
 * at its current position, producing a more "alive" intercept.
 *
 * @param beePos - Bee position.
 * @param beeVel - Bee velocity (px/s).
 * @param leadTime - Seconds to project ahead.
 */
export function predictLeadPoint(beePos: Vec2, beeVel: Vec2, leadTime: number): Vec2 {
  return {
    x: beePos.x + beeVel.x * leadTime,
    y: beePos.y + beeVel.y * leadTime,
  };
}

/**
 * Smoothly steer a current velocity toward a desired velocity.
 *
 * Uses exponential smoothing so turns are gradual (no jitter). The blend factor
 * is `1 - exp(-responsiveness * dt)`, which is frame-rate independent and always
 * in [0, 1].
 *
 * @param current - Current velocity.
 * @param desired - Desired velocity (e.g. toward the lead point at chase speed).
 * @param responsiveness - Turn responsiveness (higher = snappier).
 * @param dt - Delta time in seconds.
 * @returns The new, smoothed velocity.
 */
export function steerToward(
  current: Vec2,
  desired: Vec2,
  responsiveness: number,
  dt: number,
): Vec2 {
  const blend = 1 - Math.exp(-Math.max(0, responsiveness) * Math.max(0, dt));
  return {
    x: current.x + (desired.x - current.x) * blend,
    y: current.y + (desired.y - current.y) * blend,
  };
}

/**
 * Build the desired velocity vector pointing from `from` toward `target` at the
 * given speed. Returns a zero vector if the points coincide.
 *
 * @param from - Origin point (chaser position).
 * @param target - Target point (lead point).
 * @param speed - Desired speed magnitude (px/s).
 */
export function desiredVelocity(from: Vec2, target: Vec2, speed: number): Vec2 {
  const dx = target.x - from.x;
  const dy = target.y - from.y;
  const dist = Math.sqrt(dx * dx + dy * dy);
  if (dist === 0) return { x: 0, y: 0 };
  return { x: (dx / dist) * speed, y: (dy / dist) * speed };
}

/** Euclidean distance between two points. */
export function distance(a: Vec2, b: Vec2): number {
  const dx = b.x - a.x;
  const dy = b.y - a.y;
  return Math.sqrt(dx * dx + dy * dy);
}
