// ─── Bird_05 Configuration (Pursuer / Chaser) ─────────────────────────────────
//
// Bird_05 is an always-aggressive pursuer that roams toward the bee at chase
// speed, commits to a locked dive-through trajectory when close enough, and
// recovers with a 2s cooldown ascent. It runs a 3-state machine:
//
//   roam (always head toward bee, load-scaled speed)
//     → dive (lock target = pos + 1.5 × (bee − pos); lethal on contact;
//             ends at the +50% overshoot point)
//     → cooldown (ascend toward preferredAltitude for 2s, no attack)
//     → roam (again)

export interface Bird05Config {
  /** Circle collider radius in pixels. */
  colliderRadius: number;

  // ── Vertical band ───────────────────────────────────────────────────
  /** Top of the spawn band, as a fraction of vertical space (0 = top). */
  minHeightFraction: number;
  /** Bottom of the spawn band, as a fraction of vertical space (1 = ground). */
  maxHeightFraction: number;

  // ── Roam (always heads toward bee, with role-based vertical offset) ─
  /** Base roam speed (px/s) at zero pollen load. */
  baseChaseSpeed: number;
  /** Extra roam speed (px/s) added at full pollen load (greed = danger). */
  chaseSpeedPerLoad: number;
  /** Lead time (s) the bird aims ahead of the bee's predicted position. */
  leadTime: number;
  /** Turn smoothing factor per second (higher = snappier steering). */
  turnResponsiveness: number;
  /** Vertical offset (px) for 'top' (−) and 'bottom' (+) flock roles. */
  flockVerticalSpread: number;

  // ── Dive commit & physics ───────────────────────────────────────────
  /** Distance (px) within which roam commits to a dive. */
  chaseTriggerRadius: number;
  /** Overshoot factor — dive ends at (1 + factor) × (bee − bird). 0.5 = +50%. */
  diveOvershootFactor: number;
  /** Dive speed in px/s along the locked trajectory. */
  diveSpeed: number;
  /** Safety cap (s) — dive aborts to cooldown if it doesn't reach the target. */
  maxDiveDuration: number;

  // ── Post-attack cooldown ────────────────────────────────────────────
  /** Cooldown duration (s) — no attack possible; bird climbs diagonally. */
  attackCooldown: number;
  /** Cooldown escape speed (px/s) — magnitude of the diagonal-up vector. */
  ascendSpeed: number;
  /** Min fraction of ascendSpeed enforced as upward climb (so a near-horizontal
   *  dive still produces a visible diagonal-up escape). */
  escapeMinClimbFactor: number;

  // ── Flock attack stagger ────────────────────────────────────────────
  /** Min seconds between two birds committing to a dive (flock token). */
  attackStaggerMin: number;
  /** Max seconds between two birds committing to a dive (flock token). */
  attackStaggerMax: number;
}

/**
 * Number of Bird_05 pursuers that should be present at the start of `day`.
 *
 * Progression (per the design):
 *   - days 1–2  : 0 pursuers (no Bird_05 yet)
 *   - days 3–8  : 1 pursuer
 *   - days 9–14 : 2 pursuers
 *   - day  15+  : 3 pursuers
 *
 * Days <= 0 are treated as day 1 (zero pursuers). Non-finite inputs return 0.
 */
export function bird05CountForDay(day: number): number {
  if (!Number.isFinite(day)) return 0;
  if (day >= 15) return 3;
  if (day >= 9) return 2;
  if (day >= 3) return 1;
  return 0;
}

export const BIRD_05_CONFIG: Bird05Config = {
  colliderRadius: 16,

  minHeightFraction: 0.1,
  maxHeightFraction: 0.55,

  baseChaseSpeed: 160,
  chaseSpeedPerLoad: 140,
  leadTime: 0.3,
  turnResponsiveness: 4,
  flockVerticalSpread: 140,   // 'top' hovers ~140 above the bee, 'bottom' below

  chaseTriggerRadius: 280,
  diveOvershootFactor: 0.5,   // dive ends 50% past the bee
  diveSpeed: 460,
  maxDiveDuration: 1.5,

  attackCooldown: 2.0,        // 2s cooldown + diagonal climb before roaming again
  ascendSpeed: 260,
  escapeMinClimbFactor: 0.4,  // even a horizontal dive guarantees 40% upward climb

  // Stagger so only one bird commits per 0.5-1.0s — no doomstack dives.
  attackStaggerMin: 0.5,
  attackStaggerMax: 1.0,
} as const;

// ─── Bird Evasion Configuration (shared) ──────────────────────────────────────

export interface EvasionConfig {
  /** Vertical distance in pixels a bird shifts its flight height when it evades. */
  distance: number;
  /** Duration in seconds of the active evade maneuver (also a re-trigger guard). */
  duration: number;
  /** Vertical glide speed in px/s while actively evading (faster than normal). */
  verticalSpeed: number;
}

/** Shared evasion tuning for bird-to-bird collision dodging. */
export const EVASION_CONFIG: EvasionConfig = {
  distance: 90,
  duration: 0.8,
  verticalSpeed: 260,
} as const;

// ─── Flytrap Configuration ────────────────────────────────────────────────────

export interface FlytrapConfig {
  /** Number of flytraps to place per map. */
  count: number;
  /** Minimum spacing between flytraps in pixels. */
  spacing: number;
  /** Proximity radius in pixels — Bee within this range is caught. */
  proximityRadius: number;
  /** Duration in seconds the Bee is pinned after being caught. */
  catchDuration: number;
  /** Cooldown duration in seconds after releasing the Bee. */
  cooldownDuration: number;
  /**
   * Pin position offset (x) from the flytrap's sprite anchor (bottom-center
   * at groundY). The caught bee is snapped to this point so it always sits
   * inside the visible mouth of the trap.
   */
  pinOffsetX: number;
  /**
   * Pin position offset (y) from groundY. Negative values move the bee up
   * the sprite (e.g. −90 places the bee 90px above the ground).
   */
  pinOffsetY: number;
}

export const FLYTRAP_CONFIG: FlytrapConfig = {
  count: 3,
  spacing: 200,
  proximityRadius: 40,
  catchDuration: 3,
  cooldownDuration: 3,
  // Mouth of the flytrap sprite (sprite is 116×224 at 0.5 scale = 58×112,
  // anchored bottom-center). Tuned so the caught bee visually sits inside it.
  pinOffsetX: 6,
  pinOffsetY: -78,
} as const;
