/**
 * Game configuration constants and state interfaces for the Bee Game Demo.
 * All tuning parameters organized by entity/system.
 * @packageDocumentation
 */

// ─── Bee Configuration ────────────────────────────────────────────────────────

export const BEE_CONFIG = {
  /** Collision radius in pixels. */
  radius: 16,
  /** Base maximum speed in px/s (no pollen load). +10% from original 300. */
  baseMaxSpeed: 330,
  /** Absolute max speed ceiling in px/s (kinetic overshoot). +20% above base. */
  maxSpeedCeiling: 396,
  /** Minimum speed in px/s (at max pollen load). */
  minSpeed: 120,
  /** Base acceleration in px/s². */
  acceleration: 800,
  /**
   * Base per-frame friction multiplier at 60fps (0-1). Closer to 1 = longer
   * glide / harder to stop. 0.99 means the bee keeps most of its speed each
   * frame, so releasing controls produces a long coast.
   */
  baseFriction: 0.99,
  /** Maximum pollen the bee can carry. */
  maxPollenCapacity: 10,
  /** Gravity in px/s² at max pollen load (scales linearly with load). */
  gravity: 400,

  // ── Kinetic momentum (the more pollen, the harder to stop/steer) ─────
  /**
   * Extra glide approaching 1 at max pollen load. At full load friction
   * becomes baseFriction + kineticGlide, making the bee very hard to stop.
   */
  kineticGlide: 0.008,
  /**
   * Steering penalty at max pollen load (0-1). Heavier loads reduce how much
   * acceleration responds to input, so the player must fight momentum to
   * change direction. effectiveAccel = accel * (1 - loadFactor * penalty).
   */
  kineticSteerPenalty: 0.45,

  // ── Tiered weight penalties (always-controllable curve) ──────────────
  /**
   * Severity reached at 50% load (0-1). A small value keeps the first half of
   * the load barely penalized ("lil penalty"), then penalties ramp up toward
   * full capacity. severity(0)=0, severity(0.5)=this, severity(1+)=1.
   */
  weightMidpointSeverity: 0.3,
  /** Max-speed reduction at/above full capacity (0.20 → −20%, in the 15–25% band). */
  weightMaxSpeedReduction: 0.2,
  /** Upward (climb) thrust reduction at/above full capacity (0.25 → −25%, in the 20–30% band). */
  weightUpThrustReduction: 0.25,
  /** Steering-acceleration reduction at/above full capacity (0.35 → −35%). */
  weightSteerReduction: 0.35,
  /** Extra glide (added to base friction) at/above full capacity. */
  weightGlideMax: 0.008,
  /**
   * Fraction of available upward thrust that gravity may consume (0-1). Gravity
   * is clamped to upThrust * this, guaranteeing the bee ALWAYS climbs when the
   * player holds up — even fully overloaded. 0.6 leaves 40% net climb headroom.
   */
  gravityThrustRatio: 0.6,

  // ── Weight physics multipliers ──────────────────────────────────────
  /** Extra friction added at max weight (makes bee slide more). */
  weightFrictionBonus: 0.05,
  /** Upward thrust reduction at max weight (0.3 = 30% reduction — still flyable). */
  weightUpReduction: 0.3,
  /** Additional diagonal-up penalty at max weight (0.2 = 20% extra reduction). */
  weightDiagonalPenalty: 0.2,
  /** Acceleration reduction at max weight (0.2 = 80% effective accel). */
  weightAccelReduction: 0.2,
  /** Max fall speed multiplier relative to maxSpeed. */
  maxFallSpeedMultiplier: 1.8,
  /** Dive speed bonus: extra speed gained when pressing down (px/s²). */
  diveBoost: 200,

  // ── Death/invincibility ─────────────────────────────────────────────
  /** Duration of the death fall animation in seconds. */
  deathFallDuration: 0.5,
  /** Delay before respawn after landing in seconds. */
  respawnDelay: 0.3,
  /** Duration of invincibility after respawn in seconds. */
  invincibilityDuration: 2.0,
} as const;

