// ─── Runtime State Interfaces ─────────────────────────────────────────────────

/** Runtime game state for a single level. */
export interface GameState {
  pollenDelivered: number;
  totalPollenCount: number;
  levelComplete: boolean;
}

/** Create a fresh GameState for a new level. */
export function createGameState(): GameState {
  return {
    pollenDelivered: 0,
    totalPollenCount: POLLEN_CONFIG.count,
    levelComplete: false,
  };
}

/** Merged input from keyboard + joystick. */
export interface BeeInput {
  axisX: number; // -1 to 1
  axisY: number; // -1 to 1
}

/** Create a zeroed BeeInput. */
export function createBeeInput(): BeeInput {
  return { axisX: 0, axisY: 0 };
}
