import { Container, Graphics } from 'pixi.js';

// ─── Interfaces ─────────────────────────────────────────────────────────────

export interface ISceneTransition {
  /** Start a fade-out → fade-in transition. Returns a promise that resolves when complete. */
  play(): Promise<void>;
  /**
   * Fade out to black, run `onBlack` (swap the scene), then fade back in.
   * The scene change happens at full black for a seamless transition.
   */
  playWithSwap(onBlack: () => void | Promise<void>): Promise<void>;
  /** Whether a transition is currently in progress. */
  readonly isActive: boolean;
}

// ─── SceneTransition ────────────────────────────────────────────────────────

/**
 * Full-screen overlay that performs a linear fade-out (alpha 0→1) then
 * fade-in (alpha 1→0), blocking all input while active.
 *
 * Usage:
 *   const transition = new SceneTransition(app.stage);
 *   await transition.play(); // resolves after 1s total (0.5s out + 0.5s in)
 */
export class SceneTransition implements ISceneTransition {
  private _overlay: Graphics;
  private _isActive: boolean = false;
  private readonly _fadeDuration: number = 0.5; // seconds per phase

  constructor(private readonly _stage: Container) {
    // Create full-screen overlay rectangle (black, covers entire viewport).
    // Use a large fixed size — PixiJS will clip to screen anyway.
    this._overlay = new Graphics();
    this._overlay.rect(0, 0, 16384, 16384);
    this._overlay.fill({ color: 0x000000 });
    this._overlay.alpha = 0;
    this._overlay.visible = false;

    // Block input events: set eventMode to 'static' so the overlay captures
    // all pointer events, preventing them from reaching elements below.
    this._overlay.eventMode = 'static';
    this._overlay.cursor = 'default';

    // Add to stage so it renders above all other content.
    this._stage.addChild(this._overlay);
  }

  get isActive(): boolean {
    return this._isActive;
  }

  async play(): Promise<void> {
    return this.playWithSwap(() => {});
  }

  async playWithSwap(onBlack: () => void | Promise<void>): Promise<void> {
    // Ignore new requests while a transition is already in progress.
    if (this._isActive) return;

    this._isActive = true;
    this._overlay.visible = true;
    this._overlay.alpha = 0;

    // Ensure the overlay is rendered on top of everything.
    this._stage.setChildIndex(this._overlay, this._stage.children.length - 1);

    // Block keyboard/touch/joystick by intercepting pointer events on the overlay.
    // The overlay's eventMode = 'static' already blocks pointer propagation.
    // For keyboard events, we add a capturing listener on the document.
    const blockKeyboard = (e: Event): void => {
      e.stopPropagation();
      e.preventDefault();
    };

    document.addEventListener('keydown', blockKeyboard, true);
    document.addEventListener('keyup', blockKeyboard, true);
    document.addEventListener('touchstart', blockKeyboard, true);
    document.addEventListener('touchmove', blockKeyboard, true);
    document.addEventListener('touchend', blockKeyboard, true);

    try {
      // Phase 1: Fade out (alpha 0 → 1)
      await this._animateAlpha(0, 1, this._fadeDuration);

      // At full black: swap the scene
      await onBlack();

      // Keep the overlay on top after the scene swap added new children
      this._stage.setChildIndex(this._overlay, this._stage.children.length - 1);

      // Phase 2: Fade in (alpha 1 → 0)
      await this._animateAlpha(1, 0, this._fadeDuration);
    } finally {
      // Cleanup: hide overlay and remove event blockers.
      this._overlay.visible = false;
      this._overlay.alpha = 0;
      this._isActive = false;

      document.removeEventListener('keydown', blockKeyboard, true);
      document.removeEventListener('keyup', blockKeyboard, true);
      document.removeEventListener('touchstart', blockKeyboard, true);
      document.removeEventListener('touchmove', blockKeyboard, true);
      document.removeEventListener('touchend', blockKeyboard, true);
    }
  }

  /**
   * Animate overlay alpha linearly from `from` to `to` over `duration` seconds.
   * Uses requestAnimationFrame for smooth animation.
   */
  private _animateAlpha(from: number, to: number, duration: number): Promise<void> {
    return new Promise<void>((resolve) => {
      const durationMs = duration * 1000;
      let startTime: number | null = null;

      const tick = (timestamp: number): void => {
        if (startTime === null) startTime = timestamp;

        const elapsed = timestamp - startTime;
        const t = Math.min(elapsed / durationMs, 1);

        // Linear interpolation
        this._overlay.alpha = from + (to - from) * t;

        if (t < 1) {
          requestAnimationFrame(tick);
        } else {
          this._overlay.alpha = to;
          resolve();
        }
      };

      requestAnimationFrame(tick);
    });
  }
}
