/**
 * Bird_01 enemy system for the Bee Game.
 *
 * Bird_01 is a basic bird that spawns from the right edge and flies leftward
 * at a constant speed. It uses a circle collider for collision detection.
 *
 * Responsibilities:
 * - Spawning Bird_01 entities at random flight heights
 * - Moving all Bird_01 entities leftward each frame
 * - Destroying entities that pass beyond the left edge
 *
 * @packageDocumentation
 */

import type { World, EntityId } from '@astracore/ecs';
import { Position, Velocity, CircleCollider, GroundBirdTag, Evasion } from '../components.js';
import { BIRD_01_CONFIG, EVASION_CONFIG } from '../enemy-config.js';
import type { EvasionBird, EvasionCapableSystem } from './bird-evasion.js';

// ─── Constants ────────────────────────────────────────────────────────────────

/** Distance past the left edge before an entity is destroyed (in pixels). */
const CLEANUP_MARGIN = 50;

/** Interval (seconds) between flight-height changes. */
const HEIGHT_CHANGE_INTERVAL = 3;

/** Vertical speed (px/s) used to glide toward a new target height. */
const VERTICAL_SPEED = 100;

// ─── Bird01System ─────────────────────────────────────────────────────────────

/**
 * Manages Bird_01 enemy entities — spawning, movement, and cleanup.
 *
 * Bird_01 flies leftward at a constant horizontal speed and changes its flight
 * height every 3 seconds, gliding smoothly to a new target while staying within
 * the playable vertical bounds (never under the ground or off the top).
 */
export class Bird01System implements EvasionCapableSystem {
  private readonly _world: World;
  private readonly _entities: Set<EntityId> = new Set();
  /** Per-entity height-change state: timer, target Y, and vertical bounds. */
  private readonly _heightState = new Map<
    EntityId,
    { timer: number; targetY: number; minY: number; maxY: number }
  >();

  constructor(world: World) {
    this._world = world;
  }

  /**
   * Spawn a new Bird_01 entity at the right edge of the world.
   *
   * The flight zone is defined by {@link Bird01Config.minHeightFraction} and
   * {@link Bird01Config.maxHeightFraction} as fractions of the vertical space
   * between `topY` (top of screen) and `groundY` (ground surface). The bird
   * never leaves this band.
   *
   * @param worldRightEdge - X coordinate of the right world boundary (spawn X position)
   * @param groundY - Y coordinate of the ground surface (bottom flight boundary)
   * @param topY - Y coordinate of the top of the playable area (top flight boundary)
   */
  public spawn(worldRightEdge: number, groundY: number, topY: number): EntityId {
    const world = this._world;

    const verticalSpace = groundY - topY;
    const minY = topY + BIRD_01_CONFIG.minHeightFraction * verticalSpace;
    const maxY = topY + BIRD_01_CONFIG.maxHeightFraction * verticalSpace;
    const safeMaxY = Math.max(minY, maxY);
    const flightY = minY + Math.random() * (safeMaxY - minY);

    // Random speed between configured min and max
    const speed =
      BIRD_01_CONFIG.minSpeed +
      Math.random() * (BIRD_01_CONFIG.maxSpeed - BIRD_01_CONFIG.minSpeed);

    const canEvade = Math.random() < BIRD_01_CONFIG.evasionChance;

    const entity = world.createEntity();
    world.addComponent(entity, new GroundBirdTag());
    world.addComponent(entity, new Position(worldRightEdge, flightY));
    world.addComponent(entity, new Velocity(-speed, 0));
    world.addComponent(entity, new CircleCollider(BIRD_01_CONFIG.colliderRadius));
    world.addComponent(entity, new Evasion(canEvade, 0));

    this._entities.add(entity);
    this._heightState.set(entity, {
      timer: 0,
      targetY: flightY,
      minY,
      maxY: safeMaxY,
    });
    return entity;
  }

  /**
   * Update all Bird_01 entities: move them leftward, retarget flight height
   * every 3s, glide toward the target, advance evade maneuvers, and destroy
   * those past the left edge.
   *
   * @param dt - Delta time in seconds since last frame
   */
  public update(dt: number): void {
    const world = this._world;
    const toRemove: EntityId[] = [];

    for (const entity of this._entities) {
      if (!world.hasEntity(entity)) {
        toRemove.push(entity);
        continue;
      }

      const pos = world.getComponent(entity, Position);
      const vel = world.getComponent(entity, Velocity);
      const hs = this._heightState.get(entity);

      if (!pos || !vel || !hs) {
        toRemove.push(entity);
        continue;
      }

      // Move horizontally
      pos.x += vel.dx * dt;

      const evasion = world.getComponent(entity, Evasion);
      const evading = evasion !== undefined && evasion.cooldown > 0;
      if (evasion && evading) {
        evasion.cooldown = Math.max(0, evasion.cooldown - dt);
      }

      // Every HEIGHT_CHANGE_INTERVAL, pick a new in-bounds target height
      // (skipped while actively evading so the dodge isn't overridden).
      if (!evading) {
        hs.timer += dt;
        if (hs.timer >= HEIGHT_CHANGE_INTERVAL) {
          hs.timer -= HEIGHT_CHANGE_INTERVAL;
          hs.targetY = hs.minY + Math.random() * (hs.maxY - hs.minY);
        }
      }

      // Glide toward the target height (faster while evading), clamped to bounds
      const dy = hs.targetY - pos.y;
      const speed = evading ? EVASION_CONFIG.verticalSpeed : VERTICAL_SPEED;
      const step = speed * dt;
      if (Math.abs(dy) <= step) {
        pos.y = hs.targetY;
      } else {
        pos.y += Math.sign(dy) * step;
      }
      pos.y = Math.max(hs.minY, Math.min(pos.y, hs.maxY));

      // Destroy if past left edge by cleanup margin
      if (pos.x < -CLEANUP_MARGIN) {
        world.destroyEntity(entity);
        toRemove.push(entity);
      }
    }

    for (const entity of toRemove) {
      this._entities.delete(entity);
      this._heightState.delete(entity);
    }
  }

  /** Snapshot this system's birds for cross-system collision/evasion checks. */
  public collectEvasionBirds(): EvasionBird[] {
    const world = this._world;
    const birds: EvasionBird[] = [];
    for (const entity of this._entities) {
      if (!world.hasEntity(entity)) continue;
      const pos = world.getComponent(entity, Position);
      const col = world.getComponent(entity, CircleCollider);
      const evasion = world.getComponent(entity, Evasion);
      if (!pos || !col) continue;
      birds.push({
        id: entity,
        x: pos.x,
        y: pos.y,
        radius: col.radius,
        canEvade: evasion?.canEvade ?? false,
        evading: (evasion?.cooldown ?? 0) > 0,
      });
    }
    return birds;
  }

  /**
   * Begin an evade maneuver: retarget the flight height in the given vertical
   * direction by {@link EVASION_CONFIG.distance}, clamped to the bird's bounds.
   * If the preferred direction is blocked by a bound, the opposite is used so
   * the bird still changes height.
   *
   * @param id - Entity to evade.
   * @param dir - -1 to fly up, +1 to bounce down.
   */
  public beginEvade(id: EntityId, dir: number): void {
    const hs = this._heightState.get(id);
    const evasion = this._world.hasEntity(id)
      ? this._world.getComponent(id, Evasion)
      : undefined;
    const pos = this._world.hasEntity(id)
      ? this._world.getComponent(id, Position)
      : undefined;
    if (!hs || !evasion || !pos || !evasion.canEvade) return;

    const distance = EVASION_CONFIG.distance;
    let target = pos.y + dir * distance;
    if (target < hs.minY || target > hs.maxY) {
      // Preferred direction leaves bounds → bounce the other way instead.
      target = pos.y - dir * distance;
    }
    hs.targetY = Math.max(hs.minY, Math.min(target, hs.maxY));
    evasion.cooldown = EVASION_CONFIG.duration;
  }

  /**
   * Get the number of active Bird_01 entities.
   */
  public get count(): number {
    return this._entities.size;
  }

  /**
   * Get all tracked Bird_01 entity IDs (read-only).
   */
  public get entities(): ReadonlySet<EntityId> {
    return this._entities;
  }

  /**
   * Destroy all tracked Bird_01 entities and clear the system state.
   */
  public clear(): void {
    for (const entity of this._entities) {
      if (this._world.hasEntity(entity)) {
        this._world.destroyEntity(entity);
      }
    }
    this._entities.clear();
    this._heightState.clear();
  }
}
