/**
 * Localization system for loading and retrieving translated strings.
 *
 * Loads a flat JSON key-value map from a URL and provides string retrieval
 * with optional parameter substitution. Falls back gracefully on load failure.
 */

/** Interface for the localization system. */
export interface ILocalization {
  /** Load strings from a JSON URL. */
  load(url: string): Promise<void>;
  /** Get a string by key, with optional parameter substitution. */
  t(key: string, params?: Record<string, string | number>): string;
}

/** Default implementation of ILocalization. */
export class Localization implements ILocalization {
  private _strings: Record<string, string> = {};

  /**
   * Load localization strings from a JSON file at the given URL.
   * On fetch failure or invalid JSON, falls back to an empty dictionary.
   */
  async load(url: string): Promise<void> {
    try {
      const response = await fetch(url);
      if (!response.ok) {
        this._strings = {};
        return;
      }
      const data: unknown = await response.json();
      if (data !== null && typeof data === 'object' && !Array.isArray(data)) {
        this._strings = data as Record<string, string>;
      } else {
        this._strings = {};
      }
    } catch {
      this._strings = {};
    }
  }

  /**
   * Retrieve a localized string by key.
   * If the key is not found, returns the key itself.
   * If params are provided, replaces `{param}` placeholders with corresponding values.
   */
  t(key: string, params?: Record<string, string | number>): string {
    let value = this._strings[key] ?? key;

    if (params) {
      for (const [param, replacement] of Object.entries(params)) {
        const replacementStr = String(replacement);
        value = value.replaceAll(`{${param}}`, () => replacementStr);
      }
    }

    return value;
  }
}
