/**
 * Enemy spawn system for the Bee Game.
 *
 * Determines which enemies to spawn based on the current day number and difficulty phase.
 * Uses DIFFICULTY_CONFIG to look up phase rules and getSpawnInterval for timing.
 * Returns spawn requests rather than directly spawning — decoupled from individual enemy systems.
 *
 * Behavior by phase:
 * - Phase 1 (days 1-5): Bird_01, Bird_02 only
 * - Phase 2 (days 6-15): Bird_01, Bird_02, Bird_03, Bird_04, Flytrap
 * - Phase 3 (days 16+): all types, 1.5s interval, +25% speed, up to 2 enemies per spawn
 *
 * When Day_Timer expires: double spawn rate (halve interval), use most aggressive enemy types.
 *
 * @packageDocumentation
 */

import {
  DIFFICULTY_CONFIG,
  getSpawnInterval,
  type DifficultyConfig,
  type DifficultyPhase,
} from '../difficulty-config.js';

// ─── Types ────────────────────────────────────────────────────────────────────

/** Enemy type identifiers matching config definitions. */
export type EnemyType = 'Bird_01' | 'Bird_02' | 'Bird_03' | 'Bird_04' | 'Bird_05' | 'Flytrap';

/** A single spawn request describing what to spawn and at what speed multiplier. */
export type EnemySpawnRequest = {
  type: EnemyType;
  speedMultiplier: number;
};

/** Most aggressive enemy types used when the day timer expires. */
const AGGRESSIVE_TYPES: EnemyType[] = ['Bird_03', 'Bird_04', 'Bird_05'];

// ─── EnemySpawnSystem ─────────────────────────────────────────────────────────

/**
 * Manages enemy spawn timing and type selection based on day progression and difficulty config.
 *
 * Call `update(dt, timerExpired)` each frame. When accumulated time exceeds the spawn interval,
 * returns an array of EnemySpawnRequest objects describing what should be spawned.
 */
export class EnemySpawnSystem {
  private readonly _day: number;
  private readonly _config: DifficultyConfig;
  private readonly _phase: DifficultyPhase;
  private readonly _baseInterval: number;
  private _timeSinceLastSpawn: number = 0;

  /**
   * Create an EnemySpawnSystem for a given day.
   *
   * @param day - Current day number (1-based)
   * @param config - Optional difficulty config override (defaults to DIFFICULTY_CONFIG)
   */
  constructor(day: number, config: DifficultyConfig = DIFFICULTY_CONFIG) {
    this._day = day;
    this._config = config;
    this._phase = this._getPhaseForDay(day);
    this._baseInterval = getSpawnInterval(day, config);
  }

  /**
   * Update the spawn system. Returns spawn requests when the spawn interval is exceeded.
   *
   * @param dt - Delta time in seconds since last frame
   * @param timerExpired - Whether the day timer has reached zero
   * @returns Array of EnemySpawnRequest objects (empty if no spawn this frame)
   */
  public update(dt: number, timerExpired: boolean): EnemySpawnRequest[] {
    this._timeSinceLastSpawn += dt;

    const interval = timerExpired
      ? this._baseInterval / 2
      : this._baseInterval;

    if (this._timeSinceLastSpawn < interval) {
      return [];
    }

    // Reset accumulator (consume one interval)
    this._timeSinceLastSpawn -= interval;

    return this._createSpawnRequests(timerExpired);
  }

  /**
   * Get the current spawn interval (before timer-expired doubling).
   */
  public get baseInterval(): number {
    return this._baseInterval;
  }

  /**
   * Get the current phase for this system's day.
   */
  public get phase(): DifficultyPhase {
    return this._phase;
  }

  /**
   * Get the current day number.
   */
  public get day(): number {
    return this._day;
  }

  /**
   * Reset the spawn timer accumulator.
   */
  public reset(): void {
    this._timeSinceLastSpawn = 0;
  }

  // ─── Private ──────────────────────────────────────────────────────────────

  /**
   * Find the difficulty phase for a given day number.
   */
  private _getPhaseForDay(day: number): DifficultyPhase {
    const phase = this._config.phases.find(
      (p) => day >= p.dayRange[0] && day <= p.dayRange[1],
    );

    if (!phase) {
      // Fallback to last phase if day is beyond all defined ranges
      const lastPhase = this._config.phases[this._config.phases.length - 1];
      if (!lastPhase) {
        throw new Error(`No difficulty phases configured`);
      }
      return lastPhase;
    }

    return phase;
  }

  /**
   * Create spawn requests based on current phase and timer state.
   */
  private _createSpawnRequests(timerExpired: boolean): EnemySpawnRequest[] {
    const speedMultiplier = this._phase.speedMultiplier ?? 1.0;
    const enemiesPerSpawn = this._phase.enemiesPerSpawn ?? 1;

    if (timerExpired) {
      // When timer expired: use most aggressive types available in current phase
      const aggressiveTypes = this._getAggressiveTypes();
      const count = enemiesPerSpawn;
      const requests: EnemySpawnRequest[] = [];

      for (let i = 0; i < count; i++) {
        const type = aggressiveTypes[Math.floor(Math.random() * aggressiveTypes.length)];
        requests.push({ type, speedMultiplier });
      }

      return requests;
    }

    // Normal spawning: pick from available enemy types for this phase
    const availableTypes = this._phase.enemyTypes as EnemyType[];
    const count = enemiesPerSpawn;
    const requests: EnemySpawnRequest[] = [];

    for (let i = 0; i < count; i++) {
      const type = availableTypes[Math.floor(Math.random() * availableTypes.length)];
      requests.push({ type, speedMultiplier });
    }

    return requests;
  }

  /**
   * Get the most aggressive enemy types available in the current phase.
   * Aggressive types are Bird_03 and Bird_04, filtered to only those available in the phase.
   * Falls back to all phase types if no aggressive types are available.
   */
  private _getAggressiveTypes(): EnemyType[] {
    const available = this._phase.enemyTypes as EnemyType[];
    const aggressive = AGGRESSIVE_TYPES.filter((t) => available.includes(t));

    // If no aggressive types in this phase (Phase 1), fall back to all available
    if (aggressive.length === 0) {
      return available;
    }

    return aggressive;
  }
}
