/**
 * Dash ability system for the Bee Game.
 *
 * Manages the dash ability lifecycle: activation, duration countdown, cooldown,
 * and speed multiplier calculation. The dash grants a burst of speed and invincibility
 * when activated, then enters a cooldown period before it can be used again.
 *
 * Duration and multiplier scale with DashState.level per UPGRADE_CONFIGS.
 *
 * Exports pure functions for property testing:
 * - `getDashMultiplierForLevel` — returns UPGRADE_CONFIGS.dash.effects[level-1]
 * - `getDashDurationForLevel` — returns DASH_DURATIONS[level-1]
 *
 * @packageDocumentation
 */

import { UPGRADE_CONFIGS, DASH_DURATIONS, DASH_COOLDOWN } from '../upgrade-config';

// ─── Pure Functions (exported for property testing) ───────────────────────────

/**
 * Get the dash speed multiplier for a given upgrade level.
 *
 * @param level - The dash upgrade level (1-based, 1 to maxLevel)
 * @returns The speed multiplier from UPGRADE_CONFIGS.dash.effects[level-1]
 */
export function getDashMultiplierForLevel(level: number): number {
  if (level < 1 || level > UPGRADE_CONFIGS.dash.effects.length) {
    return 1;
  }
  return UPGRADE_CONFIGS.dash.effects[level - 1] ?? 1;
}

/**
 * Get the dash duration for a given upgrade level.
 *
 * @param level - The dash upgrade level (1-based, 1 to maxLevel)
 * @returns The duration in seconds from DASH_DURATIONS[level-1]
 */
export function getDashDurationForLevel(level: number): number {
  if (level < 1 || level > DASH_DURATIONS.length) {
    return 0;
  }
  return DASH_DURATIONS[level - 1] ?? 0;
}

// ─── DashSystem ───────────────────────────────────────────────────────────────

/**
 * Manages the dash ability: activation checks, duration countdown, cooldown timer,
 * and speed multiplier retrieval.
 *
 * While active, the Bee is invincible to enemies and immune to Flytrap catch.
 * After duration ends, a cooldown timer starts. During cooldown, dash cannot be reactivated.
 */
export class DashSystem {
  private _isActive: boolean = false;
  private _durationRemaining: number = 0;
  private _cooldownRemaining: number = 0;
  private _level: number = 0;
  private _unlocked: boolean = false;

  /**
   * Create a new DashSystem.
   *
   * @param level - The current dash upgrade level (0 = not unlocked, 1+ = unlocked)
   */
  constructor(level: number = 0) {
    this._level = level;
    this._unlocked = level > 0;
  }

  /**
   * Attempt to activate the dash ability.
   *
   * Activation succeeds only if:
   * - Dash is unlocked (level > 0)
   * - Dash is not currently active
   * - Dash is not on cooldown
   *
   * If the Bee is moving (velocityX or velocityY != 0), the dash is applied in the
   * movement direction. If the Bee is stationary, the dash is applied in the facing direction.
   *
   * @param velocityX - The Bee's current horizontal velocity
   * @param velocityY - The Bee's current vertical velocity
   * @param facingDirection - The direction the Bee is facing (-1 for left, 1 for right)
   * @returns true if the dash was activated, false if rejected
   */
  public tryActivate(velocityX: number, velocityY: number, facingDirection: number): boolean {
    // Reject if not unlocked, already active, or on cooldown
    if (!this._unlocked || this._isActive || this._cooldownRemaining > 0) {
      return false;
    }

    // Activate dash
    this._isActive = true;
    this._durationRemaining = getDashDurationForLevel(this._level);

    return true;
  }

  /**
   * Update the dash system each frame.
   * Manages the duration countdown while active, and cooldown countdown after.
   *
   * @param dt - Delta time in seconds since last frame
   */
  public update(dt: number): void {
    if (this._isActive) {
      this._durationRemaining -= dt;

      if (this._durationRemaining <= 0) {
        // Dash duration ended — start cooldown
        this._isActive = false;
        this._durationRemaining = 0;
        this._cooldownRemaining = DASH_COOLDOWN;
      }
    } else if (this._cooldownRemaining > 0) {
      this._cooldownRemaining -= dt;

      if (this._cooldownRemaining <= 0) {
        this._cooldownRemaining = 0;
      }
    }
  }

  /**
   * Whether the dash is currently active (Bee has speed boost + invincibility).
   */
  public get isActive(): boolean {
    return this._isActive;
  }

  /**
   * Whether the dash is on cooldown (cannot be activated).
   */
  public get isOnCooldown(): boolean {
    return this._cooldownRemaining > 0;
  }

  /**
   * Get the current cooldown remaining in seconds.
   * Used for HUD display while on cooldown.
   */
  public get cooldownRemaining(): number {
    return this._cooldownRemaining;
  }

  /**
   * Get the current duration remaining in seconds.
   */
  public get durationRemaining(): number {
    return this._durationRemaining;
  }

  /**
   * Get the speed multiplier for the current dash level.
   * Returns the multiplier from UPGRADE_CONFIGS.dash.effects[level-1].
   * Returns 1 if dash is not unlocked.
   */
  public getSpeedMultiplier(): number {
    return getDashMultiplierForLevel(this._level);
  }

  /**
   * Get the duration for the current dash level.
   * Returns the duration from DASH_DURATIONS[level-1].
   * Returns 0 if dash is not unlocked.
   */
  public getDuration(): number {
    return getDashDurationForLevel(this._level);
  }

  /**
   * The current dash upgrade level.
   */
  public get level(): number {
    return this._level;
  }

  /**
   * Whether the dash ability is unlocked.
   */
  public get unlocked(): boolean {
    return this._unlocked;
  }

  /**
   * Update the dash level (e.g., after an upgrade purchase).
   *
   * @param level - The new dash upgrade level
   */
  public setLevel(level: number): void {
    this._level = level;
    this._unlocked = level > 0;
  }
}
