/**
 * Bird_05 (Pursuer / Chaser) enemy system for the Bee Game.
 *
 * Bird_05 is a flocking aggressive pursuer. The flock is assembled by assigning
 * each spawned bird a `flockRole` (round-robin: top → bottom → chaser) so the
 * birds approach the bee from different angles. Attacks are throttled by a
 * single system-wide "attack token" — when one bird commits to a dive the next
 * dive is gated by a random 0.5-1s wait, so the flock attacks in sequence
 * rather than as a doomstack.
 *
 * Per-bird state machine:
 *   roam     — head toward a role-adjusted point near the bee. When the bee
 *              enters `chaseTriggerRadius` AND the flock attack token is
 *              available, commit to a dive.
 *   dive     — locked linear trajectory; ends `diveOvershootFactor` (default
 *              +50%) past the bee. Lethal on contact (once per dive).
 *   cooldown — diagonal-up escape mirroring the dive direction
 *              (same horizontal sign, reflected vertical), with a minimum
 *              upward fraction enforced so even a near-horizontal dive
 *              produces a visible climb. After `attackCooldown` seconds → roam.
 *
 * @packageDocumentation
 */
import type { World, EntityId, Query } from '@astracore/ecs';
import {
  PursuerBirdTag,
  Position,
  Velocity,
  CircleCollider,
  PursuerState,
} from '../components.js';
import { BIRD_05_CONFIG, type Bird05Config } from '../enemy-config.js';
import {
  loadFraction,
  computeChaseSpeed,
  predictLeadPoint,
  desiredVelocity,
  steerToward,
  distance,
  type Vec2,
} from './chaser-logic.js';

/** Snapshot of the bee's state needed to drive pursuit each frame. */
export interface BeeSnapshot {
  x: number;
  y: number;
  vx: number;
  vy: number;
  /** Current pollen load. */
  pollenLoad: number;
  /** Bee carrying capacity (for load fraction). */
  maxCapacity: number;
  /** Bee collider radius. */
  radius: number;
  /** True when the bee is in a safe zone (e.g. overlapping the hive). */
  inSafeZone: boolean;
  /** Day progress in [0, 1] — currently unused, kept for compatibility. */
  dayProgress: number;
  /** Ground surface Y (clamps the dive overshoot so birds don't burrow). */
  groundY: number;
}

/** The effect of a Bird_05 attack on contact, surfaced to the game scene. */
export interface PursuerAttack {
  /** Entity that landed the hit. */
  id: EntityId;
  /** Always 0 — dive-through model has no pollen-steal. */
  pollenStolen: number;
  /** Always 0 — dive-through model has no knockback. */
  knockbackX: number;
  knockbackY: number;
  /** Always true — dive contact is lethal. */
  lethal: boolean;
}

/** Round-robin role assignment for the flock. */
const FLOCK_ROLES: ReadonlyArray<'top' | 'bottom' | 'chaser'> = ['top', 'bottom', 'chaser'];

// ─── Bird05System ─────────────────────────────────────────────────────────────

/**
 * Manages all Bird_05 pursuer entities: spawning, flock role assignment, the
 * per-bird state machine, dive-through attacks, and the flock-wide attack
 * stagger token.
 */
export class Bird05System {
  private readonly _world: World;
  private readonly _config: Bird05Config;
  private readonly _entities: Set<EntityId> = new Set();
  private readonly _query: Query<
    [typeof PursuerBirdTag, typeof Position, typeof Velocity, typeof CircleCollider, typeof PursuerState]
  >;
  private readonly _rand: () => number;

  /** Total time elapsed in this system's clock (used by the attack token). */
  private _elapsedTime: number = 0;
  /** Earliest time (in `_elapsedTime`) the next bird is allowed to commit. */
  private _nextAttackTime: number = 0;
  /** Spawn counter for round-robin flock role assignment. */
  private _spawnIndex: number = 0;

  constructor(world: World, config: Bird05Config = BIRD_05_CONFIG, rand: () => number = Math.random) {
    this._world = world;
    this._config = config;
    this._rand = rand;
    this._query = world.query({
      with: [PursuerBirdTag, Position, Velocity, CircleCollider, PursuerState],
    });
  }

  /** Number of active pursuers. */
  public get count(): number {
    return this._entities.size;
  }

  /** Tracked pursuer entity ids (read-only). */
  public get entities(): ReadonlySet<EntityId> {
    return this._entities;
  }

  /** Read-only access to the underlying world (for sprite sync / collisions). */
  public get world(): World {
    return this._world;
  }

  /** Seconds remaining until the next bird may commit to a dive. 0 if available now. */
  public get attackTokenRemaining(): number {
    return Math.max(0, this._nextAttackTime - this._elapsedTime);
  }

  /**
   * Spawn a Bird_05 inside its vertical roaming band, starting in roam mode.
   *
   * @param spawnX - X spawn position (world coordinates).
   * @param groundY - Ground surface Y (bottom of playable space).
   * @param topY - Top of the playable area Y.
   */
  public spawn(spawnX: number, groundY: number, topY: number): EntityId {
    const world = this._world;
    const verticalSpace = groundY - topY;
    const minY = topY + this._config.minHeightFraction * verticalSpace;
    const maxY = topY + this._config.maxHeightFraction * verticalSpace;
    const safeMaxY = Math.max(minY, maxY);
    const spawnY = minY + this._rand() * (safeMaxY - minY);
    const role = FLOCK_ROLES[this._spawnIndex % FLOCK_ROLES.length]!;
    this._spawnIndex += 1;

    const entity = world.createEntity();
    world.addComponent(entity, new PursuerBirdTag());
    world.addComponent(entity, new Position(spawnX, spawnY));
    // Start at rest — roam steering ramps the bird up to chase speed via turnResponsiveness.
    world.addComponent(entity, new Velocity(0, 0));
    world.addComponent(entity, new CircleCollider(this._config.colliderRadius));
    world.addComponent(
      entity,
      new PursuerState(
        'roam',
        0,
        0, 0,                  // diveTargetX/Y
        role,
        minY,
        safeMaxY,
        false,                 // diveHitMade
      ),
    );

    this._entities.add(entity);
    return entity;
  }

  /**
   * Advance all pursuers one frame and return any lethal dive-contacts.
   *
   * @param dt - Delta time in seconds.
   * @param bee - Snapshot of the bee's current state.
   * @returns Attacks landed this frame (usually empty).
   */
  public update(dt: number, bee: BeeSnapshot): PursuerAttack[] {
    this._elapsedTime += dt;
    const cfg = this._config;
    const attacks: PursuerAttack[] = [];
    const beePos: Vec2 = { x: bee.x, y: bee.y };
    const load = loadFraction(bee.pollenLoad, bee.maxCapacity);
    const chaseSpeed = computeChaseSpeed(load, cfg);

    this._query.forEach((entity, _tag, pos, vel, col, state) => {
      state.phaseTimer += dt;

      // Roam → Dive: only allowed when the flock-wide attack token is free.
      // The trigger uses the bird's *current* position so the locked dive arc
      // is clean and observable.
      if (state.phase === 'roam') {
        const d = distance({ x: pos.x, y: pos.y }, beePos);
        const tokenFree = this._elapsedTime >= this._nextAttackTime;
        if (tokenFree && !bee.inSafeZone && d <= cfg.chaseTriggerRadius) {
          this._enterDive(state, pos, bee);
          // Take the token: stagger the next attack by a random 0.5-1s.
          const r = this._rand();
          this._nextAttackTime =
            this._elapsedTime + cfg.attackStaggerMin + r * (cfg.attackStaggerMax - cfg.attackStaggerMin);
        }
      }

      switch (state.phase) {
        case 'roam':
          this._updateRoam(dt, pos, vel, beePos, bee, chaseSpeed, state);
          break;

        case 'dive': {
          const arrived = this._updateDive(dt, pos, vel, state);
          // Lethal contact (once per dive).
          if (!state.diveHitMade && !bee.inSafeZone) {
            const cdx = bee.x - pos.x;
            const cdy = bee.y - pos.y;
            if (Math.sqrt(cdx * cdx + cdy * cdy) <= col.radius + bee.radius) {
              attacks.push({
                id: entity,
                pollenStolen: 0,
                knockbackX: 0,
                knockbackY: 0,
                lethal: true,
              });
              state.diveHitMade = true;
            }
          }
          if (arrived || state.phaseTimer >= cfg.maxDiveDuration) {
            this._enterCooldown(state, vel);
          }
          break;
        }

        case 'cooldown':
          this._updateCooldown(dt, pos, vel);
          if (state.phaseTimer >= cfg.attackCooldown) {
            this._enter(state, 'roam');
          }
          break;
      }
    });

    // Reconcile tracked set with externally destroyed entities.
    for (const entity of [...this._entities]) {
      if (!this._world.hasEntity(entity)) this._entities.delete(entity);
    }

    return attacks;
  }

  /** Destroy all pursuers and clear state. */
  public clear(): void {
    for (const entity of this._entities) {
      if (this._world.hasEntity(entity)) this._world.destroyEntity(entity);
    }
    this._entities.clear();
  }

  /** Read-only query for sprite sync / external collision inspection. */
  public get query(): Query<
    [typeof PursuerBirdTag, typeof Position, typeof Velocity, typeof CircleCollider, typeof PursuerState]
  > {
    return this._query;
  }

  /**
   * Compute the role-adjusted roam target for a bird. 'top' hovers above the
   * bee, 'bottom' below (clamped above ground), 'chaser' aims directly.
   */
  public roamTargetForRole(beePos: Vec2, state: PursuerState, bee: BeeSnapshot): Vec2 {
    const off = this._config.flockVerticalSpread;
    switch (state.flockRole) {
      case 'top':
        return { x: beePos.x, y: Math.max(state.minY, beePos.y - off) };
      case 'bottom':
        return { x: beePos.x, y: Math.min(bee.groundY - 40, beePos.y + off) };
      case 'chaser':
      default:
        return { x: beePos.x, y: beePos.y };
    }
  }

  // ─── Private helpers ────────────────────────────────────────────────────

  private _enter(state: PursuerState, phase: PursuerState['phase']): void {
    if (state.phase === phase) return;
    state.phase = phase;
    state.phaseTimer = 0;
  }

  /**
   * Lock a dive trajectory: target = pos + (1 + overshoot) × (bee − pos), so the
   * bird passes through the bee at the midpoint and ends `overshoot` past it.
   * The dive Y is clamped just above the ground so the bird never burrows.
   */
  private _enterDive(state: PursuerState, pos: Position, bee: BeeSnapshot): void {
    const cfg = this._config;
    const dx = bee.x - pos.x;
    const dy = bee.y - pos.y;
    const k = 1 + cfg.diveOvershootFactor;
    state.diveTargetX = pos.x + dx * k;
    state.diveTargetY = Math.min(pos.y + dy * k, bee.groundY - 10);
    state.diveHitMade = false;
    this._enter(state, 'dive');
  }

  /**
   * Enter cooldown with a diagonal-up escape velocity. The escape preserves the
   * dive's horizontal direction and reflects the vertical to upward, scaled to
   * `ascendSpeed`. A minimum climb factor guarantees that even a near-horizontal
   * dive produces a visible diagonal-up arc (not a flat slide).
   */
  private _enterCooldown(state: PursuerState, vel: Velocity): void {
    const cfg = this._config;
    const sp = Math.hypot(vel.dx, vel.dy);
    if (sp > 1e-3) {
      const fac = cfg.ascendSpeed / sp;
      vel.dx = vel.dx * fac;
      vel.dy = -Math.abs(vel.dy) * fac;
      const minClimb = cfg.ascendSpeed * cfg.escapeMinClimbFactor;
      if (vel.dy > -minClimb) vel.dy = -minClimb;
    } else {
      vel.dx = 0;
      vel.dy = -cfg.ascendSpeed;
    }
    this._enter(state, 'cooldown');
  }

  /** Roam — head toward the role-adjusted point near the bee. */
  private _updateRoam(
    dt: number,
    pos: Position,
    vel: Velocity,
    beePos: Vec2,
    bee: BeeSnapshot,
    speed: number,
    state: PursuerState,
  ): void {
    const cfg = this._config;
    const target = this._roamTarget(pos, beePos, bee, state);
    // Mix in a small lead component toward the bee's predicted position for
    // chasers — top/bottom roles and the safe-zone retreat aim at fixed points.
    const useLead = state.flockRole === 'chaser' && !bee.inSafeZone;
    const aim = useLead
      ? predictLeadPoint(target, { x: bee.vx, y: bee.vy }, cfg.leadTime)
      : target;
    const desired = desiredVelocity({ x: pos.x, y: pos.y }, aim, speed);
    const smoothed = steerToward({ x: vel.dx, y: vel.dy }, desired, cfg.turnResponsiveness, dt);
    vel.dx = smoothed.x;
    vel.dy = smoothed.y;
    pos.x += vel.dx * dt;
    pos.y += vel.dy * dt;
  }

  /**
   * Resolve the roam target. While the bee is in the safe zone (overlapping
   * the hive), the bird disengages and aims at a retreat point — away from
   * the bee on the bird's current side, lifted toward the top of the band —
   * instead of looping endlessly around the unreachable bee.
   */
  private _roamTarget(
    pos: Position,
    beePos: Vec2,
    bee: BeeSnapshot,
    state: PursuerState,
  ): Vec2 {
    if (bee.inSafeZone) {
      const dx = pos.x - beePos.x;
      // Bias the retreat to the side the bird is already on; if exactly above
      // or below the bee, retreat to the right (positive x).
      const sign = dx === 0 ? 1 : Math.sign(dx);
      return {
        x: pos.x + sign * 400,
        y: Math.max(state.minY + 20, pos.y - 60),
      };
    }
    return this.roamTargetForRole(beePos, state, bee);
  }

  /**
   * Dive — move along the locked trajectory at `diveSpeed`. Returns true when
   * the bird has reached the dive target.
   */
  private _updateDive(
    dt: number,
    pos: Position,
    vel: Velocity,
    state: PursuerState,
  ): boolean {
    const cfg = this._config;
    const tdx = state.diveTargetX - pos.x;
    const tdy = state.diveTargetY - pos.y;
    const tdist = Math.sqrt(tdx * tdx + tdy * tdy);
    if (tdist < 8) {
      // Preserve vel direction (along the dive trajectory) so cooldown can
      // mirror it diagonally. Avoid divide-by-zero when already on target.
      if (tdist > 0) {
        vel.dx = (tdx / tdist) * cfg.diveSpeed;
        vel.dy = (tdy / tdist) * cfg.diveSpeed;
      }
      pos.x = state.diveTargetX;
      pos.y = state.diveTargetY;
      return true;
    }
    const step = Math.min(cfg.diveSpeed * dt, tdist);
    vel.dx = (tdx / tdist) * cfg.diveSpeed;
    vel.dy = (tdy / tdist) * cfg.diveSpeed;
    pos.x += (tdx / tdist) * step;
    pos.y += (tdy / tdist) * step;
    return false;
  }

  /**
   * Cooldown — apply the locked diagonal-up escape velocity with mild drag so
   * the bird's escape decelerates smoothly over the cooldown window.
   */
  private _updateCooldown(dt: number, pos: Position, vel: Velocity): void {
    pos.x += vel.dx * dt;
    pos.y += vel.dy * dt;
    const drag = Math.exp(-0.6 * dt);
    vel.dx *= drag;
    vel.dy *= drag;
  }
}
