/// <reference lib="dom" />

import type { World } from '@astracore/ecs';
import type { AssetManager } from '@astracore/assets';
import type { Scene } from '@astracore/scene';
import type { ILocalization } from '../localization.js';
import type { ISaveStorage, BeeGameSaveData } from '@astracore/save-storage-core';
import type { ISceneTransition } from '../scene-transition.js';
import { Application, Container, Text, Graphics } from 'pixi.js';
import { UPGRADE_CONFIGS, type UpgradeId } from '../upgrade-config.js';

// ─── Local analytics interface ──────────────────────────────────────────────

/** Minimal analytics interface matching AnalyticsRegistry.track(). */
export interface IHiveHubAnalytics {
  track(event: { type: 'enter_day'; day: number }): void;
}

// ─── Upgrade Row UI ─────────────────────────────────────────────────────────

interface UpgradeRow {
  id: UpgradeId;
  container: Container;
  nameText: Text;
  levelText: Text;
  costText: Text;
  buyButton: Container;
  buyButtonText: Text;
  maxText: Text;
}

// ─── Constants ──────────────────────────────────────────────────────────────

/** Fixed design height for layout. */
const DESIGN_HEIGHT = 600;

/** Vertical spacing between upgrade rows. */
const ROW_HEIGHT = 50;

/** Y offset for the first upgrade row. */
const ROWS_START_Y = 160;

/** Button colors. */
const BUTTON_COLOR_ACTIVE = 0x44aa44;
const BUTTON_COLOR_DISABLED = 0x666666;
const BUTTON_COLOR_HOVER = 0x55cc55;

// ─── HiveHubScene ───────────────────────────────────────────────────────────

/**
 * Between-day hub screen where players view progress and purchase upgrades.
 *
 * Displays the player's pollen balance, lives, days completed, and available
 * upgrades. Upgrade visibility is controlled by the current day number.
 *
 * Lifecycle:
 * - onLoad: no-op (assets loaded by main pipeline)
 * - onEnter: build UI, load save data, display upgrades
 * - onExit: destroy display objects
 * - onUnload: no-op
 */
export class HiveHubScene implements Scene {
  public readonly name = 'hive-hub';

  // ── Dependencies ────────────────────────────────────────────────────────
  private readonly _pixiApp: Application;
  private readonly _localization: ILocalization;
  private readonly _saveStorage: ISaveStorage;
  private readonly _sceneTransition: ISceneTransition;
  private readonly _onNextDay: () => void;
  private readonly _analytics: IHiveHubAnalytics | null;

  // ── Display objects ─────────────────────────────────────────────────────
  private _rootContainer: Container | null = null;
  private _titleText: Text | null = null;
  private _dayText: Text | null = null;
  private _livesText: Text | null = null;
  private _daysCompletedText: Text | null = null;
  private _balanceText: Text | null = null;
  private _nextDayButton: Container | null = null;
  private _upgradeRows: UpgradeRow[] = [];

  // ── Game state ──────────────────────────────────────────────────────────
  private _saveData: BeeGameSaveData = {
    version: 1,
    pollenBalance: 0,
    daysCompleted: 0,
    upgrades: { speed: 0, capacity: 0, dayTime: 0, lives: 0, dash: 0, magnet: 0 },
    lives: 3,
  };

  // ── Layout ──────────────────────────────────────────────────────────────
  private _viewportWidth = 0;

  constructor(options: {
    pixiApp: Application;
    localization: ILocalization;
    saveStorage: ISaveStorage;
    sceneTransition: ISceneTransition;
    onNextDay: () => void;
    analytics?: IHiveHubAnalytics | null;
  }) {
    this._pixiApp = options.pixiApp;
    this._localization = options.localization;
    this._saveStorage = options.saveStorage;
    this._sceneTransition = options.sceneTransition;
    this._onNextDay = options.onNextDay;
    this._analytics = options.analytics ?? null;
  }

  // ── onLoad ──────────────────────────────────────────────────────────────

  public async onLoad(_world: World, _assets: AssetManager | undefined): Promise<void> {
    // Assets are already loaded by the main asset pipeline.
  }

  // ── onEnter ─────────────────────────────────────────────────────────────

  public onEnter(_world: World): void {
    // Compute viewport dimensions
    const scale = this._pixiApp.screen.height / DESIGN_HEIGHT;
    this._viewportWidth = this._pixiApp.screen.width / scale;

    // Root container
    this._rootContainer = new Container();
    this._pixiApp.stage.addChild(this._rootContainer);

    // Load save data then build UI
    this._loadAndBuild();
  }

  // ── onExit ──────────────────────────────────────────────────────────────

  public onExit(_world: World): void {
    if (this._rootContainer) {
      this._pixiApp.stage.removeChild(this._rootContainer);
      this._rootContainer.destroy({ children: true });
      this._rootContainer = null;
    }

    this._titleText = null;
    this._dayText = null;
    this._livesText = null;
    this._daysCompletedText = null;
    this._balanceText = null;
    this._nextDayButton = null;
    this._upgradeRows = [];
  }

  // ── onUnload ────────────────────────────────────────────────────────────

  public onUnload(_world: World): void {
    // Nothing additional to clean up.
  }

  // ── Private: load save data and build UI ────────────────────────────────

  private async _loadAndBuild(): Promise<void> {
    // Load existing save data
    const loaded = await this._saveStorage.load<BeeGameSaveData>('bee-game');
    if (loaded) {
      this._saveData = loaded;
    }

    this._buildUI();
    // The host (main.ts) drives the fade transition via playWithSwap.
  }

  // ── Private: build the full UI ──────────────────────────────────────────

  private _buildUI(): void {
    const centerX = this._viewportWidth / 2;
    const loc = this._localization;

    // ── Title ───────────────────────────────────────────────────────────
    this._titleText = new Text({
      text: loc.t('hub.title'),
      style: {
        fontFamily: 'Courier New',
        fontSize: 36,
        fontWeight: 'bold',
        fill: 0xffd040,
        dropShadow: {
          color: 0x000000,
          blur: 4,
          distance: 2,
          angle: Math.PI / 4,
        },
      },
    });
    this._titleText.anchor.set(0.5, 0);
    this._titleText.x = centerX;
    this._titleText.y = 20;
    this._rootContainer!.addChild(this._titleText);

    // ── Day number (upcoming day) ───────────────────────────────────────
    const upcomingDay = this._saveData.daysCompleted + 1;
    this._dayText = new Text({
      text: loc.t('hub.day', { day: upcomingDay }),
      style: {
        fontFamily: 'Courier New',
        fontSize: 22,
        fill: 0xffffff,
      },
    });
    this._dayText.anchor.set(0.5, 0);
    this._dayText.x = centerX;
    this._dayText.y = 62;
    this._rootContainer!.addChild(this._dayText);

    // ── Stats row: lives, days completed, pollen balance ────────────────
    const statsY = 95;
    const statsSpacing = this._viewportWidth / 4;

    this._livesText = new Text({
      text: loc.t('hud.lives', { count: this._saveData.lives }),
      style: { fontFamily: 'Courier New', fontSize: 16, fill: 0xffffff },
    });
    this._livesText.anchor.set(0.5, 0);
    this._livesText.x = statsSpacing;
    this._livesText.y = statsY;
    this._rootContainer!.addChild(this._livesText);

    this._daysCompletedText = new Text({
      text: loc.t('hub.days', { count: this._saveData.daysCompleted }),
      style: { fontFamily: 'Courier New', fontSize: 16, fill: 0xffffff },
    });
    this._daysCompletedText.anchor.set(0.5, 0);
    this._daysCompletedText.x = statsSpacing * 2;
    this._daysCompletedText.y = statsY;
    this._rootContainer!.addChild(this._daysCompletedText);

    this._balanceText = new Text({
      text: loc.t('hub.pollen', { amount: this._saveData.pollenBalance }),
      style: { fontFamily: 'Courier New', fontSize: 16, fill: 0xffdd00 },
    });
    this._balanceText.anchor.set(0.5, 0);
    this._balanceText.x = statsSpacing * 3;
    this._balanceText.y = statsY;
    this._rootContainer!.addChild(this._balanceText);

    // ── Upgrade rows ────────────────────────────────────────────────────
    this._buildUpgradeRows();

    // ── "Go to Next Day" button ─────────────────────────────────────────
    this._buildNextDayButton();
  }

  // ── Private: build upgrade rows ─────────────────────────────────────────

  private _buildUpgradeRows(): void {
    const loc = this._localization;
    const currentDay = this._saveData.daysCompleted + 1;
    const visibleUpgrades = this._getVisibleUpgrades(currentDay);

    let rowIndex = 0;
    for (const upgradeId of visibleUpgrades) {
      const config = UPGRADE_CONFIGS[upgradeId];
      const currentLevel = this._saveData.upgrades[upgradeId] ?? 0;
      const isMaxed = currentLevel >= config.maxLevel;
      const cost = isMaxed ? 0 : config.costs[currentLevel]!;
      const canAfford = this._saveData.pollenBalance >= cost;

      const rowY = ROWS_START_Y + rowIndex * ROW_HEIGHT;
      const rowContainer = new Container();
      rowContainer.y = rowY;
      this._rootContainer!.addChild(rowContainer);

      // Upgrade name
      const nameText = new Text({
        text: loc.t(config.name),
        style: { fontFamily: 'Courier New', fontSize: 16, fill: 0xffffff },
      });
      nameText.anchor.set(0, 0.5);
      nameText.x = 30;
      nameText.y = 0;
      rowContainer.addChild(nameText);

      // Level indicator
      const levelText = new Text({
        text: `Lv ${currentLevel}/${config.maxLevel}`,
        style: { fontFamily: 'Courier New', fontSize: 14, fill: 0xaaaaaa },
      });
      levelText.anchor.set(0, 0.5);
      levelText.x = 200;
      levelText.y = 0;
      rowContainer.addChild(levelText);

      // Cost text
      const costText = new Text({
        text: isMaxed ? '' : `Cost: ${cost}`,
        style: { fontFamily: 'Courier New', fontSize: 14, fill: canAfford ? 0xffdd00 : 0xff6666 },
      });
      costText.anchor.set(0, 0.5);
      costText.x = 310;
      costText.y = 0;
      rowContainer.addChild(costText);

      // Buy button
      const buyButton = new Container();
      const buyBg = new Graphics();
      const btnWidth = 60;
      const btnHeight = 28;
      buyBg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 4);
      buyBg.fill({ color: canAfford ? BUTTON_COLOR_ACTIVE : BUTTON_COLOR_DISABLED });
      buyButton.addChild(buyBg);

      const buyButtonText = new Text({
        text: loc.t('hub.buy'),
        style: { fontFamily: 'Courier New', fontSize: 14, fontWeight: 'bold', fill: 0xffffff },
      });
      buyButtonText.anchor.set(0.5, 0.5);
      buyButton.addChild(buyButtonText);

      buyButton.x = this._viewportWidth - 70;
      buyButton.y = 0;
      buyButton.eventMode = 'static';
      buyButton.cursor = canAfford ? 'pointer' : 'default';
      buyButton.visible = !isMaxed;

      if (canAfford && !isMaxed) {
        buyButton.on('pointerover', () => {
          buyBg.clear();
          buyBg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 4);
          buyBg.fill({ color: BUTTON_COLOR_HOVER });
        });
        buyButton.on('pointerout', () => {
          buyBg.clear();
          buyBg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 4);
          buyBg.fill({ color: BUTTON_COLOR_ACTIVE });
        });
        buyButton.on('pointerdown', () => {
          this._purchaseUpgrade(upgradeId);
        });
      }

      rowContainer.addChild(buyButton);

      // MAX indicator
      const maxText = new Text({
        text: loc.t('upgrade.max'),
        style: { fontFamily: 'Courier New', fontSize: 14, fontWeight: 'bold', fill: 0x44ff44 },
      });
      maxText.anchor.set(0.5, 0.5);
      maxText.x = this._viewportWidth - 70;
      maxText.y = 0;
      maxText.visible = isMaxed;
      rowContainer.addChild(maxText);

      this._upgradeRows.push({
        id: upgradeId,
        container: rowContainer,
        nameText,
        levelText,
        costText,
        buyButton,
        buyButtonText,
        maxText,
      });

      rowIndex++;
    }
  }

  // ── Private: build "Go to Next Day" button ──────────────────────────────

  private _buildNextDayButton(): void {
    const loc = this._localization;
    const centerX = this._viewportWidth / 2;
    const buttonY = DESIGN_HEIGHT - 60;

    this._nextDayButton = new Container();
    this._nextDayButton.x = centerX;
    this._nextDayButton.y = buttonY;

    const btnWidth = 200;
    const btnHeight = 40;
    const bg = new Graphics();
    bg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 6);
    bg.fill({ color: 0x2266cc });
    this._nextDayButton.addChild(bg);

    const label = new Text({
      text: loc.t('hub.nextDay'),
      style: {
        fontFamily: 'Courier New',
        fontSize: 18,
        fontWeight: 'bold',
        fill: 0xffffff,
      },
    });
    label.anchor.set(0.5, 0.5);
    this._nextDayButton.addChild(label);

    this._nextDayButton.eventMode = 'static';
    this._nextDayButton.cursor = 'pointer';

    this._nextDayButton.on('pointerover', () => {
      bg.clear();
      bg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 6);
      bg.fill({ color: 0x3388ee });
    });
    this._nextDayButton.on('pointerout', () => {
      bg.clear();
      bg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 6);
      bg.fill({ color: 0x2266cc });
    });
    this._nextDayButton.on('pointerdown', () => {
      this._goToNextDay();
    });

    this._rootContainer!.addChild(this._nextDayButton);
  }

  // ── Private: purchase upgrade ───────────────────────────────────────────

  private _purchaseUpgrade(upgradeId: UpgradeId): void {
    const config = UPGRADE_CONFIGS[upgradeId];
    const currentLevel = this._saveData.upgrades[upgradeId] ?? 0;

    // Guard: already at max
    if (currentLevel >= config.maxLevel) return;

    const cost = config.costs[currentLevel]!;

    // Guard: insufficient balance
    if (this._saveData.pollenBalance < cost) return;

    // Deduct cost, increment level
    this._saveData.pollenBalance -= cost;
    this._saveData.upgrades[upgradeId] = currentLevel + 1;

    // Update lives if lives upgrade was purchased
    if (upgradeId === 'lives') {
      this._saveData.lives = 3 + this._saveData.upgrades.lives;
    }

    // Refresh the display
    this._refreshDisplay();
  }

  // ── Private: refresh display after purchase ─────────────────────────────

  private _refreshDisplay(): void {
    const loc = this._localization;

    // Update balance
    if (this._balanceText) {
      this._balanceText.text = loc.t('hub.pollen', { amount: this._saveData.pollenBalance });
    }

    // Update lives
    if (this._livesText) {
      this._livesText.text = loc.t('hud.lives', { count: this._saveData.lives });
    }

    // Update each upgrade row
    for (const row of this._upgradeRows) {
      const config = UPGRADE_CONFIGS[row.id];
      const currentLevel = this._saveData.upgrades[row.id] ?? 0;
      const isMaxed = currentLevel >= config.maxLevel;
      const cost = isMaxed ? 0 : config.costs[currentLevel]!;
      const canAfford = this._saveData.pollenBalance >= cost;

      // Level text
      row.levelText.text = `Lv ${currentLevel}/${config.maxLevel}`;

      // Cost text
      row.costText.text = isMaxed ? '' : `Cost: ${cost}`;
      (row.costText.style as { fill: number }).fill = canAfford ? 0xffdd00 : 0xff6666;

      // Buy button visibility and interactivity
      row.buyButton.visible = !isMaxed;
      if (!isMaxed) {
        row.buyButton.cursor = canAfford ? 'pointer' : 'default';
        // Remove old listeners and rebind
        row.buyButton.removeAllListeners();

        if (canAfford) {
          const btnWidth = 60;
          const btnHeight = 28;
          const buyBg = row.buyButton.getChildAt(0) as Graphics;

          row.buyButton.on('pointerover', () => {
            buyBg.clear();
            buyBg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 4);
            buyBg.fill({ color: BUTTON_COLOR_HOVER });
          });
          row.buyButton.on('pointerout', () => {
            buyBg.clear();
            buyBg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 4);
            buyBg.fill({ color: BUTTON_COLOR_ACTIVE });
          });
          row.buyButton.on('pointerdown', () => {
            this._purchaseUpgrade(row.id);
          });

          // Update button color to active
          buyBg.clear();
          buyBg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 4);
          buyBg.fill({ color: BUTTON_COLOR_ACTIVE });
        } else {
          const btnWidth = 60;
          const btnHeight = 28;
          const buyBg = row.buyButton.getChildAt(0) as Graphics;
          buyBg.clear();
          buyBg.roundRect(-btnWidth / 2, -btnHeight / 2, btnWidth, btnHeight, 4);
          buyBg.fill({ color: BUTTON_COLOR_DISABLED });
        }
      }

      // MAX indicator
      row.maxText.visible = isMaxed;
    }
  }

  // ── Private: go to next day ─────────────────────────────────────────────

  private async _goToNextDay(): Promise<void> {
    // Save current state (upgrades purchased, balance, etc.)
    await this._saveStorage.save('bee-game', this._saveData);

    // Emit analytics event for the upcoming day
    const upcomingDay = this._saveData.daysCompleted + 1;
    if (this._analytics) {
      this._analytics.track({ type: 'enter_day', day: upcomingDay });
    }

    // Hand off to the host — it performs the fade + scene swap.
    this._onNextDay();
  }

  // ── Private: determine visible upgrades by day ──────────────────────────

  private _getVisibleUpgrades(day: number): UpgradeId[] {
    const visible: UpgradeId[] = [];

    for (const [id, config] of Object.entries(UPGRADE_CONFIGS)) {
      if (day >= config.unlockDay) {
        visible.push(id as UpgradeId);
      }
    }

    return visible;
  }
}
