/**
 * Bird-to-bird collision and evasion for the Bee Game.
 *
 * When two birds overlap, one of them evades by changing its flight height
 * (flying up, or bouncing away from the other bird). Evasion capability is a
 * per-bird trait (see the {@link Evasion} component):
 *
 * - If only one bird in the pair can evade, that bird evades.
 * - If both can evade, a random one of the pair evades.
 * - If neither can evade, the pair passes through (no height change).
 *
 * The actual height change is delegated to the owning bird system via
 * {@link EvasionCapableSystem.beginEvade}, so each system can apply the shift in
 * terms of its own flight model (glide target for Bird_01, oscillation baseline
 * for Bird_02) and clamp to its own vertical bounds.
 *
 * The decision functions are pure and exported for property-based testing.
 *
 * @packageDocumentation
 */

import type { EntityId } from '@astracore/ecs';
import { circlesOverlap } from '../collision.js';

// ─── Types ────────────────────────────────────────────────────────────────────

/** A lightweight snapshot of one bird for collision checking. */
export interface EvasionBird {
  /** Owning entity id. */
  id: EntityId;
  /** World X position. */
  x: number;
  /** World Y position. */
  y: number;
  /** Collider radius in pixels. */
  radius: number;
  /** Whether this bird is able to evade. */
  canEvade: boolean;
  /** Whether this bird is already performing an evade maneuver. */
  evading: boolean;
}

/** A bird system that can report its birds and perform evade maneuvers. */
export interface EvasionCapableSystem {
  /** Snapshot of this system's birds for collision checks. */
  collectEvasionBirds(): EvasionBird[];
  /**
   * Begin an evade maneuver on the given entity, shifting its flight height.
   * @param id - Entity id to evade.
   * @param dir - Vertical direction: -1 = fly up, +1 = bounce down.
   */
  beginEvade(id: EntityId, dir: number): void;
}

// ─── Pure decision functions ───────────────────────────────────────────────────

/** Result of {@link chooseEvader}: which bird in a pair should evade. */
export type EvaderChoice = 0 | 1 | -1;

/**
 * Decide which bird in a colliding pair should evade.
 *
 * A bird is a candidate only if it can evade and is not already evading.
 * - Both candidates → a random one (using `rand`, a value in [0, 1)).
 * - Exactly one candidate → that one.
 * - No candidates → -1 (no evade).
 *
 * @param aCanEvade - Bird A can evade.
 * @param aEvading - Bird A is already evading.
 * @param bCanEvade - Bird B can evade.
 * @param bEvading - Bird B is already evading.
 * @param rand - Random value in [0, 1) used to break ties.
 * @returns 0 (A evades), 1 (B evades), or -1 (no evade).
 */
export function chooseEvader(
  aCanEvade: boolean,
  aEvading: boolean,
  bCanEvade: boolean,
  bEvading: boolean,
  rand: number,
): EvaderChoice {
  const aCandidate = aCanEvade && !aEvading;
  const bCandidate = bCanEvade && !bEvading;

  if (aCandidate && bCandidate) {
    return rand < 0.5 ? 0 : 1;
  }
  if (aCandidate) return 0;
  if (bCandidate) return 1;
  return -1;
}

/**
 * Compute the vertical evade direction for a bird relative to the bird it hit.
 *
 * The evader moves away from the other bird: up if it is at or above the other
 * bird (smaller Y), down otherwise. The owning system may flip this if the
 * chosen direction would leave its vertical bounds.
 *
 * @param evaderY - Evading bird's Y position.
 * @param otherY - Other bird's Y position.
 * @returns -1 to fly up, +1 to bounce down.
 */
export function evadeDirection(evaderY: number, otherY: number): -1 | 1 {
  return evaderY <= otherY ? -1 : 1;
}

// ─── BirdCollisionSystem ────────────────────────────────────────────────────────

/**
 * Detects collisions between birds across one or more bird systems and triggers
 * evade maneuvers. Birds from different systems (e.g. Bird_01 vs Bird_02) are
 * checked against each other as well as within the same system.
 */
export class BirdCollisionSystem {
  private readonly _systems: readonly EvasionCapableSystem[];
  private readonly _rand: () => number;

  /**
   * @param systems - Bird systems whose birds participate in evasion.
   * @param rand - RNG returning [0, 1); injectable for deterministic tests.
   */
  constructor(systems: readonly EvasionCapableSystem[], rand: () => number = Math.random) {
    this._systems = systems;
    this._rand = rand;
  }

  /**
   * Check every unordered pair of birds for overlap and trigger an evade on the
   * chosen bird of each colliding pair. Should be called once per frame after
   * the bird systems have moved their entities.
   */
  public update(): void {
    // Flatten all birds, remembering which system owns each.
    const birds: EvasionBird[] = [];
    const owners: EvasionCapableSystem[] = [];
    for (const system of this._systems) {
      for (const bird of system.collectEvasionBirds()) {
        birds.push(bird);
        owners.push(system);
      }
    }

    for (let i = 0; i < birds.length; i++) {
      const a = birds[i]!;
      for (let j = i + 1; j < birds.length; j++) {
        const b = birds[j]!;

        if (!circlesOverlap(a.x, a.y, a.radius, b.x, b.y, b.radius)) continue;

        const choice = chooseEvader(a.canEvade, a.evading, b.canEvade, b.evading, this._rand());
        if (choice === -1) continue;

        const evader = choice === 0 ? a : b;
        const other = choice === 0 ? b : a;
        const ownerSystem = choice === 0 ? owners[i]! : owners[j]!;
        const dir = evadeDirection(evader.y, other.y);

        ownerSystem.beginEvade(evader.id, dir);
        // Reflect the new "evading" state locally so the same bird isn't chosen
        // again within this frame for another overlapping pair.
        evader.evading = true;
      }
    }
  }
}
