/**
 * Day timer system for the Bee Game.
 *
 * Manages the countdown timer for each day. The timer starts at a base of 60 seconds
 * plus any bonus from the Day Time upgrade. When it reaches zero, the expired flag is set
 * and a "Return to hive" message should be shown. If the player also loses all lives
 * while expired, the day ends.
 *
 * Exports pure functions for property testing:
 * - `calculateDisplaySeconds` — returns Math.ceil(remaining) for HUD display
 * - `calculateInitialTime` — returns baseTime + level * 5 (from UPGRADE_CONFIGS.dayTime.effects)
 *
 * @packageDocumentation
 */

// ─── Pure Functions (exported for property testing) ───────────────────────────

/**
 * Calculate the display value for the HUD timer.
 * Returns the ceiling of the remaining time so partial seconds always round up.
 *
 * @param remaining - Remaining time in seconds (must be >= 0)
 * @returns Whole seconds to display (Math.ceil)
 */
export function calculateDisplaySeconds(remaining: number): number {
  if (remaining <= 0) return 0;
  return Math.ceil(remaining);
}

/**
 * Calculate the initial time for a day based on the base time and Day Time upgrade level.
 * Each level of the Day Time upgrade adds 5 seconds.
 *
 * @param baseTime - The base countdown time in seconds (default 60)
 * @param dayTimeUpgradeLevel - The current level of the Day Time upgrade (0 = no upgrade)
 * @returns Total initial time in seconds
 */
export function calculateInitialTime(baseTime: number, dayTimeUpgradeLevel: number): number {
  return baseTime + dayTimeUpgradeLevel * 5;
}

// ─── DayTimerSystem ───────────────────────────────────────────────────────────

/**
 * Manages the day countdown timer, including decrementing, expiry detection,
 * and HUD display value calculation.
 */
export class DayTimerSystem {
  private _remaining: number;
  private _expired: boolean = false;

  /**
   * Create a new DayTimerSystem.
   *
   * @param initialTime - The starting countdown time in seconds (60 + dayTime upgrade modifier)
   */
  constructor(initialTime: number) {
    this._remaining = Math.max(0, initialTime);
    if (this._remaining === 0) {
      this._expired = true;
    }
  }

  /**
   * Update the timer by decrementing by delta time.
   * When the timer reaches zero, the expired flag is set.
   *
   * @param dt - Delta time in seconds since last frame
   */
  public update(dt: number): void {
    if (this._expired) return;

    this._remaining -= dt;

    if (this._remaining <= 0) {
      this._remaining = 0;
      this._expired = true;
    }
  }

  /**
   * Get the display value for the HUD — remaining seconds rounded up.
   * Returns 0 when the timer has expired.
   */
  public getDisplaySeconds(): number {
    return calculateDisplaySeconds(this._remaining);
  }

  /**
   * Whether the timer has reached zero.
   */
  public get isExpired(): boolean {
    return this._expired;
  }

  /**
   * The raw remaining time in seconds.
   */
  public get remaining(): number {
    return this._remaining;
  }

  /**
   * Reset the timer for a new day.
   *
   * @param initialTime - The new starting countdown time in seconds
   */
  public reset(initialTime: number): void {
    this._remaining = Math.max(0, initialTime);
    this._expired = this._remaining === 0;
  }
}
