/**
 * Pollen collection system for the Bee Game.
 *
 * Handles collision detection between the Bee and Collectible Flowers,
 * increments pollen load on collection, and manages particle effects
 * with staggered layer fade-in/fade-out animation.
 *
 * @packageDocumentation
 */

import { circlesOverlap } from '../collision.js';

// ─── Particle Animation Constants ─────────────────────────────────────────────

/** Duration (seconds) for each layer's fade-in animation. */
const FADE_IN_DURATION = 0.15;

/** Start times (seconds) for each layer's fade-in within one animation cycle. */
const LAYER_FADE_IN_STARTS = [0.0, 0.1, 0.3, 0.5];

/** Duration (seconds) for the simultaneous fadeout of all layers. */
const FADE_OUT_DURATION = 0.3;

/** The time at which the last layer finishes fading in (= all at full opacity). */
const ALL_FULL_TIME = LAYER_FADE_IN_STARTS[3]! + FADE_IN_DURATION; // 0.65s

/** Duration of one complete animation cycle (fade-in sequence + fadeout). */
const CYCLE_DURATION = ALL_FULL_TIME + FADE_OUT_DURATION; // 0.95s

/** Total particle animation duration before entity destruction. */
const TOTAL_DURATION = 1.5;

/** Number of particle layers. */
const LAYER_COUNT = 4;

/** Layer texture names. */
export const POLLEN_LAYER_NAMES = ['pollen_01', 'pollen_02', 'pollen_03', 'pollen_04'];

// ─── Pure Functions ───────────────────────────────────────────────────────────

/**
 * Calculate the opacity of a specific particle layer at a given elapsed time.
 *
 * The animation loops with a cycle of ~0.95s:
 * - Layers fade in sequentially (staggered start offsets: 0, 0.1, 0.3, 0.5s)
 * - Each layer fades in over 0.15s
 * - All layers fade out simultaneously over 0.3s after the last layer reaches full opacity
 * - The sequence loops for 1.5s total, then the particle is destroyed
 *
 * @param layerIndex - Layer index (0-3)
 * @param elapsed - Total elapsed time in seconds (0 to 1.5)
 * @returns Opacity value between 0 and 1
 */
export function calculateLayerOpacity(layerIndex: number, elapsed: number): number {
  if (layerIndex < 0 || layerIndex >= LAYER_COUNT) return 0;
  if (elapsed < 0) return 0;
  if (elapsed >= TOTAL_DURATION) return 0;

  // Determine position within the current animation cycle
  const cycleElapsed = elapsed % CYCLE_DURATION;

  const fadeInStart = LAYER_FADE_IN_STARTS[layerIndex]!;
  const fadeInEnd = fadeInStart + FADE_IN_DURATION;
  const fadeOutStart = ALL_FULL_TIME;
  const fadeOutEnd = ALL_FULL_TIME + FADE_OUT_DURATION;

  // Phase 1: Before this layer's fade-in starts
  if (cycleElapsed < fadeInStart) {
    return 0;
  }

  // Phase 2: During this layer's fade-in
  if (cycleElapsed < fadeInEnd) {
    const progress = (cycleElapsed - fadeInStart) / FADE_IN_DURATION;
    return Math.min(1, Math.max(0, progress));
  }

  // Phase 3: At full opacity (between fade-in end and fade-out start)
  if (cycleElapsed < fadeOutStart) {
    return 1;
  }

  // Phase 4: During fade-out (all layers fade out together)
  if (cycleElapsed < fadeOutEnd) {
    const progress = (cycleElapsed - fadeOutStart) / FADE_OUT_DURATION;
    return Math.max(0, Math.min(1, 1 - progress));
  }

  // Past fade-out end (shouldn't happen since cycleElapsed < CYCLE_DURATION)
  return 0;
}

// ─── Interfaces ───────────────────────────────────────────────────────────────

/** Represents a flower available for collision checking. */
export interface FlowerEntry {
  id: number | string;
  x: number;
  y: number;
  radius: number;
}

/** Request to spawn a particle effect at a given position. */
export interface ParticleSpawnRequest {
  x: number;
  y: number;
}

/** Result of the collection check. */
export interface CollectionResult {
  /** IDs of flowers that were collected. */
  collected: Array<number | string>;
  /** New pollen load after collections. */
  pollenLoad: number;
  /** Particle spawn requests for each collected flower. */
  particles: ParticleSpawnRequest[];
}

/** State of a single active particle effect. */
export interface ParticleState {
  x: number;
  y: number;
  elapsed: number;
  /** Per-layer opacity values (length 4). */
  layerOpacities: number[];
}

/** Result of updating particles. */
export interface ParticleUpdateResult {
  /** Active particles with updated opacities. */
  active: ParticleState[];
  /** Indices of particles that completed and should be destroyed. */
  destroyed: number[];
}

// ─── PollenCollectionSystem ───────────────────────────────────────────────────

/**
 * Manages pollen collection from flowers and animated particle effects.
 *
 * The system provides two main operations:
 * 1. `checkCollections` — detects Bee-flower overlap and triggers collection
 * 2. `updateParticles` — advances particle animation timers and computes opacities
 */
export class PollenCollectionSystem {
  private _pollenLoad: number = 0;
  private _particles: ParticleState[] = [];
  private _collectedIds: Set<number | string> = new Set();

  constructor(initialPollenLoad: number = 0) {
    this._pollenLoad = initialPollenLoad;
  }

  /** Current pollen load value. */
  public get pollenLoad(): number {
    return this._pollenLoad;
  }

  /** Set the pollen load (for external state sync). */
  public set pollenLoad(value: number) {
    this._pollenLoad = value;
  }

  /** All active particle states. */
  public get particles(): readonly ParticleState[] {
    return this._particles;
  }

  /**
   * Check for collisions between the Bee and collectible flowers.
   * On collision: increments pollen load, marks flower as collected,
   * and returns particle spawn requests.
   *
   * @param beeX - Bee's X position
   * @param beeY - Bee's Y position
   * @param beeRadius - Bee's circle collider radius
   * @param flowers - Array of collectible flowers to check against
   * @returns Collection result with collected flower IDs and particle requests
   */
  public checkCollections(
    beeX: number,
    beeY: number,
    beeRadius: number,
    flowers: FlowerEntry[],
  ): CollectionResult {
    const collected: Array<number | string> = [];
    const particles: ParticleSpawnRequest[] = [];

    for (const flower of flowers) {
      // Skip already-collected flowers
      if (this._collectedIds.has(flower.id)) continue;

      if (circlesOverlap(beeX, beeY, beeRadius, flower.x, flower.y, flower.radius)) {
        this._pollenLoad += 1;
        this._collectedIds.add(flower.id);
        collected.push(flower.id);
        particles.push({ x: flower.x, y: flower.y });

        // Spawn internal particle state
        this._particles.push({
          x: flower.x,
          y: flower.y,
          elapsed: 0,
          layerOpacities: [0, 0, 0, 0],
        });
      }
    }

    return {
      collected,
      pollenLoad: this._pollenLoad,
      particles,
    };
  }

  /**
   * Update all active particle effects, advancing their timers
   * and computing per-layer opacities. Particles that exceed the total
   * duration (1.5s) are marked for destruction.
   *
   * @param dt - Delta time in seconds since last frame
   * @returns Update result with active particles and indices of destroyed ones
   */
  public updateParticles(dt: number): ParticleUpdateResult {
    const destroyed: number[] = [];

    for (let i = this._particles.length - 1; i >= 0; i--) {
      const particle = this._particles[i]!;
      particle.elapsed += dt;

      if (particle.elapsed >= TOTAL_DURATION) {
        destroyed.push(i);
        this._particles.splice(i, 1);
      } else {
        // Update per-layer opacities
        for (let layer = 0; layer < LAYER_COUNT; layer++) {
          particle.layerOpacities[layer] = calculateLayerOpacity(layer, particle.elapsed);
        }
      }
    }

    return {
      active: [...this._particles],
      destroyed,
    };
  }

  /**
   * Manually spawn a particle effect at a position (for external triggering).
   */
  public spawnParticle(x: number, y: number): void {
    this._particles.push({
      x,
      y,
      elapsed: 0,
      layerOpacities: [0, 0, 0, 0],
    });
  }

  /**
   * Reset the system state (useful for scene transitions).
   */
  public clear(): void {
    this._pollenLoad = 0;
    this._particles = [];
    this._collectedIds.clear();
  }

  /**
   * Check if a flower has already been collected.
   */
  public isCollected(flowerId: number | string): boolean {
    return this._collectedIds.has(flowerId);
  }
}
