/// <reference lib="dom" />

/**
 * Dev console helpers for the Bee Game.
 *
 * Installs a `window.gameDebug` object exposing:
 *   - gameDebug.save.print()     → log the current save data
 *   - gameDebug.save.delete()    → wipe the save (next launch acts like new install)
 *   - gameDebug.timeScale.set(x) → scale game-loop dt by `x` (0 = freeze)
 *   - gameDebug.timeScale.get()  → read current scale
 *   - gameDebug.timeScale.freeze()/unfreeze() → set 0 / 1 shortcuts
 *
 * GameScene reads `TIME_SCALE.value` each frame in its Pixi ticker, so changing
 * it from the console immediately affects the simulation (without touching
 * scene transitions, menu animations, or rendering).
 *
 * @packageDocumentation
 */

import type { ISaveStorage, BeeGameSaveData } from '@astracore/save-storage-core';

/**
 * Mutable game-loop time-scale wrapper. Setting `value` to 0 freezes the
 * simulation while leaving rendering and the HUD running. Defaults to 1.
 */
export const TIME_SCALE: { value: number } = { value: 1 };

export interface GameDebugDeps {
  saveStorage: ISaveStorage;
  saveKey: string;
}

/**
 * Install the `window.gameDebug` console API. Idempotent in browsers; a no-op
 * in non-browser environments (e.g. vitest's default node runner).
 */
export function setupGameDebug(deps: GameDebugDeps): void {
  if (typeof window === 'undefined') return;

  const { saveStorage, saveKey } = deps;

  const save = {
    /** Load and pretty-print the save in storage. Returns the data or undefined. */
    async print(): Promise<BeeGameSaveData | undefined> {
      const data = await saveStorage.load<BeeGameSaveData>(saveKey);
      // eslint-disable-next-line no-console
      if (data === undefined) console.log('[gameDebug] No save found');
      // eslint-disable-next-line no-console
      else console.log('[gameDebug] save:', data);
      return data;
    },
    /** Delete the save. Returns true once the call completes. */
    async delete(): Promise<true> {
      await saveStorage.delete(saveKey);
      // eslint-disable-next-line no-console
      console.log('[gameDebug] save deleted');
      return true;
    },
  };

  const timeScale = {
    /** Read the current time scale. */
    get(): number {
      return TIME_SCALE.value;
    },
    /** Set the time scale. 0 = freeze, 1 = normal, > 1 = fast-forward. */
    set(value: number): number {
      if (!Number.isFinite(value) || value < 0) {
        // eslint-disable-next-line no-console
        console.warn('[gameDebug] timeScale.set: ignoring non-finite or negative value', value);
        return TIME_SCALE.value;
      }
      TIME_SCALE.value = value;
      // eslint-disable-next-line no-console
      console.log('[gameDebug] timeScale =', TIME_SCALE.value);
      return TIME_SCALE.value;
    },
    /** Convenience: freeze the simulation. */
    freeze(): number {
      return this.set(0);
    },
    /** Convenience: resume at normal speed. */
    unfreeze(): number {
      return this.set(1);
    },
  };

  const api = { save, timeScale };
  (window as unknown as Record<string, unknown>)['gameDebug'] = api;

  // eslint-disable-next-line no-console
  console.log(
    '%c[bee-game] Dev tools ready — gameDebug.save.print() / gameDebug.timeScale.freeze() / .set(0.25) / .unfreeze()',
    'color:#66ddff;font-weight:bold',
  );
}
