/**
 * Pure collision detection functions for the Bee Game.
 * Exported for property-based testing.
 * @packageDocumentation
 */

/** Circle-circle overlap test using squared distance vs squared radii sum. */
export function circlesOverlap(
  x1: number, y1: number, r1: number,
  x2: number, y2: number, r2: number,
): boolean {
  const dx = x2 - x1;
  const dy = y2 - y1;
  const distSq = dx * dx + dy * dy;
  const radiiSum = r1 + r2;
  return distSq <= radiiSum * radiiSum;
}

/** Circle vs axis-aligned centered rectangle overlap using closest-point method. */
export function circleRectOverlap(
  cx: number, cy: number, cr: number,
  rx: number, ry: number, rw: number, rh: number,
): boolean {
  const halfW = rw / 2;
  const halfH = rh / 2;
  const closestX = Math.max(rx - halfW, Math.min(cx, rx + halfW));
  const closestY = Math.max(ry - halfH, Math.min(cy, ry + halfH));
  const dx = cx - closestX;
  const dy = cy - closestY;
  return (dx * dx + dy * dy) <= cr * cr;
}
