/**
 * Magnet ability system for the Bee Game.
 *
 * When unlocked, the magnet attracts CollectibleFlower pollen entities
 * within a configurable radius toward the Bee's position. The attraction
 * radius and speed scale with upgrade level.
 *
 * Pure functions are exported separately for property-based testing.
 *
 * @packageDocumentation
 */

// ─── Pure Functions (exported for property testing) ───────────────────────────

/**
 * Calculate the magnet attraction radius for a given upgrade level.
 *
 * Base radius is 100px at level 1, increasing by 30px per additional level,
 * capped at a maximum of 250px.
 *
 * @param level - Magnet upgrade level (>= 1)
 * @returns Attraction radius in pixels
 */
export function calculateMagnetRadius(level: number): number {
  return Math.min(100 + (level - 1) * 30, 250);
}

/**
 * Calculate the magnet attraction speed for a given upgrade level.
 *
 * Base speed is 150 px/s at level 1, increasing by 50 px/s per additional level.
 *
 * @param level - Magnet upgrade level (>= 1)
 * @returns Attraction speed in pixels per second
 */
export function calculateMagnetSpeed(level: number): number {
  return 150 + (level - 1) * 50;
}

/**
 * Calculate the attraction velocity vector for pollen moving toward the Bee.
 *
 * Returns a velocity vector (dx, dy) pointing from the pollen position
 * toward the Bee position, scaled to the given attraction speed.
 * If the pollen is already at the Bee's position (distance = 0),
 * returns a zero vector.
 *
 * @param pollenX - Pollen entity X position
 * @param pollenY - Pollen entity Y position
 * @param beeX - Bee entity X position
 * @param beeY - Bee entity Y position
 * @param speed - Attraction speed in pixels per second
 * @returns Object with dx and dy components of the velocity vector
 */
export function calculateAttractionVector(
  pollenX: number,
  pollenY: number,
  beeX: number,
  beeY: number,
  speed: number,
): { dx: number; dy: number } {
  const diffX = beeX - pollenX;
  const diffY = beeY - pollenY;
  const distance = Math.sqrt(diffX * diffX + diffY * diffY);

  if (distance === 0) {
    return { dx: 0, dy: 0 };
  }

  // Normalize direction and scale by speed
  const nx = diffX / distance;
  const ny = diffY / distance;

  return { dx: nx * speed, dy: ny * speed };
}

// ─── Interfaces ───────────────────────────────────────────────────────────────

/** Represents a pollen entity that can be attracted by the magnet. */
export interface PollenEntry {
  id: number | string;
  x: number;
  y: number;
}

/** Velocity adjustment returned for each attracted pollen entity. */
export interface AttractionResult {
  id: number | string;
  dx: number;
  dy: number;
}

// ─── MagnetSystem ─────────────────────────────────────────────────────────────

/**
 * Manages the magnet ability — attracting pollen entities within range
 * toward the Bee's current position.
 *
 * The system is disabled while the Bee is in a dying or respawning state.
 * When active, it computes velocity adjustments for all pollen within the
 * magnet radius, which can then be applied to their positions by the caller.
 */
export class MagnetSystem {
  private _unlocked: boolean = false;
  private _level: number = 1;

  constructor(unlocked: boolean = false, level: number = 1) {
    this._unlocked = unlocked;
    this._level = level;
  }

  /** Whether the magnet ability is unlocked. */
  public get unlocked(): boolean {
    return this._unlocked;
  }

  /** Set the unlocked state. */
  public set unlocked(value: boolean) {
    this._unlocked = value;
  }

  /** Current magnet upgrade level. */
  public get level(): number {
    return this._level;
  }

  /** Set the magnet upgrade level. */
  public set level(value: number) {
    this._level = value;
  }

  /** Current calculated attraction radius based on level. */
  public get radius(): number {
    return calculateMagnetRadius(this._level);
  }

  /** Current calculated attraction speed based on level. */
  public get speed(): number {
    return calculateMagnetSpeed(this._level);
  }

  /**
   * Update the magnet system: compute attraction velocity adjustments
   * for pollen entities within range and move them toward the Bee.
   *
   * @param dt - Delta time in seconds since last frame
   * @param beeX - Bee's current X position
   * @param beeY - Bee's current Y position
   * @param flowers - Array of pollen entities to check against
   * @param isDisabled - Whether the magnet is disabled (dying/respawning state)
   * @returns Array of velocity adjustments for attracted pollen entities
   */
  public update(
    dt: number,
    beeX: number,
    beeY: number,
    flowers: PollenEntry[],
    isDisabled: boolean = false,
  ): AttractionResult[] {
    // Magnet does nothing if not unlocked or if disabled (dying/respawning)
    if (!this._unlocked || isDisabled) {
      return [];
    }

    const radius = this.radius;
    const speed = this.speed;
    const results: AttractionResult[] = [];

    for (const flower of flowers) {
      const diffX = beeX - flower.x;
      const diffY = beeY - flower.y;
      const distanceSq = diffX * diffX + diffY * diffY;

      // Check if within attraction radius (use squared distance for performance)
      if (distanceSq <= radius * radius && distanceSq > 0) {
        const attraction = calculateAttractionVector(flower.x, flower.y, beeX, beeY, speed);

        // Apply dt to get position delta for this frame
        results.push({
          id: flower.id,
          dx: attraction.dx * dt,
          dy: attraction.dy * dt,
        });
      }
    }

    return results;
  }

  /**
   * Reset the system state (useful for scene transitions).
   */
  public clear(): void {
    this._unlocked = false;
    this._level = 1;
  }
}
