/**
 * Hive interaction system for the Bee Game.
 *
 * Handles collision detection between the Bee and the Hive,
 * determines deposit eligibility, computes deposit results,
 * and provides tooltip state for the UI layer.
 *
 * The system is stateless — it computes the interaction result
 * based on inputs without maintaining internal state.
 *
 * @packageDocumentation
 */

import { circleRectOverlap } from '../collision.js';

// ─── Types ────────────────────────────────────────────────────────────────────

/** Tooltip keys for hive interaction states. */
export type HiveTooltipKey = 'press_e_to_leave' | 'need_more_pollen' | null;

/** Result of a successful pollen deposit. */
export interface DepositResult {
  /** Pollen load after deposit (always 0). */
  newPollenLoad: number;
  /** Excess pollen added to Pollen_Balance (pollenLoad - minPollen, min 0). */
  excessPollen: number;
}

/** Full interaction state returned by the system's update method. */
export interface HiveInteractionState {
  /** Whether the Bee's collider overlaps the Hive's collider. */
  isOverlapping: boolean;
  /** Whether the Bee can deposit pollen (has enough). */
  canDeposit: boolean;
  /** Which tooltip to show (null if not overlapping). */
  tooltipKey: HiveTooltipKey;
  /** Deposit result, present only when canDeposit is true. */
  depositResult?: DepositResult;
}

// ─── Pure Functions (exported for property testing) ───────────────────────────

/**
 * Calculate the result of a pollen deposit attempt.
 *
 * If pollenLoad >= minPollen, the deposit succeeds:
 * - newPollenLoad is set to 0 (all pollen deposited)
 * - excessPollen is max(0, pollenLoad - minPollen) added to balance
 *
 * If pollenLoad < minPollen, no deposit occurs.
 *
 * @param pollenLoad - Current pollen carried by the Bee
 * @param minPollen - Minimum pollen required for deposit
 * @returns Deposit calculation result
 */
export function calculateDeposit(
  pollenLoad: number,
  minPollen: number,
): { deposited: boolean; newPollenLoad: number; excessPollen: number } {
  if (pollenLoad >= minPollen) {
    return {
      deposited: true,
      newPollenLoad: 0,
      excessPollen: Math.max(0, pollenLoad - minPollen),
    };
  }

  return {
    deposited: false,
    newPollenLoad: pollenLoad,
    excessPollen: 0,
  };
}

// ─── HiveInteractionSystem ────────────────────────────────────────────────────

/**
 * Computes hive interaction state based on Bee and Hive positions,
 * collider radii, and current pollen load.
 *
 * The system is stateless: each call to `update` produces a fresh
 * interaction state based solely on the provided inputs.
 */
export class HiveInteractionSystem {
  /**
   * Compute the interaction state between the Bee and the Hive.
   *
   * @param beeX - Bee's X position
   * @param beeY - Bee's Y position
   * @param beeRadius - Bee's circle collider radius
   * @param hiveX - Hive's center X position
   * @param hiveY - Hive's center Y position (use sprite-center, not anchor base)
   * @param hiveWidth - Hive's collider width in pixels (full asset width)
   * @param hiveHeight - Hive's collider height in pixels (full asset height)
   * @param pollenLoad - Current pollen carried by the Bee
   * @param minPollen - Minimum pollen required for this day
   * @returns Interaction state including overlap, deposit eligibility, and tooltip
   */
  public update(
    beeX: number,
    beeY: number,
    beeRadius: number,
    hiveX: number,
    hiveY: number,
    hiveWidth: number,
    hiveHeight: number,
    pollenLoad: number,
    minPollen: number,
  ): HiveInteractionState {
    const isOverlapping = circleRectOverlap(beeX, beeY, beeRadius, hiveX, hiveY, hiveWidth, hiveHeight);

    if (!isOverlapping) {
      return {
        isOverlapping: false,
        canDeposit: false,
        tooltipKey: null,
      };
    }

    const deposit = calculateDeposit(pollenLoad, minPollen);

    if (deposit.deposited) {
      return {
        isOverlapping: true,
        canDeposit: true,
        tooltipKey: 'press_e_to_leave',
        depositResult: {
          newPollenLoad: deposit.newPollenLoad,
          excessPollen: deposit.excessPollen,
        },
      };
    }

    return {
      isOverlapping: true,
      canDeposit: false,
      tooltipKey: 'need_more_pollen',
    };
  }
}
