/**
 * Bird_03 (Diver) enemy system.
 *
 * Behavior:
 * - Spawns from the right edge at high altitude (top 20% of vertical space)
 * - Flies left at constant horizontal speed
 * - Dives when horizontal position is within tolerance of the Bee's x
 * - During dive: moves toward captured target Y, continues left, does NOT update target
 * - After reaching target Y: ascends back to original altitude, resumes horizontal flight
 * - Destroyed when past left boundary
 * - Collision with Bee triggers death sequence
 *
 * @packageDocumentation
 */

import type { World, EntityId, Query } from '@astracore/ecs';
import {
  DiverBirdTag,
  Position,
  Velocity,
  CircleCollider,
  DiveState,
} from '../components.js';
import { BIRD_03_CONFIG } from '../enemy-config.js';

// ─── Constants ────────────────────────────────────────────────────────────────

/** Collider radius for Bird_03 entities. */
const COLLIDER_RADIUS = 14;

/** Left boundary offset — entities past this distance left of 0 are destroyed. */
const LEFT_BOUNDARY = -50;

// ─── Bird03System ─────────────────────────────────────────────────────────────

/**
 * Manages Bird_03 (Diver) entities: spawning, movement, dive logic, and cleanup.
 *
 * Usage:
 * ```ts
 * const bird03System = new Bird03System(world);
 * // In spawn logic:
 * bird03System.spawn(worldRightEdge, viewportHeight);
 * // In update loop:
 * bird03System.update(dt, beeX, beeY);
 * ```
 */
export class Bird03System {
  private readonly _world: World;
  private readonly _query: Query<
    [typeof DiverBirdTag, typeof Position, typeof Velocity, typeof CircleCollider, typeof DiveState]
  >;

  constructor(world: World) {
    this._world = world;
    this._query = world.query({
      with: [DiverBirdTag, Position, Velocity, CircleCollider, DiveState],
    });
  }

  /**
   * Spawn a new Bird_03 entity at the right edge of the world at high altitude.
   *
   * @param worldRightEdge - The x-coordinate of the right edge (spawn position).
   * @param viewportHeight - The height of the playable vertical space.
   * @returns The entity ID of the spawned bird.
   */
  public spawn(worldRightEdge: number, viewportHeight: number): EntityId {
    const world = this._world;

    const entity = world.createEntity();

    // Spawn at high altitude: random y within top 20% of viewport height
    const maxAltitude = viewportHeight * BIRD_03_CONFIG.altitudeFraction;
    const spawnY = Math.random() * maxAltitude;

    world.addComponent(entity, new DiverBirdTag());
    world.addComponent(entity, new Position(worldRightEdge, spawnY));
    world.addComponent(entity, new Velocity(-BIRD_03_CONFIG.speed, 0));
    world.addComponent(entity, new CircleCollider(COLLIDER_RADIUS));
    world.addComponent(
      entity,
      new DiveState(
        false,             // isDiving
        0,                 // targetY (set when dive triggers)
        spawnY,            // originalY
        BIRD_03_CONFIG.diveSpeed,
        BIRD_03_CONFIG.speed,
        BIRD_03_CONFIG.tolerance,
      ),
    );

    return entity;
  }

  /**
   * Update all Bird_03 entities: horizontal movement, dive trigger, dive/ascend logic, cleanup.
   *
   * @param dt - Delta time in seconds.
   * @param beeX - The Bee's current x position.
   * @param beeY - The Bee's current y position.
   */
  public update(dt: number, beeX: number, beeY: number): void {
    const world = this._world;
    const toDestroy: EntityId[] = [];

    this._query.forEach((entity, _tag, pos, vel, _collider, diveState) => {
      // ── Horizontal movement (always active) ──────────────────────────
      pos.x += vel.dx * dt;

      // ── Dive state machine ───────────────────────────────────────────
      if (!diveState.isDiving) {
        // Check if bird should start diving
        if (Math.abs(pos.x - beeX) < diveState.triggerTolerance) {
          // Start dive: capture bee's current Y as target
          diveState.isDiving = true;
          diveState.targetY = beeY;
          vel.dy = diveState.diveSpeed; // positive = downward
        }
      } else {
        // Currently in dive or ascend phase
        if (pos.y < diveState.targetY) {
          // Diving down toward target Y
          vel.dy = diveState.diveSpeed;
          pos.y += vel.dy * dt;

          // Check if we've reached or passed target Y
          if (pos.y >= diveState.targetY) {
            pos.y = diveState.targetY;
            // Switch to ascending phase: target becomes the original altitude
            diveState.targetY = diveState.originalY;
            vel.dy = -diveState.diveSpeed; // negative = upward
          }
        } else if (pos.y > diveState.originalY) {
          // Ascending back to original altitude
          vel.dy = -diveState.diveSpeed;
          pos.y += vel.dy * dt;

          // Check if we've reached or passed original altitude
          if (pos.y <= diveState.originalY) {
            pos.y = diveState.originalY;
            vel.dy = 0;
            diveState.isDiving = false;
          }
        } else {
          // Edge case: already at or above original after dive
          // This handles the case where targetY was above originalY
          vel.dy = -diveState.diveSpeed;
          pos.y += vel.dy * dt;

          if (pos.y <= diveState.originalY) {
            pos.y = diveState.originalY;
            vel.dy = 0;
            diveState.isDiving = false;
          }
        }
      }

      // ── Destroy when past left boundary ──────────────────────────────
      if (pos.x < LEFT_BOUNDARY) {
        toDestroy.push(entity);
      }
    });

    // Destroy entities outside the loop to avoid mutation during iteration
    for (const entity of toDestroy) {
      world.destroyEntity(entity);
    }
  }

  /** Read-only access to the query for external collision checks. */
  public get query(): Query<
    [typeof DiverBirdTag, typeof Position, typeof Velocity, typeof CircleCollider, typeof DiveState]
  > {
    return this._query;
  }
}
