/**
 * ECS components for the Bee Game Demo.
 * Plain data classes with no logic, following the AstraCore component pattern.
 * @packageDocumentation
 */

/** Marker tag for the player bee entity. */
export class BeeTag {}

/** Marker tag for pollen (flower) entities. */
export class PollenTag {}

/** Marker tag for the hive entity. */
export class HiveTag {}

/** Marker tag for ground bird entities. */
export class GroundBirdTag {}

/** Marker tag for wave bird entities. */
export class WaveBirdTag {}

/** 2D position in world space (pixels). */
export class Position {
  constructor(public x: number = 0, public y: number = 0) {}
}

/** 2D velocity in pixels per second. */
export class Velocity {
  constructor(public dx: number = 0, public dy: number = 0) {}
}

/** Circle collider with radius in pixels. */
export class CircleCollider {
  constructor(public radius: number = 10) {}
}

/** Rectangle collider with width and height in pixels (centered on entity position). */
export class RectCollider {
  constructor(public width: number = 40, public height: number = 40) {}
}

/** Pollen load carried by the bee. Affects movement speed. */
export class PollenLoad {
  constructor(public current: number = 0) {}
}

/** Wave bird oscillation state for sinusoidal vertical movement. */
export class WaveMotion {
  constructor(
    public baseY: number = 0,
    public amplitude: number = 100,
    public frequency: number = 2,
    public phase: number = 0,
  ) {}
}

/**
 * Bird-to-bird evasion ability and state.
 *
 * Birds with `canEvade` will dodge (change flight height) when they collide
 * with another bird. While `cooldown` is positive the bird is actively
 * evading — it moves vertically faster and will not re-trigger another evade.
 */
export class Evasion {
  constructor(
    /** Whether this bird is able to evade collisions. */
    public canEvade: boolean = false,
    /** Seconds remaining of the active evade maneuver (also a re-trigger guard). */
    public cooldown: number = 0,
  ) {}
}

// ─── Enemy Components ─────────────────────────────────────────────────

/** Marker tag for Bird_03 diver enemies. */
export class DiverBirdTag {}

/** Marker tag for Bird_04 state machine enemies. */
export class StateBirdTag {}

/** Marker tag for Bird_05 pursuer (chaser) enemies. */
export class PursuerBirdTag {}

/**
 * Bird_05 pursuer state. Drives a 3-state machine:
 *   roam → dive (commit to a locked overshoot trajectory through the bee) →
 *   cooldown (diagonal escape mirroring the dive direction, 2s) → roam.
 *
 * Flock coordination: each bird is assigned a `flockRole` at spawn so the
 * flock approaches the bee from different angles ('top' hovers above,
 * 'bottom' below, 'chaser' direct). Combined with an attack-stagger token
 * managed by Bird05System, this prevents all birds from diving at once.
 */
export class PursuerState {
  constructor(
    /** Current behavior state. */
    public phase: 'roam' | 'dive' | 'cooldown' = 'roam',
    /** Seconds spent in the current phase. */
    public phaseTimer: number = 0,
    /** Locked dive target — set when entering 'dive' (bird overshoots bee by +50%). */
    public diveTargetX: number = 0,
    public diveTargetY: number = 0,
    /** Role in the flock — shapes the roam target relative to the bee. */
    public flockRole: 'top' | 'bottom' | 'chaser' = 'chaser',
    /** Vertical roaming band (used for spawn placement). */
    public minY: number = 0,
    public maxY: number = 0,
    /** True once the current dive has already inflicted a lethal contact. */
    public diveHitMade: boolean = false,
  ) {}
}

/** Marker tag for Flytrap enemies. */
export class FlytrapTag {}

/** Bird_03 dive state tracking. */
export class DiveState {
  constructor(
    public isDiving: boolean = false,
    public targetY: number = 0,
    public originalY: number = 0,
    public diveSpeed: number = 300,
    public horizontalSpeed: number = 120,
    public triggerTolerance: number = 30,
  ) {}
}

/** Bird_04 FSM state reference. */
export class Bird04State {
  constructor(
    public currentState: 'fly' | 'idle' | 'aware' | 'chase' = 'fly',
    public stateTimer: number = 0,
    public flyDistance: number = 0,
    public distanceTraveled: number = 0,
    public awarenessRadius: number = 200,
    public chaseRadius: number = 100,
    public chaseSpeed: number = 180,
    public chaseDuration: number = 5,
  ) {}
}

/** Flytrap catch state. */
export class FlytrapState {
  constructor(
    public isActive: boolean = true,
    public isCatching: boolean = false,
    public catchTimer: number = 0,
    public cooldownTimer: number = 0,
    public proximityRadius: number = 40,
    public catchDuration: number = 3,
    public cooldownDuration: number = 3,
  ) {}
}

