/**
 * Upgrade system configuration for the Bee Game.
 * All upgrade costs, max levels, unlock days, and effect values are defined here.
 * Modify this file to tune progression without code changes.
 * @packageDocumentation
 */

// ─── Types ────────────────────────────────────────────────────────────────────

export type UpgradeId = 'speed' | 'capacity' | 'dayTime' | 'lives' | 'dash' | 'magnet';

export interface UpgradeConfig {
  id: UpgradeId;
  /** Localization key for the upgrade name. */
  name: string;
  /** Maximum purchasable level. */
  maxLevel: number;
  /** Cost to go from level i to level i+1 (length === maxLevel). */
  costs: number[];
  /** Day when this upgrade becomes visible in the Hive Hub. */
  unlockDay: number;
  /** Effect value at each level (index 0 = level 1 effect). */
  effects: number[];
}

