/// <reference lib="dom" />

import type { World } from '@astracore/ecs';
import type { AssetManager } from '@astracore/assets';
import type { Scene } from '@astracore/scene';

/**
 * Options passed to MenuScene.
 *
 * - `hasSave` is read at construction time and decides which buttons appear.
 *   When true, the menu shows "Resume Game" + "Start New Game"; when false
 *   it shows a single "Start Game" button.
 * - "Resume" calls `onResume` directly (no tutorial — the player has played).
 * - "Start New Game" (and the single "Start Game" when there is no save)
 *   shows the tutorial overlay first and then calls `onStartNew`.
 */
export interface MenuSceneOptions {
  /** Whether a saved game is present (drives which buttons render). */
  hasSave: boolean;
  /** Callback for "Resume Game" — invoked immediately, no tutorial. */
  onResume: () => void;
  /** Callback for "Start New Game" (or the single "Start Game" fallback). */
  onStartNew: () => void;
}

/**
 * Main menu scene — HTML overlay with game title, save-aware buttons, and a
 * tutorial screen shown before transitioning into a new game.
 */
export class MenuScene implements Scene {
  public readonly name = 'menu';

  private _overlay: HTMLElement | null = null;
  private _hasSave: boolean;
  private readonly _onResume: () => void;
  private readonly _onStartNew: () => void;

  public constructor(options: MenuSceneOptions) {
    this._hasSave = options.hasSave;
    this._onResume = options.onResume;
    this._onStartNew = options.onStartNew;
  }

  /**
   * Update the save-aware menu after the menu has been built (e.g. after the
   * player just cleared their save via gameDebug). Re-renders the menu HTML
   * if the scene is currently displayed.
   */
  public setHasSave(hasSave: boolean): void {
    if (this._hasSave === hasSave) return;
    this._hasSave = hasSave;
    if (this._overlay !== null) {
      this._overlay.innerHTML = this._buildMenuHTML();
      this._wireMenuButtons();
    }
  }

  public onLoad(_world: World, _assets: AssetManager | undefined): void {
    // No ECS systems needed for the menu.
  }

  public onEnter(_world: World): void {
    const overlay = document.getElementById('menu-overlay');
    if (overlay === null) return;

    this._overlay = overlay;
    overlay.style.display = 'flex';
    overlay.innerHTML = this._buildMenuHTML();
    this._wireMenuButtons();
  }

  public onExit(_world: World): void {
    if (this._overlay !== null) {
      this._overlay.innerHTML = '';
      this._overlay.style.display = 'none';
      this._overlay = null;
    }
  }

  public onUnload(_world: World): void {
    // Nothing to clean up.
  }

  private _wireMenuButtons(): void {
    if (this._overlay === null) return;

    const resumeBtn = this._overlay.querySelector<HTMLButtonElement>('#resume-game-btn');
    if (resumeBtn) {
      resumeBtn.addEventListener('click', () => {
        this._onResume();
      });
    }

    const startBtn = this._overlay.querySelector<HTMLButtonElement>('#start-game-btn');
    if (startBtn) {
      startBtn.addEventListener('click', () => {
        this._showTutorial();
      });
    }
  }

  private _showTutorial(): void {
    if (this._overlay === null) return;

    this._overlay.innerHTML = this._buildTutorialHTML();

    const playBtn = this._overlay.querySelector<HTMLButtonElement>('#tutorial-play-btn');
    if (playBtn) {
      playBtn.addEventListener('click', () => {
        this._onStartNew();
      });
    }
  }

  private _buildTutorialHTML(): string {
    return `
      <div style="
        background: rgba(20, 10, 0, 0.92);
        border: 1px solid rgba(255, 200, 50, 0.4);
        border-radius: clamp(6px, 2vw, 12px);
        padding: clamp(16px, 4vw, 36px) clamp(12px, 4vw, 40px);
        max-width: min(520px, 96vw);
        width: 96vw;
        max-height: 90vh;
        overflow-y: auto;
        text-align: center;
        font-family: 'Courier New', Courier, monospace;
        color: #f0e0a0;
        box-shadow: 0 0 40px rgba(255, 180, 0, 0.2);
        box-sizing: border-box;
      ">
        <h2 style="
          margin: 0 0 clamp(12px, 3vw, 24px) 0;
          font-size: clamp(14px, 4vw, 22px);
          font-weight: 700;
          color: #ffd040;
          letter-spacing: 1px;
          text-transform: uppercase;
        ">How to Play</h2>

        <div style="
          display: flex;
          justify-content: center;
          gap: clamp(8px, 2vw, 20px);
          flex-wrap: wrap;
          margin-bottom: clamp(16px, 4vw, 28px);
        ">
          <div style="display:flex;flex-direction:column;align-items:center;gap:4px;width:clamp(60px,14vw,90px);">
            <img src="./assets/bee.png" style="width:clamp(32px,8vw,48px);height:clamp(32px,8vw,48px);image-rendering:pixelated;" />
            <span style="font-size:clamp(9px,2.2vw,11px);color:#b0a060;">Control Bee</span>
          </div>
          <div style="display:flex;flex-direction:column;align-items:center;gap:4px;width:clamp(60px,14vw,90px);">
            <img src="./assets/flowers/flower_blue.png" style="width:clamp(32px,8vw,48px);height:clamp(32px,8vw,48px);image-rendering:pixelated;" />
            <span style="font-size:clamp(9px,2.2vw,11px);color:#b0a060;">Collect Pollen</span>
          </div>
          <div style="display:flex;flex-direction:column;align-items:center;gap:4px;width:clamp(60px,14vw,90px);">
            <div style="width:clamp(32px,8vw,48px);height:clamp(32px,8vw,48px);background:#dd8800;border-radius:4px;display:flex;align-items:center;justify-content:center;font-size:clamp(14px,4vw,20px);">🍯</div>
            <span style="font-size:clamp(9px,2.2vw,11px);color:#b0a060;">Place Pollen in Hive</span>
          </div>
          <div style="display:flex;flex-direction:column;align-items:center;gap:4px;width:clamp(60px,14vw,90px);">
            <img src="./assets/bird01.png" style="width:clamp(32px,8vw,48px);height:clamp(32px,8vw,48px);image-rendering:pixelated;" />
            <span style="font-size:clamp(9px,2.2vw,11px);color:#b0a060;">Avoid Birds</span>
          </div>
          <div style="display:flex;flex-direction:column;align-items:center;gap:4px;width:clamp(60px,14vw,90px);">
            <div style="width:clamp(32px,8vw,48px);height:clamp(32px,8vw,48px);display:flex;align-items:center;justify-content:center;font-size:clamp(18px,5vw,28px);">⚖️</div>
            <span style="font-size:clamp(9px,2.2vw,11px);color:#b0a060;">Pollen adds weight — harder to fly</span>
          </div>
        </div>

        <button id="tutorial-play-btn" style="
          background: #a06800;
          color: #fff8e0;
          border: 1px solid rgba(255, 200, 50, 0.5);
          border-radius: 6px;
          padding: clamp(10px,2.5vw,14px) clamp(24px,6vw,40px);
          font-family: 'Courier New', Courier, monospace;
          font-size: clamp(13px,3.5vw,16px);
          font-weight: 700;
          letter-spacing: 1px;
          cursor: pointer;
          transition: background 0.15s, border-color 0.15s;
          text-transform: uppercase;
        "
        onmouseover="this.style.background='#c08000'; this.style.borderColor='rgba(255,220,80,0.7)';"
        onmouseout="this.style.background='#a06800'; this.style.borderColor='rgba(255,200,50,0.5)';"
        >Got it!</button>
      </div>
    `;
  }

  private _buildMenuHTML(): string {
    const startLabel = this._hasSave ? 'Start New Game' : 'Start Game';
    const resumeButton = this._hasSave
      ? `
        <button id="resume-game-btn" style="
          background: #5a8a3a;
          color: #fff8e0;
          border: 1px solid rgba(180, 240, 120, 0.6);
          border-radius: 6px;
          padding: clamp(10px,2.5vw,14px) clamp(24px,6vw,40px);
          font-family: 'Courier New', Courier, monospace;
          font-size: clamp(13px,3.5vw,16px);
          font-weight: 700;
          letter-spacing: 1px;
          cursor: pointer;
          transition: background 0.15s, border-color 0.15s;
          text-transform: uppercase;
          margin-bottom: clamp(10px, 2.5vw, 14px);
          width: 100%;
        "
        onmouseover="this.style.background='#76aa50'; this.style.borderColor='rgba(220,255,160,0.85)';"
        onmouseout="this.style.background='#5a8a3a'; this.style.borderColor='rgba(180,240,120,0.6)';"
        >Resume Game</button>
      `
      : '';

    return `
      <div style="
        background: rgba(20, 10, 0, 0.92);
        border: 1px solid rgba(255, 200, 50, 0.4);
        border-radius: clamp(6px, 2vw, 12px);
        padding: clamp(24px, 6vw, 48px) clamp(20px, 6vw, 56px);
        max-width: min(420px, 96vw);
        width: 96vw;
        text-align: center;
        font-family: 'Courier New', Courier, monospace;
        color: #f0e0a0;
        box-shadow: 0 0 40px rgba(255, 180, 0, 0.2);
        box-sizing: border-box;
      ">
        <h1 style="
          margin: 0 0 clamp(8px, 2vw, 12px) 0;
          font-size: clamp(20px, 6vw, 32px);
          font-weight: 700;
          color: #ffd040;
          letter-spacing: 2px;
          text-transform: uppercase;
        ">Bee Game</h1>

        <p style="
          margin: 0 0 clamp(20px, 5vw, 36px) 0;
          font-size: clamp(11px, 2.8vw, 13px);
          color: #b0a060;
          line-height: 1.6;
        ">
          Collect pollen from flowers and return it to the hive.<br/>
          Avoid the birds! WASD or arrows to move.
        </p>

        ${resumeButton}

        <button id="start-game-btn" style="
          background: #a06800;
          color: #fff8e0;
          border: 1px solid rgba(255, 200, 50, 0.5);
          border-radius: 6px;
          padding: clamp(10px,2.5vw,14px) clamp(24px,6vw,40px);
          font-family: 'Courier New', Courier, monospace;
          font-size: clamp(13px,3.5vw,16px);
          font-weight: 700;
          letter-spacing: 1px;
          cursor: pointer;
          transition: background 0.15s, border-color 0.15s;
          text-transform: uppercase;
          width: 100%;
        "
        onmouseover="this.style.background='#c08000'; this.style.borderColor='rgba(255,220,80,0.7)';"
        onmouseout="this.style.background='#a06800'; this.style.borderColor='rgba(255,200,50,0.5)';"
        >${startLabel}</button>
      </div>
    `;
  }
}
