/**
 * Death and respawn system for the Bee Game.
 *
 * Manages the bee's death sequence, respawn, and invincibility.
 * State machine: alive → dying → paused → respawning → alive
 *
 * Death sequence:
 * 1. Spin-and-fall animation (0.5s)
 * 2. Pause (0.3s)
 * 3. Respawn at death x-position with invincibility
 *
 * During invincibility the bee's sprite flashes (oscillating alpha)
 * and enemy collisions are ignored.
 *
 * @packageDocumentation
 */

// ─── Types ────────────────────────────────────────────────────────────────────

/** Possible states in the death/respawn state machine. */
export type DeathState = 'alive' | 'dying' | 'paused' | 'respawning';

/** Configuration for the death system timings. */
export interface DeathSystemConfig {
  /** Duration of the spin-and-fall animation in seconds. */
  dyingDuration: number;
  /** Duration of the pause after dying before respawn in seconds. */
  pauseDuration: number;
  /** Duration of invincibility after respawn in seconds. */
  invincibilityDuration: number;
  /** Frequency of alpha oscillation during invincibility (Hz). */
  flashFrequency: number;
}

/** Default configuration values. */
export const DEFAULT_DEATH_CONFIG: DeathSystemConfig = {
  dyingDuration: 0.5,
  pauseDuration: 0.3,
  invincibilityDuration: 2.0,
  flashFrequency: 8,
};

// ─── Pure Helper Functions ────────────────────────────────────────────────────

/**
 * Calculate starting lives based on the Lives upgrade level.
 *
 * Base is 1 life per level — the Lives upgrade adds extra lives on top.
 *
 * @param upgradeLevel - The current level of the Lives upgrade (0 to 3)
 * @returns The number of starting lives (1 + upgradeLevel)
 */
export function calculateStartingLives(upgradeLevel: number): number {
  return 1 + upgradeLevel;
}

/**
 * Calculate the sprite alpha for invincibility flashing.
 *
 * Uses a sinusoidal oscillation to produce a flashing effect.
 *
 * @param elapsed - Time elapsed since invincibility started (seconds)
 * @param frequency - Flash frequency in Hz
 * @returns Alpha value between 0.2 and 1.0
 */
export function calculateFlashAlpha(elapsed: number, frequency: number): number {
  // Oscillate between 0.2 and 1.0 using absolute sine
  const sine = Math.sin(2 * Math.PI * frequency * elapsed);
  return 0.2 + 0.8 * Math.abs(sine);
}

// ─── DeathSystem Class ────────────────────────────────────────────────────────

/**
 * Manages the bee's death/respawn state machine.
 *
 * Usage:
 * - Call `triggerDeath(deathX, deathY)` when a collision is detected
 * - Call `update(dt)` every frame to advance the state machine
 * - Check `state` and `isInvincible` to determine bee behavior
 * - Check `spriteAlpha` for rendering the flash effect
 */
export class DeathSystem {
  private _state: DeathState = 'alive';
  private _stateTimer: number = 0;
  private _deathX: number = 0;
  private _deathY: number = 0;
  private _invincibilityTimer: number = 0;
  private _lives: number = 3;
  private _pollenLoad: number = 0;
  private _config: DeathSystemConfig;
  private _livesReachedZero: boolean = false;

  constructor(config: Partial<DeathSystemConfig> = {}) {
    this._config = { ...DEFAULT_DEATH_CONFIG, ...config };
  }

  // ─── Getters ──────────────────────────────────────────────────────────

  /** Current state of the death/respawn state machine. */
  public get state(): DeathState {
    return this._state;
  }

  /** Whether the bee is currently invincible (post-respawn). */
  public get isInvincible(): boolean {
    return this._invincibilityTimer > 0;
  }

  /** Remaining invincibility time in seconds. */
  public get invincibilityTimer(): number {
    return this._invincibilityTimer;
  }

  /** Current number of lives remaining. */
  public get lives(): number {
    return this._lives;
  }

  /** Current pollen load (retained across deaths). */
  public get pollenLoad(): number {
    return this._pollenLoad;
  }

  /** Whether lives have reached zero (triggers end of day). */
  public get livesReachedZero(): boolean {
    return this._livesReachedZero;
  }

  /** The x-position where the bee died (used for respawn). */
  public get deathX(): number {
    return this._deathX;
  }

  /** The y-position where the bee died. */
  public get deathY(): number {
    return this._deathY;
  }

  /**
   * Get the current sprite alpha value for rendering.
   * Returns 1.0 when not invincible, oscillating value during invincibility.
   */
  public get spriteAlpha(): number {
    if (!this.isInvincible) {
      return 1.0;
    }
    const elapsed = this._config.invincibilityDuration - this._invincibilityTimer;
    return calculateFlashAlpha(elapsed, this._config.flashFrequency);
  }

  /** Whether the bee is immobile (dying or paused states). */
  public get isImmobile(): boolean {
    return this._state === 'dying' || this._state === 'paused';
  }

  /** Whether enemy collisions should be checked. */
  public get canBeHit(): boolean {
    return this._state === 'alive' && !this.isInvincible;
  }

  /** The current configuration. */
  public get config(): Readonly<DeathSystemConfig> {
    return this._config;
  }

  // ─── Setters ──────────────────────────────────────────────────────────

  /** Set the current number of lives. */
  public set lives(value: number) {
    this._lives = value;
  }

  /** Set the current pollen load. */
  public set pollenLoad(value: number) {
    this._pollenLoad = value;
  }

  // ─── Actions ──────────────────────────────────────────────────────────

  /**
   * Trigger the death sequence.
   *
   * Starts the spin-and-fall animation, records death position,
   * decrements lives, and retains pollen load.
   *
   * @param deathX - X position where the bee died
   * @param deathY - Y position where the bee died
   * @returns true if the death was triggered, false if the bee cannot die (already dying or invincible)
   */
  public triggerDeath(deathX: number, deathY: number): boolean {
    // Can only die when alive and not invincible
    if (!this.canBeHit) {
      return false;
    }

    this._state = 'dying';
    this._stateTimer = this._config.dyingDuration;
    this._deathX = deathX;
    this._deathY = deathY;

    // Decrement lives, retain pollen load
    this._lives = Math.max(0, this._lives - 1);

    // Check if lives reached zero
    if (this._lives === 0) {
      this._livesReachedZero = true;
    }

    return true;
  }

  /**
   * Update the death/respawn state machine.
   *
   * Advances timers and transitions between states:
   * - dying → paused (after dyingDuration)
   * - paused → respawning/alive (after pauseDuration)
   * - During alive: counts down invincibility timer
   *
   * @param dt - Delta time in seconds since last frame
   */
  public update(dt: number): void {
    switch (this._state) {
      case 'dying':
        this._stateTimer -= dt;
        if (this._stateTimer <= 0) {
          // Transition to paused
          this._state = 'paused';
          this._stateTimer = this._config.pauseDuration;
        }
        break;

      case 'paused':
        this._stateTimer -= dt;
        if (this._stateTimer <= 0) {
          if (this._livesReachedZero) {
            // Stay in paused state — the game should transition to Hive_Hub
            // The external system reads livesReachedZero and handles the transition
            this._state = 'alive';
          } else {
            // Respawn
            this._state = 'alive';
            this._invincibilityTimer = this._config.invincibilityDuration;
          }
        }
        break;

      case 'alive':
        // Count down invincibility
        if (this._invincibilityTimer > 0) {
          this._invincibilityTimer = Math.max(0, this._invincibilityTimer - dt);
        }
        break;

      case 'respawning':
        // Alias for transition — handled in paused → alive above
        break;
    }
  }

  /**
   * Reset the death system to initial state.
   *
   * @param startingLives - Number of lives to start with
   */
  public reset(startingLives: number): void {
    this._state = 'alive';
    this._stateTimer = 0;
    this._deathX = 0;
    this._deathY = 0;
    this._invincibilityTimer = 0;
    this._lives = startingLives;
    this._pollenLoad = 0;
    this._livesReachedZero = false;
  }
}
