/// <reference lib="dom" />

/**
 * Device detection utilities for the Bee Game.
 *
 * Uses @astracore/device for device service context and browser APIs to
 * determine touch input capabilities. The primary use case is deciding
 * whether to show the virtual joystick overlay for touch-based environments.
 *
 * @packageDocumentation
 */

import type { DeviceService } from '@astracore/device';

/** Result of touch environment detection. */
export interface TouchDetectionResult {
  /** Whether the device supports touch input. */
  hasTouch: boolean;
  /** Whether detection failed or was inconclusive. */
  detectionFailed: boolean;
}

/**
 * Detect whether the current environment supports touch input.
 *
 * Uses the @astracore/device DeviceService for context and falls back to
 * browser APIs (`ontouchstart` in window, `navigator.maxTouchPoints`) for
 * touch capability detection.
 *
 * @param _deviceService - Optional DeviceService instance (reserved for future
 *   touch-specific APIs that may be added to @astracore/device)
 * @returns A TouchDetectionResult indicating touch support and detection status
 */
export function detectTouchEnvironment(_deviceService?: DeviceService): TouchDetectionResult {
  try {
    // Check for touch event support via the standard 'ontouchstart' property
    if ('ontouchstart' in window) {
      return { hasTouch: true, detectionFailed: false };
    }

    // Additional check: navigator.maxTouchPoints > 0 indicates touch capability
    if (navigator.maxTouchPoints > 0) {
      return { hasTouch: true, detectionFailed: false };
    }

    // No touch support detected — desktop/keyboard environment
    return { hasTouch: false, detectionFailed: false };
  } catch {
    // If detection fails for any reason, mark as failed
    // (caller should default to showing joystick per Requirement 6.4)
    return { hasTouch: false, detectionFailed: true };
  }
}

/**
 * Determine whether the virtual joystick should be displayed based on
 * the touch detection result.
 *
 * Returns `true` (show joystick) if:
 * - Touch is supported (mobile/tablet device)
 * - Detection failed or was inconclusive (safe default per Requirement 6.4)
 *
 * Returns `false` (hide joystick) only when we can confidently
 * determine the environment does NOT support touch.
 *
 * @param detection - Result from detectTouchEnvironment()
 * @returns Whether the virtual joystick should be shown
 */
export function shouldShowJoystick(detection: TouchDetectionResult): boolean {
  // If detection failed, default to showing joystick (safe fallback)
  if (detection.detectionFailed) {
    return true;
  }

  // Show joystick if touch is supported
  return detection.hasTouch;
}
