/**
 * Pure weight mechanic functions for the Bee Game.
 * Exported for property-based testing.
 * @packageDocumentation
 */

/**
 * Compute the bee's current maximum speed based on pollen load.
 * Formula: baseMaxSpeed - (pollenLoad / maxCapacity) * (baseMaxSpeed - minSpeed)
 * Clamps pollenLoad to [0, maxCapacity] for safety.
 */
export function computeMaxSpeed(
  pollenLoad: number,
  baseMaxSpeed: number,
  minSpeed: number,
  maxCapacity: number,
): number {
  if (maxCapacity <= 0) return baseMaxSpeed;
  const clamped = Math.max(0, Math.min(pollenLoad, maxCapacity));
  return baseMaxSpeed - (clamped / maxCapacity) * (baseMaxSpeed - minSpeed);
}

/**
 * Compute the effective per-frame friction based on pollen load.
 *
 * Heavier loads glide more (harder to stop) — the friction value moves
 * toward 1 (less deceleration) as the load increases. This models kinetic
 * momentum: the more pollen carried, the more the bee keeps moving.
 *
 * The Carrying Weight upgrade COUNTERACTS this — a higher capacity means a
 * given pollen amount is a smaller fraction of the total, so glide is reduced
 * and control improves.
 *
 * @param pollenLoad - Current pollen carried
 * @param maxCapacity - Max capacity (increases with Carrying Weight upgrade)
 * @param baseFriction - Friction with no load (e.g. 0.92)
 * @param kineticGlide - Extra glide approaching 1 at full load (e.g. 0.06)
 * @returns Effective friction multiplier, clamped to (0, 0.995]
 */
export function computeKineticFriction(
  pollenLoad: number,
  maxCapacity: number,
  baseFriction: number,
  kineticGlide: number,
): number {
  if (maxCapacity <= 0) return baseFriction;
  const loadFactor = Math.max(0, Math.min(pollenLoad / maxCapacity, 1));
  const friction = baseFriction + loadFactor * kineticGlide;
  return Math.min(friction, 0.995);
}

/**
 * Compute the effective acceleration based on pollen load (steering resistance).
 *
 * Heavier loads RESIST steering input — the bee's acceleration is reduced so
 * the player must fight built-up momentum to change direction or stop. This is
 * tempered by the Carrying Weight upgrade (larger capacity → smaller load
 * fraction → less steering penalty, easier control).
 *
 * @param baseAccel - Base acceleration in px/s²
 * @param pollenLoad - Current pollen carried
 * @param maxCapacity - Max capacity (increases with Carrying Weight upgrade)
 * @param steerPenalty - Max fractional accel reduction at full load (e.g. 0.45)
 * @returns Effective acceleration in px/s² (always > 0)
 */
export function computeKineticAccel(
  baseAccel: number,
  pollenLoad: number,
  maxCapacity: number,
  steerPenalty: number,
): number {
  if (maxCapacity <= 0) return baseAccel;
  const loadFactor = Math.max(0, Math.min(pollenLoad / maxCapacity, 1));
  const factor = 1 - loadFactor * Math.max(0, Math.min(steerPenalty, 0.95));
  return baseAccel * factor;
}

// ─── Tiered weight-penalty model ───────────────────────────────────────────────
//
// The bee must ALWAYS stay in control — collecting a lot of pollen makes it
// heavier and harder to fly, but it can never become unflyable. Penalties ramp
// across three tiers of load (pollenLoad / maxCapacity):
//
//   0–50%   : light penalties for control + kinetic/gravity
//   50–100% : penalties increase toward their cap
//   ≥100%   : penalties are capped (max-speed −15..25%, climb thrust −20..30%)
//
// The gravity applied in the game loop is clamped against the bee's own upward
// thrust (see `gravityHeadroom`), guaranteeing the bee can always climb.

/** Tuning for the tiered weight-penalty curve. All reductions are fractions (0–1). */
export interface WeightPenaltyConfig {
  /** Fraction of full severity reached at 50% load (gentle first half, e.g. 0.3). */
  midpointSeverity: number;
  /** Max-speed reduction at/over full capacity (e.g. 0.20 → −20%). */
  maxSpeedReduction: number;
  /** Upward (climb) thrust reduction at/over full capacity (e.g. 0.25 → −25%). */
  upThrustReduction: number;
  /** Steering acceleration reduction at/over full capacity (e.g. 0.35). */
  steerReduction: number;
  /** Extra glide (friction toward 1) added at/over full capacity (e.g. 0.008). */
  glideMax: number;
}

/** Resolved per-frame weight penalties for the current pollen load. */
export interface WeightPenalties {
  /** Normalized load severity in [0, 1]. */
  severity: number;
  /** Multiply the speed ceiling by this (≤ 1). */
  maxSpeedFactor: number;
  /** Multiply upward (climb) acceleration by this (≤ 1). */
  upThrustFactor: number;
  /** Multiply steering acceleration by this (≤ 1). */
  steerFactor: number;
  /** Add this to the base friction (more glide). */
  glide: number;
}

/**
 * Map a load fraction to a normalized severity in [0, 1] using a two-segment ramp.
 *
 * - At loadFraction 0 → severity 0.
 * - At loadFraction 0.5 → severity = `midpointSeverity` (gentle first half).
 * - At loadFraction 1 → severity 1.
 * - Above 1 (over capacity) → clamped to 1.
 *
 * The shallow first segment keeps the bee responsive at light loads; the steeper
 * second segment ramps penalties up as the bee approaches full capacity.
 *
 * @param loadFraction - pollenLoad / maxCapacity (may exceed 1 when overloaded)
 * @param midpointSeverity - severity reached at 50% load (clamped to [0, 1])
 */
export function computeLoadSeverity(loadFraction: number, midpointSeverity: number): number {
  const f = Math.max(0, loadFraction);
  const mid = Math.max(0, Math.min(midpointSeverity, 1));
  if (f >= 1) return 1;
  if (f <= 0.5) {
    return (f / 0.5) * mid;
  }
  return mid + ((f - 0.5) / 0.5) * (1 - mid);
}

/** Human-readable weight tier shown in the HUD. */
export type WeightLabel = 'Low' | 'Moderate' | 'Heavy';

/**
 * Map a pollen load fraction to a HUD-readable weight tier.
 *
 * The thresholds align with the tiered penalty model: 0–33% is the "light"
 * zone where penalties are mild, 33–66% is the ramp, and ≥66% is the heavy
 * zone where penalties approach their cap.
 *
 * @param loadFraction - pollenLoad / maxCapacity (may exceed 1 when overloaded)
 */
export function weightLabel(loadFraction: number): WeightLabel {
  const f = Math.max(0, loadFraction);
  if (f < 1 / 3) return 'Low';
  if (f < 2 / 3) return 'Moderate';
  return 'Heavy';
}

/**
 * Resolve the per-frame weight penalties for a given load fraction.
 *
 * All factors are ≥ their capped minimum so the bee remains controllable and,
 * combined with the gravity clamp in the game loop, can always climb.
 *
 * @param loadFraction - pollenLoad / maxCapacity (may exceed 1 when overloaded)
 * @param config - tuning for the tiered penalty curve
 */
export function computeWeightPenalties(
  loadFraction: number,
  config: WeightPenaltyConfig,
): WeightPenalties {
  const severity = computeLoadSeverity(loadFraction, config.midpointSeverity);
  const clampReduction = (r: number): number => Math.max(0, Math.min(r, 0.95));
  return {
    severity,
    maxSpeedFactor: 1 - clampReduction(config.maxSpeedReduction) * severity,
    upThrustFactor: 1 - clampReduction(config.upThrustReduction) * severity,
    steerFactor: 1 - clampReduction(config.steerReduction) * severity,
    glide: Math.max(0, config.glideMax) * severity,
  };
}
