/// <reference lib="dom" />

import { App } from '@astracore/application';
import { Phase } from '@astracore/ecs';
import type { IWorld } from '@astracore/ecs';
import { BrowserDeviceAdapter, DeviceService } from '@astracore/device';
import { BrowserInputAdapter, createInputPlugin, InputState } from '@astracore/input';
import { SceneManager, createScenePlugin } from '@astracore/scene';
import { AssetManager } from '@astracore/assets';
import { PixiLoader } from '@astracore/assets-pixi';
import { LocalStorageSaveAdapter } from '@astracore/save-localstorage';
import type { BeeGameSaveData } from '@astracore/save-storage-core';
import { Application } from 'pixi.js';
import { MenuScene } from './menu-scene.js';
import { GameScene } from './game-scene.js';
import { HiveHubScene } from './scenes/hive-hub-scene.js';
import { SceneTransition } from './scene-transition.js';
import { Localization } from './localization.js';
import { setupBeeDevtools } from './bee-stats.js';
import { setupGameDebug } from './dev-tools.js';

const SAVE_KEY = 'bee-game';

const FRESH_SAVE: BeeGameSaveData = {
  version: 1,
  pollenBalance: 0,
  daysCompleted: 0,
  upgrades: { speed: 0, capacity: 0, dayTime: 0, lives: 0, dash: 0, magnet: 0 },
  // calculateStartingLives(upgradeLives=0) = 1 — keep the schema field in sync.
  // (Runtime starting lives are derived from upgrade level, not this field.)
  lives: 1,
};

async function main(): Promise<void> {
  const canvas = document.getElementById('app-canvas') as HTMLCanvasElement | null;
  if (canvas === null) throw new Error('Canvas #app-canvas not found');

  // ── Device info (viewport dimensions + DPR) ─────────────────────────
  const deviceAdapter = new BrowserDeviceAdapter(document.documentElement);
  const deviceService = new DeviceService(deviceAdapter);
  const { width, height, devicePixelRatio } = deviceService.getInfo();

  // ── PixiJS Application (raw, no sprite pipeline) ────────────────────
  const pixiApp = new Application();

  await pixiApp.init({
    canvas,
    background: 0x87ceeb,
    width,
    height,
    antialias: false,
    resolution: devicePixelRatio,
    autoDensity: true,
  });

  // ── Pixi Inspector support (browser extension) ──────────────────────
  (globalThis as Record<string, unknown>).__PIXI_APP__ = pixiApp;

  // ── Design resolution scaling ───────────────────────────────────────
  // The game is designed for a fixed height. On smaller/larger screens,
  // the stage is uniformly scaled to fit, maintaining aspect ratio.
  const DESIGN_HEIGHT = 600;

  function applyScale(): void {
    const currentH = pixiApp.screen.height;
    const scale = currentH / DESIGN_HEIGHT;
    pixiApp.stage.scale.set(scale);
  }
  applyScale();

  // ── Resize handling ─────────────────────────────────────────────────
  deviceService.onResize((info) => {
    pixiApp.renderer.resize(info.width, info.height);
    pixiApp.renderer.resolution = info.devicePixelRatio;
    applyScale();
  });

  // ── AstraCore App ───────────────────────────────────────────────────
  const app = new App({ targetFps: 60, capacity: 4096 });

  // ── Input plugin (WASD + arrows) ────────────────────────────────────
  // Keep a direct reference to the adapter so we can clear stale held-key
  // state on scene re-entry (otherwise a key held through a transition leaves
  // the bee auto-moving on the next day).
  const inputAdapter = new BrowserInputAdapter(window);
  const inputPlugin = createInputPlugin({
    adapter: inputAdapter,
    bindings: [
      { action: 'moveUp', keys: ['KeyW', 'ArrowUp'] },
      { action: 'moveDown', keys: ['KeyS', 'ArrowDown'] },
      { action: 'moveLeft', keys: ['KeyA', 'ArrowLeft'] },
      { action: 'moveRight', keys: ['KeyD', 'ArrowRight'] },
    ],
  });
  app.addPlugin(inputPlugin);

  // Query for InputState on the app world — passed to GameScene
  const inputQuery = app.world.query({ with: [InputState] });

  // ── Scene Manager ───────────────────────────────────────────────────
  const assetManager = new AssetManager();
  assetManager.registerManifestLoader(new PixiLoader());

  const sceneManager = new SceneManager({ worldCapacity: 4096, assets: assetManager });

  // ── Scene transition (fade overlay) ─────────────────────────────────
  const sceneTransition = new SceneTransition(pixiApp.stage);

  // ── Localization ────────────────────────────────────────────────────
  const localization = new Localization();
  await localization.load('locales/en.json');

  // ── Save storage ────────────────────────────────────────────────────
  const saveStorage = new LocalStorageSaveAdapter();

  // Install the dev console: gameDebug.save.print() / gameDebug.timeScale.set(0)
  setupGameDebug({ saveStorage, saveKey: SAVE_KEY });

  // ── Shared game progression state ───────────────────────────────────
  // Load any persisted save up-front so the menu can decide whether to show
  // a "Resume Game" button. If load() returns undefined (no save, malformed,
  // or schema violation), we fall back to a fresh in-memory save.
  const initialSave = await saveStorage.load<BeeGameSaveData>(SAVE_KEY);
  let saveData: BeeGameSaveData = initialSave
    ? { ...initialSave, upgrades: { ...initialSave.upgrades } }
    : { ...FRESH_SAVE, upgrades: { ...FRESH_SAVE.upgrades } };
  const hasSave = initialSave !== undefined;

  // ── Game scene ──────────────────────────────────────────────────────
  const gameScene = new GameScene(pixiApp, inputQuery, () => {
    // Day complete → go to the Hive Hub (NOT the menu).
    // GameScene already persisted the updated save (daysCompleted = currentDay).
    if (sceneTransition.isActive) return;
    sceneTransition.playWithSwap(() => sceneManager.transition('hive-hub')).catch(console.error);
  });
  // Wire save system into the game scene
  gameScene.saveSystem = {
    save: (key, data) => saveStorage.save(key, data),
    load: (key) => saveStorage.load(key),
  };
  // Lost all lives → restart the SAME day (no progress, no day advance)
  gameScene.onGameOver = () => {
    if (sceneTransition.isActive) return;
    sceneTransition.playWithSwap(async () => {
      // Re-enter the game scene at the same day with the same upgrades/balance.
      // transition('game') tears down and re-enters the scene (fresh day).
      gameScene.currentDay = saveData.daysCompleted + 1;
      gameScene.pollenBalance = saveData.pollenBalance;
      gameScene.setUpgrades(saveData.upgrades);
      // Drop any held-key state from before the restart so the bee doesn't
      // resume auto-moving when the new day spawns.
      inputAdapter.reset();
      await sceneManager.transition('game');
    }).catch(console.error);
  };

  // ── Hive hub scene ──────────────────────────────────────────────────
  const hiveHubScene = new HiveHubScene({
    pixiApp,
    localization,
    saveStorage,
    sceneTransition,
    onNextDay: () => {
      // Reload the latest save (HiveHubScene persists purchases + state before calling this)
      void (async () => {
        const loaded = await saveStorage.load<BeeGameSaveData>(SAVE_KEY);
        if (loaded) saveData = loaded;
        gameScene.currentDay = saveData.daysCompleted + 1;
        gameScene.pollenBalance = saveData.pollenBalance;
        gameScene.setUpgrades(saveData.upgrades);
        // Clear stale held-key state before entering the new day.
        inputAdapter.reset();
        await sceneTransition.playWithSwap(() => sceneManager.transition('game'));
      })();
    },
  });

  // ── Menu scene ──────────────────────────────────────────────────────
  const menuScene = new MenuScene({
    hasSave,
    // Resume from the existing save: drop the player at the hive hub with
    // their persisted balance / upgrades / daysCompleted in place.
    onResume: () => {
      if (sceneTransition.isActive) return;
      void (async () => {
        const loaded = await saveStorage.load<BeeGameSaveData>(SAVE_KEY);
        if (loaded) saveData = { ...loaded, upgrades: { ...loaded.upgrades } };
        gameScene.currentDay = saveData.daysCompleted + 1;
        gameScene.pollenBalance = saveData.pollenBalance;
        gameScene.setUpgrades(saveData.upgrades);
        inputAdapter.reset();
        await sceneTransition.playWithSwap(() => sceneManager.transition('hive-hub'));
      })();
    },
    // Start a brand-new run: explicitly wipe the existing save so closing the
    // tab mid-day doesn't leave the OLD progress lingering in storage.
    onStartNew: () => {
      if (sceneTransition.isActive) return;
      void saveStorage.delete(SAVE_KEY).catch(() => {/* best-effort */});
      saveData = { ...FRESH_SAVE, upgrades: { ...FRESH_SAVE.upgrades } };
      gameScene.currentDay = 1;
      gameScene.pollenBalance = 0;
      gameScene.setUpgrades(saveData.upgrades);
      inputAdapter.reset();
      sceneTransition.playWithSwap(() => sceneManager.transition('game')).catch((err: unknown) => {
        console.error('[bee-game] Scene transition error:', err);
        const msg = err instanceof Error ? `${err.message}\n${err.stack ?? ''}` : String(err);
        const div = document.createElement('div');
        div.style.cssText = 'position:fixed;inset:0;background:#200;color:#f88;padding:20px;font:14px monospace;z-index:9999;white-space:pre-wrap;overflow:auto;';
        div.textContent = `[bee-game] Scene transition error:\n${msg}`;
        document.body.appendChild(div);
      });
    },
  });

  sceneManager.register('menu', menuScene);
  sceneManager.register('game', gameScene);
  sceneManager.register('hive-hub', hiveHubScene);

  // Scene plugin — no renderer option since we manage Pixi.js rendering ourselves
  app.addPlugin(createScenePlugin({
    manager: sceneManager,
    initial: 'menu',
  }));

  // ── Dev-only: Gizmos + ECS Inspector (tree-shaken in production) ────
  if (import.meta.env.DEV) {
    const [
      { createGizmoPlugin },
      { PixiGizmoAdapter },
      { DevTools, createDevToolsPlugin },
      { EcsInspector },
      {
        BeeTag, PollenTag, HiveTag, GroundBirdTag, WaveBirdTag,
        Position, Velocity, CircleCollider, RectCollider, PollenLoad, WaveMotion,
      },
    ] = await Promise.all([
      import('@astracore/gizmos'),
      import('@astracore/gizmos/pixi'),
      import('@astracore/devtools-core'),
      import('@astracore/ecs-inspector'),
      import('./components.js'),
    ]);

    // Gizmo plugin
    const gizmoAdapter = new PixiGizmoAdapter(pixiApp.stage);
    app.addPlugin(createGizmoPlugin(gizmoAdapter));

    // ECS Inspector
    const devtools = new DevTools();
    const inspector = new EcsInspector(new Map([
      ['BeeTag',         BeeTag         as never],
      ['PollenTag',      PollenTag      as never],
      ['HiveTag',        HiveTag        as never],
      ['GroundBirdTag',  GroundBirdTag  as never],
      ['WaveBirdTag',    WaveBirdTag    as never],
      ['Position',       Position       as never],
      ['Velocity',       Velocity       as never],
      ['CircleCollider', CircleCollider as never],
      ['RectCollider',   RectCollider   as never],
      ['PollenLoad',     PollenLoad     as never],
      ['WaveMotion',     WaveMotion     as never],
    ]));
    devtools.registerPanel(inspector);
    app.addPlugin(createDevToolsPlugin(devtools, {
      getWorld: () => sceneManager.activeWorld,
    }));
  }

  // ── LateUpdate system: call pixiApp.render() each frame ─────────────
  // Registered on app.world so it runs AFTER scene:step and gizmo-system
  app.world.addSystem({
    name: 'bee:pixi-render',
    phase: Phase.LateUpdate,
    order: 1000,
    fn: (_w: IWorld) => {
      pixiApp.render();
    },
  });

  // ── Start ───────────────────────────────────────────────────────────
  app.start();

  // ── Dev console: live bee stat tuning (beeStats.set({...})) ─────────
  setupBeeDevtools();
}

main().catch((err: unknown) => {
  console.error('[bee-game] Fatal error:', err);
  // Show error on screen so it's visible on device/emulator
  const msg = err instanceof Error ? `${err.message}\n${err.stack ?? ''}` : String(err);
  const div = document.createElement('div');
  div.style.cssText = 'position:fixed;inset:0;background:#200;color:#f88;padding:20px;font:14px monospace;z-index:9999;white-space:pre-wrap;overflow:auto;';
  div.textContent = `[bee-game] Fatal error:\n${msg}`;
  document.body.appendChild(div);
});
