/**
 * Pure movement functions for the Bee Game.
 * Exported for property-based testing.
 * @packageDocumentation
 */

/**
 * Apply friction to velocity — multiply each component by friction factor.
 * Friction should be in (0, 1) for deceleration (e.g., 0.92).
 */
export function applyFriction(
  dx: number,
  dy: number,
  friction: number,
): { dx: number; dy: number } {
  return { dx: dx * friction, dy: dy * friction };
}

/**
 * Apply acceleration from input axes, then clamp velocity magnitude to maxSpeed.
 * axisX/axisY should be in [-1, 1]. accel is in px/s². dt is in seconds.
 */
export function applyAcceleration(
  dx: number,
  dy: number,
  axisX: number,
  axisY: number,
  accel: number,
  dt: number,
  maxSpeed: number,
): { dx: number; dy: number } {
  let newDx = dx + axisX * accel * dt;
  let newDy = dy + axisY * accel * dt;
  const magnitude = Math.sqrt(newDx * newDx + newDy * newDy);
  if (magnitude > maxSpeed && magnitude > 0) {
    newDx = (newDx / magnitude) * maxSpeed;
    newDy = (newDy / magnitude) * maxSpeed;
  }
  return { dx: newDx, dy: newDy };
}
