/**
 * Bird_02 enemy system for the Bee Game.
 *
 * Bird_02 is a wave bird that spawns from the right edge and flies leftward
 * at a constant speed while oscillating vertically in a sinusoidal pattern.
 *
 * Responsibilities:
 * - Spawning Bird_02 entities at random positions in the upper two-thirds
 * - Moving all Bird_02 entities leftward each frame
 * - Applying sinusoidal vertical oscillation: baseY + amplitude * sin(2π * frequency * t + phase)
 * - Destroying entities that pass beyond the left edge
 *
 * @packageDocumentation
 */

import type { World, EntityId } from '@astracore/ecs';
import { Position, Velocity, CircleCollider, WaveBirdTag, WaveMotion, Evasion } from '../components.js';
import { BIRD_02_CONFIG, EVASION_CONFIG } from '../enemy-config.js';
import type { EvasionBird, EvasionCapableSystem } from './bird-evasion.js';

// ─── Constants ────────────────────────────────────────────────────────────────

/** Distance past the left edge before an entity is destroyed (in pixels). */
const CLEANUP_MARGIN = 50;

/** Default circle collider radius for Bird_02 entities (in pixels). */
const COLLIDER_RADIUS = 14;

/** Interval (seconds) between baseline-height changes. */
const HEIGHT_CHANGE_INTERVAL = 3;

/** Speed (px/s) at which the oscillation baseline glides to a new target. */
const BASELINE_SPEED = 80;

// ─── Bird02System ─────────────────────────────────────────────────────────────

/**
 * Manages Bird_02 enemy entities — spawning, movement, wave oscillation, and cleanup.
 *
 * Bird_02 flies left at a constant speed and oscillates vertically with a
 * sinusoidal wave. Every 3 seconds its oscillation baseline retargets to a new
 * height, gliding smoothly while keeping the full wave (baseline ± amplitude)
 * within the playable vertical bounds.
 */
export class Bird02System implements EvasionCapableSystem {
  private readonly _world: World;
  private readonly _entities: Set<EntityId> = new Set();
  /** Tracks elapsed time per entity for the wave calculation. */
  private readonly _elapsedTime: Map<EntityId, number> = new Map();
  /** Per-entity baseline retarget state. */
  private readonly _baseState = new Map<
    EntityId,
    { timer: number; targetBaseY: number; minBase: number; maxBase: number }
  >();

  constructor(world: World) {
    this._world = world;
  }

  /**
   * Spawn a new Bird_02 entity at the right edge of the world.
   *
   * The oscillation baseline stays within a flight zone defined by
   * {@link Bird02Config.minHeightFraction} and {@link Bird02Config.maxHeightFraction}
   * (fractions of the space between `topY` and `groundY`), inset by the wave
   * amplitude so the full wave remains inside the zone.
   *
   * @param worldRightEdge - X coordinate of the right world boundary (spawn X position)
   * @param groundY - Y coordinate of the ground surface (bottom boundary)
   * @param topY - Y coordinate of the top of the playable area (top boundary)
   */
  public spawn(worldRightEdge: number, groundY: number, topY: number): EntityId {
    const world = this._world;

    const amplitude = BIRD_02_CONFIG.amplitude;
    const verticalSpace = groundY - topY;
    // Baseline must keep the full wave (±amplitude) within the configured zone.
    const minBase = topY + BIRD_02_CONFIG.minHeightFraction * verticalSpace + amplitude;
    const maxBase = topY + BIRD_02_CONFIG.maxHeightFraction * verticalSpace - amplitude;
    const safeMaxBase = Math.max(minBase, maxBase);
    const baseY = minBase + Math.random() * (safeMaxBase - minBase);

    const phase = Math.random() * Math.PI * 2;
    const canEvade = Math.random() < BIRD_02_CONFIG.evasionChance;

    const entity = world.createEntity();
    world.addComponent(entity, new WaveBirdTag());
    world.addComponent(entity, new Position(worldRightEdge, baseY));
    world.addComponent(entity, new Velocity(-BIRD_02_CONFIG.speed, 0));
    world.addComponent(entity, new CircleCollider(COLLIDER_RADIUS));
    world.addComponent(
      entity,
      new WaveMotion(baseY, amplitude, BIRD_02_CONFIG.frequency, phase),
    );
    world.addComponent(entity, new Evasion(canEvade, 0));

    this._entities.add(entity);
    this._elapsedTime.set(entity, 0);
    this._baseState.set(entity, {
      timer: 0,
      targetBaseY: baseY,
      minBase,
      maxBase: safeMaxBase,
    });
    return entity;
  }

  /**
   * Update all Bird_02 entities: move leftward, retarget oscillation baseline
   * every 3s, advance evade maneuvers, apply sinusoidal Y, and destroy past
   * left edge.
   *
   * @param dt - Delta time in seconds since last frame
   */
  public update(dt: number): void {
    const world = this._world;
    const toRemove: EntityId[] = [];

    for (const entity of this._entities) {
      if (!world.hasEntity(entity)) {
        toRemove.push(entity);
        continue;
      }

      const pos = world.getComponent(entity, Position);
      const vel = world.getComponent(entity, Velocity);
      const wave = world.getComponent(entity, WaveMotion);
      const bs = this._baseState.get(entity);

      if (!pos || !vel || !wave || !bs) {
        toRemove.push(entity);
        continue;
      }

      const elapsed = (this._elapsedTime.get(entity) ?? 0) + dt;
      this._elapsedTime.set(entity, elapsed);

      // Move leftward
      pos.x += vel.dx * dt;

      const evasion = world.getComponent(entity, Evasion);
      const evading = evasion !== undefined && evasion.cooldown > 0;
      if (evasion && evading) {
        evasion.cooldown = Math.max(0, evasion.cooldown - dt);
      }

      // Every HEIGHT_CHANGE_INTERVAL, pick a new in-bounds baseline target
      // (skipped while actively evading so the dodge isn't overridden).
      if (!evading) {
        bs.timer += dt;
        if (bs.timer >= HEIGHT_CHANGE_INTERVAL) {
          bs.timer -= HEIGHT_CHANGE_INTERVAL;
          bs.targetBaseY = bs.minBase + Math.random() * (bs.maxBase - bs.minBase);
        }
      }

      // Glide the wave baseline toward the target (faster while evading)
      const dy = bs.targetBaseY - wave.baseY;
      const speed = evading ? EVASION_CONFIG.verticalSpeed : BASELINE_SPEED;
      const step = speed * dt;
      if (Math.abs(dy) <= step) {
        wave.baseY = bs.targetBaseY;
      } else {
        wave.baseY += Math.sign(dy) * step;
      }

      // Apply sinusoidal vertical oscillation around the (moving) baseline
      pos.y = wave.baseY + wave.amplitude * Math.sin(2 * Math.PI * wave.frequency * elapsed + wave.phase);

      // Destroy if past left edge by cleanup margin
      if (pos.x < -CLEANUP_MARGIN) {
        world.destroyEntity(entity);
        toRemove.push(entity);
      }
    }

    for (const entity of toRemove) {
      this._entities.delete(entity);
      this._elapsedTime.delete(entity);
      this._baseState.delete(entity);
    }
  }

  /** Snapshot this system's birds for cross-system collision/evasion checks. */
  public collectEvasionBirds(): EvasionBird[] {
    const world = this._world;
    const birds: EvasionBird[] = [];
    for (const entity of this._entities) {
      if (!world.hasEntity(entity)) continue;
      const pos = world.getComponent(entity, Position);
      const col = world.getComponent(entity, CircleCollider);
      const evasion = world.getComponent(entity, Evasion);
      if (!pos || !col) continue;
      birds.push({
        id: entity,
        x: pos.x,
        y: pos.y,
        radius: col.radius,
        canEvade: evasion?.canEvade ?? false,
        evading: (evasion?.cooldown ?? 0) > 0,
      });
    }
    return birds;
  }

  /**
   * Begin an evade maneuver: retarget the oscillation baseline in the given
   * vertical direction by {@link EVASION_CONFIG.distance}, clamped to bounds.
   * If the preferred direction is blocked by a bound, the opposite is used so
   * the bird still changes height.
   *
   * @param id - Entity to evade.
   * @param dir - -1 to fly up, +1 to bounce down.
   */
  public beginEvade(id: EntityId, dir: number): void {
    const bs = this._baseState.get(id);
    const wave = this._world.hasEntity(id)
      ? this._world.getComponent(id, WaveMotion)
      : undefined;
    const evasion = this._world.hasEntity(id)
      ? this._world.getComponent(id, Evasion)
      : undefined;
    if (!bs || !wave || !evasion || !evasion.canEvade) return;

    const distance = EVASION_CONFIG.distance;
    let target = wave.baseY + dir * distance;
    if (target < bs.minBase || target > bs.maxBase) {
      // Preferred direction leaves bounds → bounce the other way instead.
      target = wave.baseY - dir * distance;
    }
    bs.targetBaseY = Math.max(bs.minBase, Math.min(target, bs.maxBase));
    evasion.cooldown = EVASION_CONFIG.duration;
  }

  /**
   * Get the number of active Bird_02 entities.
   */
  public get count(): number {
    return this._entities.size;
  }

  /**
   * Get all tracked Bird_02 entity IDs (read-only).
   */
  public get entities(): ReadonlySet<EntityId> {
    return this._entities;
  }

  /**
   * Destroy all tracked Bird_02 entities and clear the system state.
   */
  public clear(): void {
    for (const entity of this._entities) {
      if (this._world.hasEntity(entity)) {
        this._world.destroyEntity(entity);
      }
    }
    this._entities.clear();
    this._elapsedTime.clear();
    this._baseState.clear();
  }
}
