/**
 * Flytrap enemy system for the Bee Game.
 *
 * Manages Flytrap entities that catch the Bee when within proximity radius,
 * pin it for a configurable duration, then enter a cooldown before reactivating.
 *
 * @packageDocumentation
 */

import { FlytrapState, Position } from '../components.js';

// ─── Types ────────────────────────────────────────────────────────────────────

/** Sprite alias returned to indicate which sprite frame a flytrap should display. */
export type FlytrapSpriteAlias = 'flytrap_01' | 'flytrap_02';

/** Per-entity result after an update tick. */
export interface FlytrapEntityState {
  /** The entity index in the managed array. */
  index: number;
  /** Current sprite alias to display. */
  sprite: FlytrapSpriteAlias;
  /** Whether this flytrap is currently pinning the Bee. */
  isPinning: boolean;
}

/** Result returned from the system update. */
export interface FlytrapUpdateResult {
  /** Whether any flytrap is currently pinning the Bee. */
  beePinned: boolean;
  /** Per-entity states for rendering updates. */
  entities: FlytrapEntityState[];
  /**
   * World position the Bee should be snapped to while pinned. `undefined`
   * when no flytrap is pinning this frame.
   */
  pinX?: number;
  pinY?: number;
}

// ─── FlytrapSystem ────────────────────────────────────────────────────────────

/**
 * System that manages all Flytrap entities.
 *
 * Each Flytrap has three phases:
 * 1. Active (isActive=true, isCatching=false): waiting for Bee to enter proximity radius
 * 2. Catching (isCatching=true): Bee is pinned, catchTimer counts up to catchDuration
 * 3. Cooldown (isActive=false, isCatching=false): recovering before becoming active again
 *
 * The system does NOT manage Position or spawning — those are handled externally.
 * It receives Bee state each frame and returns whether the Bee should be pinned.
 */
export class FlytrapSystem {
  private readonly _states: FlytrapState[] = [];
  private readonly _positions: Position[] = [];
  /**
   * Pin positions per flytrap — where the bee is snapped to while caught.
   * Defaults to the catch position when not supplied to addFlytrap.
   */
  private readonly _pinPositions: Position[] = [];

  /**
   * Register a Flytrap entity with this system.
   * @param state - The FlytrapState component for this entity
   * @param position - The Position component (catch zone center) for this entity
   * @param pinPosition - World position the bee is snapped to while pinned.
   *                      If omitted, defaults to `position` (legacy behavior).
   * @returns The index assigned to this entity
   */
  public addFlytrap(state: FlytrapState, position: Position, pinPosition?: Position): number {
    const index = this._states.length;
    this._states.push(state);
    this._positions.push(position);
    this._pinPositions.push(pinPosition ?? new Position(position.x, position.y));
    return index;
  }

  /**
   * Get the number of managed flytraps.
   */
  public get count(): number {
    return this._states.length;
  }

  /**
   * Get a FlytrapState by index (for testing/inspection).
   */
  public getState(index: number): FlytrapState | undefined {
    return this._states[index];
  }

  /**
   * Get a Position by index (for testing/inspection).
   */
  public getPosition(index: number): Position | undefined {
    return this._positions[index];
  }

  /**
   * Update all Flytrap entities for the current frame.
   *
   * @param dt - Delta time in seconds
   * @param beeX - Bee's current X position
   * @param beeY - Bee's current Y position
   * @param beeIsDead - Whether the Bee is currently dead (dying/respawning)
   * @returns Update result indicating pin state and per-entity sprite info
   */
  public update(dt: number, beeX: number, beeY: number, beeIsDead: boolean): FlytrapUpdateResult {
    let beePinned = false;
    let pinX: number | undefined;
    let pinY: number | undefined;
    const entities: FlytrapEntityState[] = [];

    for (let i = 0; i < this._states.length; i++) {
      const state = this._states[i]!;
      const pos = this._positions[i]!;
      const pinPos = this._pinPositions[i]!;

      let sprite: FlytrapSpriteAlias = 'flytrap_01';
      let isPinning = false;

      if (state.isCatching) {
        // ── Currently catching the Bee ──────────────────────────────────

        if (beeIsDead) {
          // Bee died while pinned: release immediately, enter cooldown
          state.isCatching = false;
          state.isActive = false;
          state.catchTimer = 0;
          state.cooldownTimer = state.cooldownDuration;
          sprite = 'flytrap_01'; // closed during cooldown
        } else {
          // Increment catch timer
          state.catchTimer += dt;

          if (state.catchTimer >= state.catchDuration) {
            // Pin duration expired: release Bee, enter cooldown
            state.isCatching = false;
            state.isActive = false;
            state.catchTimer = 0;
            state.cooldownTimer = state.cooldownDuration;
            sprite = 'flytrap_01'; // closed during cooldown
          } else {
            // Still catching
            sprite = 'flytrap_01'; // closed/catching
            isPinning = true;
            beePinned = true;
            pinX = pinPos.x;
            pinY = pinPos.y;
          }
        }
      } else if (!state.isActive) {
        // ── In cooldown ─────────────────────────────────────────────────
        state.cooldownTimer -= dt;
        sprite = 'flytrap_01'; // still closed in cooldown

        if (state.cooldownTimer <= 0) {
          // Cooldown expired: become active again
          state.isActive = true;
          state.cooldownTimer = 0;
          sprite = 'flytrap_02'; // open and ready
        }
      } else {
        // ── Active: check if Bee is within proximity radius ─────────────
        const dx = beeX - pos.x;
        const dy = beeY - pos.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance < state.proximityRadius) {
          // Catch the Bee
          state.isCatching = true;
          state.catchTimer = 0;
          sprite = 'flytrap_01'; // snap closed
          isPinning = true;
          beePinned = true;
          pinX = pinPos.x;
          pinY = pinPos.y;
        } else {
          sprite = 'flytrap_02'; // open/waiting
        }
      }

      entities.push({ index: i, sprite, isPinning });
    }

    const result: FlytrapUpdateResult = { beePinned, entities };
    if (pinX !== undefined) result.pinX = pinX;
    if (pinY !== undefined) result.pinY = pinY;
    return result;
  }

  /**
   * Reset all flytraps to their initial active state.
   * Useful when restarting a level.
   */
  public reset(): void {
    for (const state of this._states) {
      state.isActive = true;
      state.isCatching = false;
      state.catchTimer = 0;
      state.cooldownTimer = 0;
    }
  }

  /**
   * Remove all managed flytraps.
   */
  public clear(): void {
    this._states.length = 0;
    this._positions.length = 0;
    this._pinPositions.length = 0;
  }
}
