/// <reference lib="dom" />

/**
 * Runtime-adjustable bee movement stats for the Bee Game.
 *
 * These values are seeded from BEE_CONFIG but can be tweaked live (e.g. from
 * the browser console via `window.beeStats`) to tune the feel of bee movement
 * without rebuilding. The GameScene reads from BEE_STATS every frame.
 *
 * @packageDocumentation
 */

import { BEE_CONFIG } from './config.js';

/** Mutable bee movement stats — read by the game loop each frame. */
export interface BeeStats {
  /** Base maximum speed in px/s with no pollen load. */
  baseMaxSpeed: number;
  /** Absolute speed ceiling in px/s (kinetic overshoot allowance). */
  maxSpeedCeiling: number;
  /** Minimum speed in px/s at maximum pollen load. */
  minSpeed: number;
  /** Base acceleration in px/s². */
  acceleration: number;
  /** Base per-frame friction multiplier (0-1, higher = longer glide). */
  baseFriction: number;
  /** Extra glide approaching 1 at max pollen load (harder to stop). */
  kineticGlide: number;
  /** Steering resistance at max load (0-1) — higher = harder to change direction. */
  kineticSteerPenalty: number;
  /** Gravity in px/s² applied at max pollen load. */
  gravity: number;
  /** Severity reached at 50% load (0-1) for the tiered weight-penalty curve. */
  weightMidpointSeverity: number;
  /** Max-speed reduction at/above full capacity (0-1). */
  weightMaxSpeedReduction: number;
  /** Upward (climb) thrust reduction at/above full capacity (0-1). */
  weightUpThrustReduction: number;
  /** Steering-acceleration reduction at/above full capacity (0-1). */
  weightSteerReduction: number;
  /** Extra glide added to base friction at/above full capacity. */
  weightGlideMax: number;
  /** Fraction of upward thrust gravity may consume (0-1) — guarantees climb. */
  gravityThrustRatio: number;
}

/** Live stats object — mutate these to retune movement at runtime. */
export const BEE_STATS: BeeStats = {
  baseMaxSpeed: BEE_CONFIG.baseMaxSpeed,
  maxSpeedCeiling: BEE_CONFIG.maxSpeedCeiling,
  minSpeed: BEE_CONFIG.minSpeed,
  acceleration: BEE_CONFIG.acceleration,
  baseFriction: BEE_CONFIG.baseFriction,
  kineticGlide: BEE_CONFIG.kineticGlide,
  kineticSteerPenalty: BEE_CONFIG.kineticSteerPenalty,
  gravity: BEE_CONFIG.gravity,
  weightMidpointSeverity: BEE_CONFIG.weightMidpointSeverity,
  weightMaxSpeedReduction: BEE_CONFIG.weightMaxSpeedReduction,
  weightUpThrustReduction: BEE_CONFIG.weightUpThrustReduction,
  weightSteerReduction: BEE_CONFIG.weightSteerReduction,
  weightGlideMax: BEE_CONFIG.weightGlideMax,
  gravityThrustRatio: BEE_CONFIG.gravityThrustRatio,
};

/** Snapshot of the defaults so the console helper can reset. */
const BEE_STATS_DEFAULTS: BeeStats = { ...BEE_STATS };

/**
 * Expose a small devtools API on `window.beeStats` for live tuning.
 * Safe to call multiple times; only attaches once.
 *
 * Console usage:
 *   beeStats.get()                       // print current stats
 *   beeStats.set({ baseMaxSpeed: 420 })  // patch one or more fields
 *   beeStats.reset()                     // restore defaults
 */
export function setupBeeDevtools(): void {
  if (typeof window === 'undefined') return;

  const api = {
    /** Return a copy of the current live stats. */
    get(): BeeStats {
      const snapshot = { ...BEE_STATS };
      // eslint-disable-next-line no-console
      console.table(snapshot);
      return snapshot;
    },
    /** Patch one or more stat fields. Unknown keys are ignored. */
    set(patch: Partial<BeeStats>): BeeStats {
      for (const key of Object.keys(patch) as (keyof BeeStats)[]) {
        const value = patch[key];
        if (typeof value === 'number' && Number.isFinite(value)) {
          BEE_STATS[key] = value;
        }
      }
      // eslint-disable-next-line no-console
      console.log('[beeStats] updated:', { ...BEE_STATS });
      return { ...BEE_STATS };
    },
    /** Restore all stats to their config defaults. */
    reset(): BeeStats {
      Object.assign(BEE_STATS, BEE_STATS_DEFAULTS);
      // eslint-disable-next-line no-console
      console.log('[beeStats] reset to defaults:', { ...BEE_STATS });
      return { ...BEE_STATS };
    },
    /** The raw mutable object, for direct field assignment. */
    raw: BEE_STATS,
  };

  (window as unknown as Record<string, unknown>)['beeStats'] = api;

  // eslint-disable-next-line no-console
  console.log(
    '%c[bee-game] Dev stats ready — use beeStats.get() / beeStats.set({ baseMaxSpeed: 420 }) / beeStats.reset()',
    'color:#ffcc00;font-weight:bold',
  );
}
