import { Container, Sprite, TilingSprite, Texture } from 'pixi.js';

// ─── Configuration ────────────────────────────────────────────────────────────

/** Scroll factor for the far cloud layer (slowest). */
const FAR_CLOUD_SCROLL_FACTOR = 0.1;

/** Scroll factor for the near cloud layer (faster). */
const NEAR_CLOUD_SCROLL_FACTOR = 0.2;

/** Minimum spacing between cloud instances within the same layer (in pixels). */
const MIN_CLOUD_SPACING = 100;

// ─── Types ────────────────────────────────────────────────────────────────────

export interface ParallaxTextures {
  /** The 1px-wide background texture for tiling the sky. */
  background: Texture;
  /** Cloud textures used across both layers. */
  clouds: Texture[];
}

export interface ParallaxConfig {
  /** Viewport width in pixels. */
  viewportWidth: number;
  /** Viewport height in pixels. */
  viewportHeight: number;
  /** Textures for the parallax layers. */
  textures: ParallaxTextures;
}

// ─── Cloud Layer ──────────────────────────────────────────────────────────────

/**
 * Manages a single cloud layer with a given scroll factor.
 * Clouds are arranged horizontally with seamless wrapping.
 */
class CloudLayer {
  public readonly container: Container;
  private readonly _sprites: Sprite[] = [];
  private readonly _scrollFactor: number;
  private readonly _totalWidth: number;

  constructor(
    textures: Texture[],
    viewportWidth: number,
    viewportHeight: number,
    scrollFactor: number,
  ) {
    this.container = new Container();
    this._scrollFactor = scrollFactor;

    // Arrange clouds across a strip wide enough for seamless scrolling.
    // We need enough clouds to cover viewport + extra buffer so that
    // recycling keeps the strip seamless.
    const stripWidth = viewportWidth + viewportWidth; // 2x viewport for wrap buffer

    let x = 0;
    let textureIndex = 0;

    while (x < stripWidth) {
      const tex = textures[textureIndex % textures.length]!;
      const sprite = new Sprite(tex);
      sprite.anchor.set(0, 0.5);
      // Position vertically: distribute in the upper portion of the viewport
      // Use a deterministic-ish vertical placement based on index
      const yRatio = 0.15 + (textureIndex % 3) * 0.15; // 15%, 30%, 45% from top
      sprite.y = viewportHeight * yRatio;
      sprite.x = x;
      this.container.addChild(sprite);
      this._sprites.push(sprite);

      // Advance by sprite width + minimum spacing
      x += tex.width + MIN_CLOUD_SPACING;
      textureIndex++;
    }

    this._totalWidth = x;
  }

  /**
   * Update cloud positions based on camera offset.
   * Implements seamless wrapping by repositioning sprites that scroll
   * out of the visible area to the other side.
   */
  public update(cameraX: number): void {
    const offset = cameraX * this._scrollFactor;

    // Apply the parallax offset to the entire container
    this.container.x = -offset;

    // Seamless wrapping: recycle sprites that go off-screen
    for (const sprite of this._sprites) {
      // The world-space x of this sprite
      const worldX = sprite.x + this.container.x;

      if (worldX + sprite.width < -sprite.width) {
        // Sprite is off the left edge — move to the right end
        sprite.x += this._totalWidth;
      } else if (worldX > this._totalWidth) {
        // Sprite is off the right edge — move to the left end
        sprite.x -= this._totalWidth;
      }
    }
  }

  /** Total strip width (used for external calculations like spacing checks). */
  public get totalWidth(): number {
    return this._totalWidth;
  }

  /** Scroll factor for this layer. */
  public get scrollFactor(): number {
    return this._scrollFactor;
  }

  /** Read-only access to sprites for testing/inspection. */
  public get sprites(): readonly Sprite[] {
    return this._sprites;
  }
}

// ─── ParallaxSystem ───────────────────────────────────────────────────────────

/**
 * Manages a multi-layer parallax background for the bee game.
 *
 * Layers (back to front):
 * 1. Sky — TilingSprite filling the viewport, no parallax offset
 * 2. Far clouds — scroll at 0.1x camera offset
 * 3. Near clouds — scroll at 0.2x camera offset
 *
 * All layers are rendered behind gameplay elements by adding the
 * root container before the game world container in the display list.
 */
export class ParallaxSystem {
  /** Root container holding all parallax layers. Add this to the stage. */
  public readonly container: Container;

  private readonly _sky: TilingSprite;
  private readonly _farClouds: CloudLayer;
  private readonly _nearClouds: CloudLayer;
  private readonly _viewportWidth: number;

  constructor(config: ParallaxConfig) {
    const { viewportWidth, viewportHeight, textures } = config;
    this._viewportWidth = viewportWidth;

    this.container = new Container();

    // ── Sky layer: 1px-wide background tiled horizontally ─────────────
    this._sky = new TilingSprite({
      texture: textures.background,
      width: viewportWidth,
      height: viewportHeight,
    });
    this.container.addChild(this._sky);

    // ── Far cloud layer (0.1x scroll) ─────────────────────────────────
    this._farClouds = new CloudLayer(
      textures.clouds,
      viewportWidth,
      viewportHeight,
      FAR_CLOUD_SCROLL_FACTOR,
    );
    this.container.addChild(this._farClouds.container);

    // ── Near cloud layer (0.2x scroll) ────────────────────────────────
    this._nearClouds = new CloudLayer(
      textures.clouds,
      viewportWidth,
      viewportHeight,
      NEAR_CLOUD_SCROLL_FACTOR,
    );
    // Offset near clouds slightly lower and scale them a bit larger for depth
    this._nearClouds.container.y = 20;
    this.container.addChild(this._nearClouds.container);
  }

  /**
   * Update all parallax layers based on the current camera X offset.
   * Call this every frame after the camera position is updated.
   *
   * @param cameraX - The camera's horizontal offset in world pixels
   *   (positive = camera moved right, clouds scroll left).
   */
  public update(cameraX: number): void {
    // Sky is static (no horizontal scroll since it tiles seamlessly)
    // But if we want subtle sky movement, we could add it here.
    // For now, the TilingSprite fills the viewport with no offset.

    this._farClouds.update(cameraX);
    this._nearClouds.update(cameraX);
  }

  /**
   * Resize the parallax layers when the viewport changes.
   */
  public resize(viewportWidth: number, viewportHeight: number): void {
    this._sky.width = viewportWidth;
    this._sky.height = viewportHeight;
  }

  /**
   * Clean up all display objects.
   */
  public destroy(): void {
    this.container.destroy({ children: true });
  }

  // ── Getters for testing/inspection ──────────────────────────────────

  /** The sky TilingSprite. */
  public get sky(): TilingSprite {
    return this._sky;
  }

  /** The far cloud layer. */
  public get farClouds(): CloudLayer {
    return this._farClouds;
  }

  /** The near cloud layer. */
  public get nearClouds(): CloudLayer {
    return this._nearClouds;
  }

  /** Viewport width. */
  public get viewportWidth(): number {
    return this._viewportWidth;
  }
}

// ─── Exported helpers for property testing ────────────────────────────────────

/**
 * Compute the parallax offset for a layer given a camera position and scroll factor.
 * This is the pure calculation used internally by CloudLayer.update().
 */
export function computeParallaxOffset(cameraX: number, scrollFactor: number): number {
  return cameraX * scrollFactor;
}

/**
 * Generate cloud positions for a layer given textures and viewport width.
 * Returns an array of x positions where each cloud will be placed.
 * Useful for property testing the spacing invariant.
 */
export function generateCloudPositions(
  textureWidths: number[],
  viewportWidth: number,
  minSpacing: number = MIN_CLOUD_SPACING,
): number[] {
  if (textureWidths.length === 0) return [];

  const stripWidth = viewportWidth * 2;
  const positions: number[] = [];
  let x = 0;
  let textureIndex = 0;

  while (x < stripWidth) {
    positions.push(x);
    const width = textureWidths[textureIndex % textureWidths.length]!;
    x += width + minSpacing;
    textureIndex++;
  }

  return positions;
}

/** Minimum cloud spacing constant (exported for testing). */
export const PARALLAX_MIN_CLOUD_SPACING = MIN_CLOUD_SPACING;

/** Far cloud scroll factor (exported for testing). */
export const PARALLAX_FAR_SCROLL_FACTOR = FAR_CLOUD_SCROLL_FACTOR;

/** Near cloud scroll factor (exported for testing). */
export const PARALLAX_NEAR_SCROLL_FACTOR = NEAR_CLOUD_SCROLL_FACTOR;
