/**
 * Bird_04 (State Machine) enemy system.
 *
 * Implements the fly → idle → aware → chase → fly cycle using @astracore/simple-fsm.
 * Bird_04 lands on the ground, idles, reacts to the Bee's proximity, and chases
 * when close enough.
 *
 * @packageDocumentation
 */

import { SimpleFSM } from '@astracore/simple-fsm';
import {
  StateBirdTag,
  Position,
  Velocity,
  CircleCollider,
  Bird04State,
} from '../components.js';
import { BIRD_04_CONFIG } from '../enemy-config.js';
import type { Bird04Config } from '../enemy-config.js';

// ─── Types ────────────────────────────────────────────────────────────────────

/** Internal entity representation for Bird_04 instances. */
interface Bird04Entity {
  id: number;
  tag: StateBirdTag;
  position: Position;
  velocity: Velocity;
  collider: CircleCollider;
  state: Bird04State;
  fsm: SimpleFSM;
  /** Direction of horizontal movement: 1 = right, -1 = left. */
  direction: number;
  /** Random idle duration for the current idle cycle. */
  idleDuration: number;
  /** Ground Y position where the bird lands. */
  groundY: number;
  /** When true, the next fly cycle flees a full screen away (after chase). */
  fleeing: boolean;
  /** Bee X at the moment chase ended — used to choose flee direction. */
  lastBeeX: number;
}

/** One screen width to flee after a chase. */
const FLEE_DISTANCE = 900;
/** Fly speed in px/s. */
const FLY_SPEED = 100;
/** Faster speed while fleeing. */
const FLEE_SPEED = 220;

// ─── Bird04System ─────────────────────────────────────────────────────────────

/**
 * Manages all Bird_04 state machine enemies.
 *
 * Each Bird_04 operates a finite state machine with states:
 * - fly: move horizontally for a random distance (200-400px), then land
 * - idle: wait for 5-10s on the ground, display bird_04_idle sprite
 * - aware: triggered when Bee enters awarenessRadius (200px), display bird_04_aware
 * - chase: triggered when Bee enters chaseRadius (100px), pursue for up to 5s
 *
 * Collision with the Bee triggers death in any active state.
 */
export class Bird04System {
  private readonly _entities: Bird04Entity[] = [];
  private readonly _config: Bird04Config;
  private _nextId = 0;

  constructor(config: Bird04Config = BIRD_04_CONFIG) {
    this._config = config;
  }

  /** All tracked Bird_04 entities (read-only for external inspection). */
  get entities(): readonly Bird04Entity[] {
    return this._entities;
  }

  /**
   * Spawn a new Bird_04 entity at the given position.
   *
   * @param x - Horizontal spawn position in world pixels
   * @param groundY - The Y coordinate of the ground surface where the bird lands
   * @returns The entity ID assigned to this Bird_04
   */
  spawn(x: number, groundY: number): number {
    const id = this._nextId++;
    const flyDistance = this._randomFlyDistance();

    const state = new Bird04State(
      'fly',
      0,
      flyDistance,
      0,
      this._config.awarenessRadius,
      this._config.chaseRadius,
      this._config.chaseSpeed,
      this._config.chaseDuration,
    );

    const position = new Position(x, groundY);
    const velocity = new Velocity(0, 0);
    const collider = new CircleCollider(14);

    const entity: Bird04Entity = {
      id,
      tag: new StateBirdTag(),
      position,
      velocity,
      collider,
      state,
      fsm: null!,  // assigned below after FSM creation
      direction: Math.random() < 0.5 ? 1 : -1,
      idleDuration: this._randomIdleDuration(),
      groundY,
      fleeing: false,
      lastBeeX: 0,
    };

    // Create the FSM for this entity
    entity.fsm = this._createFSM(entity);

    this._entities.push(entity);
    return id;
  }

  /**
   * Update all Bird_04 entities through their state machines.
   *
   * @param dt - Delta time in seconds
   * @param beeX - Bee's current X position
   * @param beeY - Bee's current Y position
   */
  update(dt: number, beeX: number, beeY: number): void {
    for (const entity of this._entities) {
      this._updateEntity(entity, dt, beeX, beeY);
    }
  }

  /**
   * Remove a Bird_04 entity by ID.
   */
  remove(id: number): void {
    const idx = this._entities.findIndex((e) => e.id === id);
    if (idx !== -1) {
      this._entities.splice(idx, 1);
    }
  }

  /**
   * Remove all Bird_04 entities.
   */
  clear(): void {
    this._entities.length = 0;
  }

  // ─── Private Methods ────────────────────────────────────────────────────

  private _updateEntity(entity: Bird04Entity, dt: number, beeX: number, beeY: number): void {
    const { state, position } = entity;
    const distToBee = this._distance(position.x, position.y, beeX, beeY);

    // Increment state timer
    state.stateTimer += dt;

    switch (state.currentState) {
      case 'fly':
        this._updateFly(entity, dt);
        break;

      case 'idle':
        this._updateIdle(entity, distToBee);
        break;

      case 'aware':
        this._updateAware(entity, distToBee, beeX, beeY);
        break;

      case 'chase':
        this._updateChase(entity, dt, distToBee, beeX, beeY);
        break;
    }
  }

  private _updateFly(entity: Bird04Entity, dt: number): void {
    const { state, position, velocity } = entity;
    const speed = entity.fleeing ? FLEE_SPEED : FLY_SPEED;

    // Move horizontally
    velocity.dx = entity.direction * speed;
    velocity.dy = 0;
    position.x += velocity.dx * dt;

    // Track distance traveled
    state.distanceTraveled += Math.abs(velocity.dx * dt);

    // Transition to idle when fly distance reached
    if (state.distanceTraveled >= state.flyDistance) {
      entity.fleeing = false;
      entity.fsm.send('LAND');
    }
  }

  private _updateIdle(entity: Bird04Entity, distToBee: number): void {
    const { state } = entity;

    // Stop movement
    entity.velocity.dx = 0;
    entity.velocity.dy = 0;

    // Check if Bee enters awareness radius
    if (distToBee <= state.awarenessRadius) {
      entity.fsm.send('BEE_NEAR');
      return;
    }

    // Check if idle duration expired → fly again
    if (state.stateTimer >= entity.idleDuration) {
      entity.fsm.send('IDLE_DONE');
    }
  }

  private _updateAware(entity: Bird04Entity, distToBee: number, _beeX: number, _beeY: number): void {
    const { state } = entity;

    // Stop movement while aware
    entity.velocity.dx = 0;
    entity.velocity.dy = 0;

    // Check if Bee enters chase radius
    if (distToBee <= state.chaseRadius) {
      entity.fsm.send('BEE_CLOSE');
      return;
    }

    // Check if Bee leaves awareness radius → back to idle
    if (distToBee > state.awarenessRadius) {
      entity.fsm.send('BEE_FAR');
    }
  }

  private _updateChase(entity: Bird04Entity, dt: number, distToBee: number, beeX: number, beeY: number): void {
    const { state, position, velocity } = entity;

    // Remember where the Bee is so we can flee the opposite way afterward
    entity.lastBeeX = beeX;

    // Pursue the Bee
    const dx = beeX - position.x;
    const dy = beeY - position.y;
    const dist = Math.sqrt(dx * dx + dy * dy);

    if (dist > 0) {
      velocity.dx = (dx / dist) * state.chaseSpeed;
      velocity.dy = (dy / dist) * state.chaseSpeed;
    } else {
      velocity.dx = 0;
      velocity.dy = 0;
    }

    position.x += velocity.dx * dt;
    position.y += velocity.dy * dt;

    // Chase ends after chaseDuration (default 3s) OR if the Bee escapes
    // the awareness radius — then flee a full screen away.
    if (state.stateTimer >= state.chaseDuration || distToBee > state.awarenessRadius) {
      entity.fleeing = true;
      entity.fsm.send('CHASE_TIMEOUT');
    }
  }

  /** Called externally when the Bee dies during a chase — flee away. */
  public onBeeKilled(): void {
    for (const entity of this._entities) {
      if (entity.state.currentState === 'chase' || entity.state.currentState === 'aware') {
        entity.fleeing = true;
        entity.fsm.send('CHASE_TIMEOUT');
      }
    }
  }

  private _createFSM(entity: Bird04Entity): SimpleFSM {
    return new SimpleFSM({
      initial: 'fly',
      states: {
        fly: {
          onEnter: () => {
            entity.state.currentState = 'fly';
            entity.state.stateTimer = 0;
            entity.state.distanceTraveled = 0;
            if (entity.fleeing) {
              // Flee a full screen away, in the direction away from the Bee
              entity.state.flyDistance = FLEE_DISTANCE;
              entity.direction = entity.position.x >= entity.lastBeeX ? 1 : -1;
              // Take off from the ground a bit
              entity.position.y = entity.groundY - 40;
            } else {
              entity.state.flyDistance = this._randomFlyDistance();
              entity.direction = Math.random() < 0.5 ? 1 : -1;
            }
          },
          transitions: {
            LAND: { target: 'idle' },
          },
        },
        idle: {
          onEnter: () => {
            entity.state.currentState = 'idle';
            entity.state.stateTimer = 0;
            entity.idleDuration = this._randomIdleDuration();
            // Land on the ground
            entity.position.y = entity.groundY;
            entity.velocity.dx = 0;
            entity.velocity.dy = 0;
          },
          transitions: {
            BEE_NEAR: { target: 'aware' },
            IDLE_DONE: { target: 'fly' },
          },
        },
        aware: {
          onEnter: () => {
            entity.state.currentState = 'aware';
            entity.state.stateTimer = 0;
            entity.velocity.dx = 0;
            entity.velocity.dy = 0;
          },
          transitions: {
            BEE_CLOSE: { target: 'chase' },
            BEE_FAR: { target: 'idle' },
          },
        },
        chase: {
          onEnter: () => {
            entity.state.currentState = 'chase';
            entity.state.stateTimer = 0;
          },
          transitions: {
            CHASE_TIMEOUT: { target: 'fly' },
          },
        },
      },
    });
  }

  private _distance(x1: number, y1: number, x2: number, y2: number): number {
    const dx = x2 - x1;
    const dy = y2 - y1;
    return Math.sqrt(dx * dx + dy * dy);
  }

  private _randomFlyDistance(): number {
    const { minFlyDistance, maxFlyDistance } = this._config;
    return minFlyDistance + Math.random() * (maxFlyDistance - minFlyDistance);
  }

  private _randomIdleDuration(): number {
    const { minIdleDuration, maxIdleDuration } = this._config;
    return minIdleDuration + Math.random() * (maxIdleDuration - minIdleDuration);
  }
}
